const LABEL_TEMPLATES_JSON_KEY = '__labelTemplates'
const BUILTIN_DEFAULT_LABEL_TEMPLATE_ID = 'tpl_default'
const BUILTIN_ATACAREJO_LABEL_TEMPLATE_ID = 'tpl_atacarejo_10fd'
const BUILTIN_BLACK_YELLOW_LABEL_TEMPLATE_ID = 'tpl_black_yellow'
const BUILTIN_RED_BURST_LABEL_TEMPLATE_ID = 'tpl_red_burst'
const BUILTIN_OFER_AMARELA_LABEL_TEMPLATE_ID = 'tpl_oferta_amarela'
const BUILTIN_BARLOW_BLACK_LABEL_TEMPLATE_ID = 'tpl_barlow_black'
const BUILTIN_LABEL_TEMPLATE_IDS = new Set([
    BUILTIN_DEFAULT_LABEL_TEMPLATE_ID,
    BUILTIN_ATACAREJO_LABEL_TEMPLATE_ID,
    BUILTIN_BLACK_YELLOW_LABEL_TEMPLATE_ID,
    BUILTIN_RED_BURST_LABEL_TEMPLATE_ID,
    BUILTIN_OFER_AMARELA_LABEL_TEMPLATE_ID,
    BUILTIN_BARLOW_BLACK_LABEL_TEMPLATE_ID
])
const BUILTIN_ATACAREJO_SEED_VERSION = 4
const BUILTIN_RED_BURST_SEED_VERSION = 2
const LABEL_TEMPLATE_PREVIEW_RENDER_VERSION = 8
const LABEL_TEMPLATE_EXTRA_PROPS = ['_customId', 'name', 'fontFamily', 'visible', 'charSpacing', '__preserveManualLayout', '__forceAtacarejoCanonical', '__atacValueVariants', '__atacVariantGroups', '__fontScale', '__yOffsetRatio', '__manualScaleX', '__manualScaleY', '__strokeWidth', '__roundness', '__originalWidth', '__originalHeight', '__originalFontSize', '__originalLeft', '__originalTop', '__originalOriginX', '__originalOriginY', '__originalScaleX', '__originalScaleY', '__originalRadius', '__originalRx', '__originalRy', '__originalStrokeWidth', '__shadowBlur', '__originalFill', '__manualTemplateBaseW', '__manualTemplateBaseH', '__manualGapSingle', '__manualGapRetail', '__manualGapWholesale', '__manualSingleAnchors', '__cornerTL', '__cornerTR', '__cornerBL', '__cornerBR', '__originalCornerTL', '__originalCornerTR', '__originalCornerBL', '__originalCornerBR']
const MANUAL_TEMPLATE_STABLE_PROPS = ['__manualTemplateBaseW', '__manualTemplateBaseH'] as const;
const MANUAL_TEMPLATE_DERIVED_PROPS = ['__manualGapSingle', '__manualGapRetail', '__manualGapWholesale', '__manualSingleAnchors'] as const;
const autoHealedLabelTemplateIds = new Set<string>()

// getLabelTemplateTimestamp extraido para utils/labelTemplateHelpers.ts.

const isBuiltInLabelTemplateId = (value: any): boolean => {
    const id = String(value || '').trim()
    return !!id && BUILTIN_LABEL_TEMPLATE_IDS.has(id)
}

const normalizeLabelTemplateGroupAsManual = (group: any) => {
    if (!group || typeof group !== 'object') return group;
    sanitizeRedBurstTemplateGroupJson(group);
    if (typeof (group as any).__forceAtacarejoCanonical !== 'boolean') {
        (group as any).__forceAtacarejoCanonical = false;
    }
    if (typeof (group as any).__preserveManualLayout !== 'boolean') {
        (group as any).__preserveManualLayout = (group as any).__forceAtacarejoCanonical !== true;
    }
    if (typeof (group as any).__isCustomTemplate !== 'boolean') {
        (group as any).__isCustomTemplate = (group as any).__preserveManualLayout === true;
    }
    return group;
};

const normalizeLabelTemplateRecordAsManual = (tpl: any) => {
    if (!tpl || typeof tpl !== 'object') return tpl;
    const isBuiltIn = !!(tpl as any).isBuiltIn || isBuiltInLabelTemplateId((tpl as any).id);
    return {
        ...tpl,
        group: normalizeLabelTemplateGroupAsManual((tpl as any).group),
        isBuiltIn
    } as any;
};

// shouldUseIncomingTemplateSnapshot extraido para utils/labelTemplateHelpers.ts.

const serializeLabelTemplatesForProject = () => {
    // Persist all current templates in the project so manual layouts never regress
    // to an older DB/library snapshot after reload or page switch.
    return (labelTemplates.value || [])
        .map((t: any) => {
            const normalized = normalizeLabelTemplateRecordAsManual(t);
            return {
                ...normalized,
                __fromDb: undefined,
                __localOverride: undefined,
                isBuiltIn: normalized?.isBuiltIn === true ? true : undefined,
                previewDataUrl: undefined
            };
        })
}

const hydrateLabelTemplatesFromProjectJson = (json: any) => {
    const raw = json?.[LABEL_TEMPLATES_JSON_KEY]
    if (!Array.isArray(raw)) return;

    const existing = (labelTemplates.value || []) as any[];
    const byId = new Map<string, any>(existing.map(t => [String(t?.id), t]));
    for (const t of raw as any[]) {
        if (!t?.id) continue;
        const id = String(t.id);
        const incomingTemplate = normalizeLabelTemplateRecordAsManual(t);
        const prev = byId.get(id);
        if (!prev) {
            byId.set(id, {
                ...incomingTemplate,
                __fromDb: false,
                __localOverride: true
            });
            continue;
        }

        const incomingIsLocalOverride = !!(incomingTemplate as any)?.__localOverride;
        const prevIsLocalOverride = !!(prev as any)?.__localOverride;
        const useIncoming = shouldUseIncomingTemplateSnapshot(prev, incomingTemplate);

        const merged = {
            ...(useIncoming ? prev : incomingTemplate),
            ...(useIncoming ? incomingTemplate : prev),
            previewDataUrl: ((useIncoming ? incomingTemplate : prev) as any)?.previewDataUrl ?? ((useIncoming ? prev : incomingTemplate) as any)?.previewDataUrl
        } as any;

        const hasLocalOverride = prevIsLocalOverride || incomingIsLocalOverride;
        if (hasLocalOverride) {
            merged.__fromDb = false;
            merged.__localOverride = true;
        }

        byId.set(id, normalizeLabelTemplateRecordAsManual(merged));
    }
    labelTemplates.value = Array.from(byId.values()) as any;
}

const syncLabelTemplatesIntoProjectPages = (source: 'user' | 'system' = 'user') => {
    const templatesSnapshot = serializeLabelTemplatesForProject();
    const pages = Array.isArray(project.pages) ? project.pages : [];
    if (!pages.length) return;

    for (let i = 0; i < pages.length; i++) {
        const page = pages[i];
        if (!page?.canvasData || typeof page.canvasData !== 'object') {
            continue;
        }
        const baseCanvasData = page.canvasData;
        const nextCanvasData = {
            ...baseCanvasData,
            [LABEL_TEMPLATES_JSON_KEY]: templatesSnapshot
        };
        updatePageData(i, nextCanvasData, {
            source,
            markUnsaved: source === 'user',
            skipIfSameFingerprint: false
        });
    }
}

const normalizeDbLabelTemplate = (row: any): LabelTemplate | null => {
    if (!row?.id || !row?.group) return null;
    return normalizeLabelTemplateRecordAsManual({
        id: String(row.id),
        name: String(row.name || 'Etiqueta'),
        kind: (row.kind || 'priceGroup-v1') as any,
        group: row.group ?? (row as any)['group'],
        previewDataUrl: row.preview_data_url ?? undefined,
        createdAt: row.created_at ? String(row.created_at) : new Date().toISOString(),
        updatedAt: row.updated_at ? String(row.updated_at) : (row.created_at ? String(row.created_at) : new Date().toISOString())
    }) as LabelTemplate;
}

const loadLabelTemplatesFromDb = async () => {
    if (hasLoadedLabelTemplatesFromDb.value) return;
    hasLoadedLabelTemplatesFromDb.value = true;

    try {
        const userId = currentUser.value?.id || undefined;
        const headers = await getApiAuthHeaders();
        const resp: any = await $fetch('/api/label-templates', { method: 'GET', headers, query: userId ? { userId } : {} });
        const rows = Array.isArray(resp?.templates) ? resp.templates : [];
        const incoming = rows.map(normalizeDbLabelTemplate).filter(Boolean) as LabelTemplate[];
        if (!incoming.length) return;

        const existing = (labelTemplates.value || []) as any[];
        const byId = new Map<string, any>(existing.map(t => [String(t?.id), t]));

        for (const t of incoming) {
            const prev = byId.get(String(t.id));
            if (prev) {
                // Evitar sobrescrever mudanças locais/projeto com versão antiga do banco.
                const prevTs = Date.parse(String(prev?.updatedAt || prev?.createdAt || 0));
                const dbTs = Date.parse(String((t as any)?.updatedAt || (t as any)?.createdAt || 0));
                const prevIsLocalOverride = !!(prev as any)?.__localOverride;
                // Never let DB overwrite a local override saved in the project.
                const useDb = !prevIsLocalOverride && Number.isFinite(dbTs) && (!Number.isFinite(prevTs) || dbTs > prevTs);
                const merged = {
                    ...(useDb ? prev : t),
                    ...(useDb ? t : prev),
                    previewDataUrl: (useDb ? t.previewDataUrl : prev.previewDataUrl) ?? (useDb ? prev.previewDataUrl : t.previewDataUrl)
                } as any;
                if (prevIsLocalOverride) {
                    merged.__fromDb = false;
                    merged.__localOverride = true;
                } else if (useDb) {
                    merged.__fromDb = true;
                }
                byId.set(String(t.id), normalizeLabelTemplateRecordAsManual(merged));
            } else {
                byId.set(String(t.id), normalizeLabelTemplateRecordAsManual({ ...t, __fromDb: true }));
            }
        }
        labelTemplates.value = Array.from(byId.values()) as any;
    } catch (err) {
        console.warn('[labelTemplates] Falha ao carregar modelos do banco', err);
    }
}

const ensureLabelTemplatesReady = async () => {
    await loadLabelTemplatesFromDb();
    await ensureBuiltInDefaultLabelTemplate();
    await ensureBuiltInAtacarejoLabelTemplate();
    await ensureBuiltInBlackYellowLabelTemplate();
    await ensureBuiltInOfertaAmarelaLabelTemplate();
    await ensureBuiltInRedBurstLabelTemplate();
    await ensureBuiltInBarlowBlackLabelTemplate();

    // Generate/refresh previews in-memory.
    // This self-heals stale/broken thumbnails after reload or renderer updates.
    const list = [...(labelTemplates.value || [])];
    let changed = false;
    for (let i = 0; i < list.length; i++) {
        const t = list[i];
        if (!t) continue;
        const currentPreviewVersion = Number((t as any).__previewRenderVersion || 0);
        const needsPreviewRefresh =
            !(t as any).previewDataUrl ||
            currentPreviewVersion < LABEL_TEMPLATE_PREVIEW_RENDER_VERSION;
        if (!needsPreviewRefresh) continue;
        const url = await renderLabelTemplatePreview(t);
        if (url) {
            (list[i] as any) = {
                ...(t as any),
                previewDataUrl: url,
                __previewRenderVersion: LABEL_TEMPLATE_PREVIEW_RENDER_VERSION
            };
            changed = true;
        }
    }
    if (changed) labelTemplates.value = list as any;

    // Hard guard: never keep duplicated IDs in memory.
    const dedup = new Map<string, any>();
    (labelTemplates.value || []).forEach((tpl: any) => {
        const id = String(tpl?.id || '').trim();
        if (!id) return;
        dedup.set(id, tpl);
    });
    if (dedup.size !== (labelTemplates.value || []).length) {
        labelTemplates.value = Array.from(dedup.values()) as any;
    }
}

// Invalida o _zoneTemplateSnapshot em todas as zonas que usam um dado templateId.
// Chamado apos upsert bem-sucedido para que edicoes no Mini Editor propaguem
// para zonas ja aplicadas, sem necessidade de reload manual.
const invalidateZoneTemplateSnapshotsForTemplate = (templateId: string) => {
    if (!templateId || !canvas.value) return;
    try {
        const objs = canvas.value.getObjects() || [];
        for (const obj of objs) {
            if (!obj || !isLikelyProductZone(obj)) continue;
            const snapId = String((obj as any)?._zoneTemplateSnapshotId || '').trim();
            if (snapId && snapId === templateId) {
                (obj as any)._zoneTemplateSnapshot = null;
            }
        }
    } catch { /* ignore */ }
};

const upsertLabelTemplateToDb = async (tpl: LabelTemplate): Promise<boolean> => {
    if (!tpl) return true;
    try {
        normalizeLabelTemplateGroupAsManual((tpl as any)?.group);
        const headers = await getApiAuthHeaders();
        const resp: any = await $fetch('/api/label-templates', {
            method: 'POST',
            headers,
            body: {
                id: tpl.id,
                userId: currentUser.value?.id ?? null,
                name: tpl.name,
                kind: tpl.kind,
                group: tpl.group,
                previewDataUrl: tpl.previewDataUrl ?? null
            }
        });
        if (!resp?.success) {
            console.warn('[labelTemplates] API retornou falha ao salvar modelo no banco', resp);
            return false;
        }
        // Apos salvar com sucesso, invalida snapshot stale em zonas que usam esse template.
        // Sem isso, zonas ja aplicadas continuavam mostrando o template antigo ate reload.
        if (tpl.id) invalidateZoneTemplateSnapshotsForTemplate(String(tpl.id));
        return true;
    } catch (err) {
        console.warn('[labelTemplates] Falha ao salvar modelo no banco', err);
        return false;
    }
}

const deleteLabelTemplateFromDb = async (templateId: string) => {
    if (!templateId) return;
    try {
        const headers = await getApiAuthHeaders();
        await $fetch('/api/label-templates', { method: 'DELETE', headers, query: { id: templateId } });
    } catch (err) {
        console.warn('[labelTemplates] Falha ao excluir modelo do banco', err);
    }
}

