    if (idx == null || idx < 0) return
    const src = project.pages[idx]
    if (!src) return
    const dup = {
        ...JSON.parse(JSON.stringify(src)),
        id: makeId(),
        name: `${src.name || 'Página'} (cópia)`,
        dirty: true
    }
    project.pages.splice(idx + 1, 0, dup)
