const sortProductZonesByVisualOrder = (zones: any[]): any[] => {
    return zones
        .filter((zone: any) => !!zone && isLikelyProductZone(zone))
        .slice()
        .sort((a: any, b: any) => {
            const ao = Number((a as any)?._zoneOrder)
            const bo = Number((b as any)?._zoneOrder)
            if (Number.isFinite(ao) && Number.isFinite(bo) && ao !== bo) return ao - bo
            if (Number.isFinite(ao) && !Number.isFinite(bo)) return -1
            if (!Number.isFinite(ao) && Number.isFinite(bo)) return 1

            const ar = getZoneMetrics(a) ?? a?.getBoundingRect?.(true) ?? { top: 0, left: 0 }
            const br = getZoneMetrics(b) ?? b?.getBoundingRect?.(true) ?? { top: 0, left: 0 }
            const topDelta = Number(ar?.top || 0) - Number(br?.top || 0)
            if (Math.abs(topDelta) > 2) return topDelta
            return Number(ar?.left || 0) - Number(br?.left || 0)
        })
}

const resolveRelatedImportZones = (primaryZone: any): any[] => {
    if (!canvas.value || !primaryZone || !isLikelyProductZone(primaryZone)) return []

    const allZones = (canvas.value.getObjects?.() || []).filter((obj: any) => isLikelyProductZone(obj))
    if (!allZones.length) return []

    const primaryId = String((primaryZone as any)?._customId || '').trim()
    const refreshedPrimary = primaryId
        ? allZones.find((zone: any) => String((zone as any)?._customId || '').trim() === primaryId) || primaryZone
        : primaryZone

    // Comportamento corrigido: a importacao inteligente sempre alvo APENAS a
    // zona explicitamente selecionada pelo usuario. Antes, agrupavamos todas
    // as zonas com o mesmo parentFrameId como "irmas" e distribuiamos os
    // produtos entre elas — o que fazia com que ao duplicar uma zona e
    // importar produtos NA COPIA, os itens caissem na zona original (que vinha
    // primeiro na ordem visual). Tratar cada zona como independente respeita
    // a escolha do usuario e evita esse vazamento entre duplicatas.
    return [refreshedPrimary]
}

const getImportTargetZones = (): any[] => {
    const stored = Array.isArray(targetGridZones.value) ? targetGridZones.value : []
    const zones = stored
        .map((zone: any) => {
            if (!zone || !isLikelyProductZone(zone) || !canvas.value) return null
            const id = String((zone as any)?._customId || '').trim()
            if (!id) return zone
            return (canvas.value.getObjects?.() || []).find((obj: any) =>
                isLikelyProductZone(obj) && String((obj as any)?._customId || '').trim() === id
            ) || zone
        })
        .filter((zone: any) => !!zone && isLikelyProductZone(zone))

    if (zones.length > 0) return sortProductZonesByVisualOrder(zones)

    const single = resolveImportTargetZone()
    return single ? [single] : []
}

const getImportZonesExistingCount = (zones: any[]): number => {
    return zones.reduce((total, zone) => {
        try {
            return total + getZoneChildren(zone).length
        } catch {
            return total
        }
    }, 0)
}

const BASE_PRODUCT_ZONE_NAME = 'Zona de Produtos'
// isDefaultProductZoneName extraido para utils/product-zone-helpers.ts.

const getNextProductZoneName = (excludeZone?: any): string => {
    const used = new Set<number>()
    const zones = (canvas.value?.getObjects?.() || []).filter((obj: any) => isLikelyProductZone(obj) && obj !== excludeZone)
    zones.forEach((zone: any) => {
        const name = String((zone as any)?.zoneName || '').trim()
        if (!name) return
        if (name.toLowerCase() === BASE_PRODUCT_ZONE_NAME.toLowerCase()) {
            used.add(1)
            return
        }
        const match = /^Zona de Produtos\s+(\d+)$/i.exec(name)
        if (match) {
            const n = Number(match[1])
            if (Number.isInteger(n) && n > 0) used.add(n)
        }
    })
    let index = 1
    while (used.has(index)) index += 1
    return `${BASE_PRODUCT_ZONE_NAME} ${index}`
}

const ensureProductZoneNamesDistinct = (zonesInput?: any[]) => {
    const zones = (Array.isArray(zonesInput) ? zonesInput : (canvas.value?.getObjects?.() || []))
        .filter((obj: any) => isLikelyProductZone(obj))
    if (!zones.length) return

    const reservedNames = new Set<string>()
    const usedNumbers = new Set<number>()
    const ordered = sortProductZonesByVisualOrder(zones)
    ordered.forEach((zone: any) => {
        const current = String((zone as any)?.zoneName || '').trim()
        if (!current || isDefaultProductZoneName(current)) return
        const key = current.toLowerCase()
        if (reservedNames.has(key)) return
        reservedNames.add(key)
        const match = /^Zona de Produtos\s+(\d+)$/i.exec(current)
        if (match) {
            const n = Number(match[1])
            if (Number.isInteger(n) && n > 0) usedNumbers.add(n)
        }
    })

    let nextIndex = 1
    const nextDefaultName = () => {
        while (usedNumbers.has(nextIndex) || reservedNames.has(`${BASE_PRODUCT_ZONE_NAME} ${nextIndex}`.toLowerCase())) {
            nextIndex += 1
        }
        const name = `${BASE_PRODUCT_ZONE_NAME} ${nextIndex}`
        usedNumbers.add(nextIndex)
        reservedNames.add(name.toLowerCase())
        nextIndex += 1
        return name
    }

    const seenCustomNames = new Set<string>()
    ordered.forEach((zone: any) => {
        const current = String((zone as any)?.zoneName || '').trim()
        const key = current.toLowerCase()
        if (!current || isDefaultProductZoneName(current) || seenCustomNames.has(key)) {
            ;(zone as any).zoneName = nextDefaultName()
            return
        }
        seenCustomNames.add(key)
    })
}

const openProductReviewForZone = (zone: any, opts: { mode?: 'replace' | 'append' } = {}): boolean => {
    productReviewInitialImportMode.value = opts.mode === 'append' ? 'append' : 'replace'
    return openProductReviewForZoneHelper({
        zone,
        isLikelyProductZone,
        getZoneChildren,
        setTargetZone: (nextZone) => {
            targetGridZone.value = nextZone
            targetGridZones.value = resolveRelatedImportZones(nextZone)
        },
        setExistingCount: (count) => {
            const zones = targetGridZones.value.length ? targetGridZones.value : [targetGridZone.value].filter(Boolean)
            productImportExistingCount.value = zones.length > 1 ? getImportZonesExistingCount(zones) : count
        },
        setReviewProducts: (products) => {
            reviewProducts.value = products
        },
        setShowReviewModal: (value) => {
            showProductReviewModal.value = value
        }
    })
}

const focusProductZoneFromDblClickTarget = (target: any): boolean => {
    if (!target) return false;
    if (isPriceGroupOrPriceChild(target)) return false;
    if (isProductCardContainer(target) || isLikelyProductCard(target)) return false;
    if (isProductCardContainer((target as any)?.group) || isLikelyProductCard((target as any)?.group)) return false;

    const zone = resolveZoneForProductImport(target);
    if (!zone) return false;
    try {
        canvas.value?.setActiveObject?.(zone);
        refreshSelectedRef();
    } catch {
        // ignore selection focus failures
    }
    if (isMobile.value) {
        mobilePanel.value = 'properties';
    }
    focusProductZoneSettings();
    return true;
}

