const normalizeProductCardIdentity = (
    card: any,
    opts: { zoneInstanceId?: string | null; forceNewInstance?: boolean; reason?: string } = {}
) => {
    if (!card || typeof card !== 'object') return null;

    const previousData = (card as any)._productData && typeof (card as any)._productData === 'object'
        ? clonePlainMetadata((card as any)._productData)
        : {};
    const previousInstanceId = String(previousData.productInstanceId || (card as any).productInstanceId || '').trim();
    const productId = String(
        previousData.productId ||
        previousData.product_id ||
        previousData.id ||
        (card as any).productId ||
        (card as any).id ||
        ''
    ).trim();
    const nextInstanceId = opts.forceNewInstance || !previousInstanceId
        ? makeProductInstanceId()
        : previousInstanceId;
    const zoneInstanceId = String(opts.zoneInstanceId || (card as any).parentZoneId || previousData.zoneInstanceId || '').trim();

    const nextProductData = {
        ...previousData,
        ...(productId ? { productId } : {}),
        productInstanceId: nextInstanceId,
        ...(zoneInstanceId ? { zoneInstanceId } : {})
    };

    (card as any)._productData = nextProductData;
    (card as any).productInstanceId = nextInstanceId;
    if (productId) (card as any).productId = productId;
    else delete (card as any).productId;
    if (zoneInstanceId) (card as any).zoneInstanceId = zoneInstanceId;
    else delete (card as any).zoneInstanceId;
    if (opts.forceNewInstance) (card as any).__productIdentityFresh = true;

    if (import.meta.dev && opts.reason) {
        console.debug('[product-zone:identity]', {
            reason: opts.reason,
            cardObjectId: String((card as any)._customId || '').trim(),
            productId,
            previousProductInstanceId: previousInstanceId || null,
            productInstanceId: nextInstanceId,
            zoneInstanceId: zoneInstanceId || null
        });
    }

    return {
        productId,
        previousProductInstanceId: previousInstanceId || null,
        productInstanceId: nextInstanceId,
        zoneInstanceId: zoneInstanceId || null
    };
};

// isControlLikeObject extraido para utils/controlObjectClassifiers.ts.

const ensureObjectPersistentId = (obj: any) => {
    if (!obj || typeof obj !== 'object') return;
    if (obj._customId) return;
    if (isControlLikeObject(obj)) return;
    // User guides are persisted by `id` (guide-user-*) and should never become layers (_customId).
    try { if (isUserGuideObject(obj)) return; } catch {}
    obj._customId = makeCanvasObjectId();
};

const isTransientCanvasObject = (obj: any) => {
    if (!obj || typeof obj !== 'object') return false;
    const name = String(obj.name || '');
    const id = String(obj.id || '');
    const hasCustomId = typeof obj._customId === 'string' && obj._customId.trim().length > 0;

    if (hasCustomId) return false;
    if (isControlLikeObject(obj)) return true;
    if (obj.type === 'circle' && obj.radius && obj.radius <= 10 && !hasCustomId && !!obj.excludeFromExport) return true;
    if (obj.type === 'line' && !hasCustomId && !!obj.excludeFromExport) return true;
    if (obj.type === 'path' && !hasCustomId && !obj.isVectorPath && !!obj.excludeFromExport) return true;

    if (obj.excludeFromExport === true) {
        const isPersistentContent =
            !!obj.isFrame ||
            !!obj.isSmartObject ||
            !!obj.isProductCard ||
            !!obj.isGridZone ||
            !!obj.isProductZone ||
            !!obj.parentZoneId ||
            name === 'gridZone' ||
            name === 'productZoneContainer' ||
            name === 'priceGroup' ||
            name.startsWith('product-card') ||
            id === 'artboard-bg';
        if (isPersistentContent) return false;
        // Avoid removing regular user content by mistake. For non-persistent objects,
        // only treat as transient when they look like control/guide objects.
        return isControlLikeObject(obj);
    }

    return false;
};

const ensurePersistentContentFlags = (obj: any) => {
    if (!obj || typeof obj !== 'object') return;
    ensureObjectPersistentId(obj);
    const name = String(obj.name || '');
    const isPersistentContent =
        !!obj.isFrame ||
        !!obj.isSmartObject ||
        !!obj.isProductCard ||
        !!obj.isGridZone ||
        !!obj.isProductZone ||
        !!obj.parentZoneId ||
        name === 'gridZone' ||
        name === 'productZoneContainer' ||
        name.startsWith('product-card');
    if (isPersistentContent && obj.excludeFromExport) {
        obj.excludeFromExport = false;
    }
};

const showDeletePageModal = ref(false)

