// Helper function to extract key/path from Wasabi URL (presigned or permanent)
const extractWasabiKey = (url: string): string | null => {
    try {
        // CRITICAL: Decode URL first to handle encoded characters
        const decodedUrl = decodeURIComponent(url);
        const urlObj = new URL(decodedUrl);

        // Formatos Wasabi:
        // - Path-style: https://s3.wasabisys.com/bucket/key...
        //
        // OBS: a "key" é SEMPRE o caminho completo do objeto no bucket (ex.: projects/{userId}/...)

        // Decode pathname as well to handle any encoded characters
        const decodedPathname = decodeURIComponent(urlObj.pathname);
        const pathParts = decodedPathname.split('/').filter(p => p);
        if (import.meta.dev) {
            console.log(`🔍 extractWasabiKey - URL: ${url.substring(0, 100)}...`);
            console.log(`   decodedUrl: ${decodedUrl.substring(0, 100)}...`);
            console.log(`   pathname: ${decodedPathname}`);
            console.log(`   pathParts: [${pathParts.join(', ')}]`);
        }

        if (pathParts.length === 0) {
            if (import.meta.dev) console.warn(`⚠️ Não foi possível extrair chave da URL (path vazio): ${url.substring(0, 100)}`);
            return null;
        }

        const cfg = useRuntimeConfig()?.public?.wasabi || {};
        const configuredBucket = (cfg.bucket || 'jobvarejo').toString();

        if (import.meta.dev) console.log(`   configuredBucket: ${configuredBucket}`);

        const hostname = (urlObj.hostname || '').toLowerCase();
        const first = pathParts[0] ?? '';
        // Check if first part is bucket
        const firstLooksLikeBucket = first === configuredBucket || first.includes(':');
        const hostLooksLikeVirtualHost = hostname.includes(`${configuredBucket.toLowerCase()}.`);

        if (import.meta.dev) {
            console.log(`   first: ${first}`);
            console.log(`   firstLooksLikeBucket: ${firstLooksLikeBucket}`);
            console.log(`   hostLooksLikeVirtualHost: ${hostLooksLikeVirtualHost}`);
        }

        // Path-style: primeira parte do path é bucket → remover
        // Virtual-host: host já contém bucket → NÃO remover nada do path
        const keyParts = (firstLooksLikeBucket && !hostLooksLikeVirtualHost) ? pathParts.slice(1) : pathParts;
        const key = keyParts.join('/');

        if (import.meta.dev) {
            console.log(`   keyParts: [${keyParts.join(', ')}]`);
            console.log(`   key extraída: ${key}`);
        }

        if (!key || key.length === 0) {
            if (import.meta.dev) console.warn(`⚠️ Chave extraída está vazia da URL: ${url.substring(0, 100)}`);
            return null;
        }
        return key;
    } catch (err) {
        if (import.meta.dev) console.error(`❌ Erro ao extrair chave da URL: ${url.substring(0, 100)}`, err);
        return null;
    }
};

// Helper function to convert presigned URL to permanent URL (Wasabi)
const convertPresignedToPermanentUrl = (url: string): string => {
    // If it's not a Wasabi URL, return as-is
    if (!url.includes('wasabisys.com')) {
        return url;
    }

    // If it's already a permanent URL (no query params), return as-is
    try {
        const urlObj = new URL(url);
        if (!urlObj.search) {
            if (import.meta.dev) console.log(`🔗 URL já é permanente (sem query params): ${url.substring(0, 80)}...`);
            return url;
        }

        // Extract key from presigned URL
        const key = extractWasabiKey(url);
        if (!key) {
            console.warn(`⚠️ Não foi possível extrair key da URL presignada: ${url.substring(0, 100)}`);
            return url; // Can't extract key, return original
        }

        // Build permanent URL for Wasabi
        const config = useRuntimeConfig().public?.wasabi || {};
        const endpoint = config.endpoint || 's3.wasabisys.com';
        const bucket = config.bucket || 'jobvarejo';
        const permanentUrl = `https://${endpoint}/${bucket}/${key}`;
        console.log(`🔄 Convertendo presigned → permanent (Wasabi):`);
        console.log(`   De: ${url.substring(0, 100)}...`);
        console.log(`   Para: ${permanentUrl.substring(0, 100)}...`);
        console.log(`   Key extraída: ${key}`);
        return permanentUrl;
    } catch (err) {
        console.error(`❌ Erro ao converter URL presignada para permanente:`, err);
        return url; // Error parsing, return original
    }
};

// Helper function to generate new presigned URL from permanent URL or key
const generatePresignedUrl = async (urlOrKey: string): Promise<string | null> => {
    try {
        // If it's already a presigned URL, extract key and generate new one
        let key: string | null = null;
        
        console.log(`🔑 generatePresignedUrl chamada com: ${urlOrKey.substring(0, 100)}...`);

        if (urlOrKey.includes('wasabisys.com')) {
            key = extractWasabiKey(urlOrKey);
            console.log(`   Key extraída da URL Wasabi: ${key || '(null)'}`);
        } else {
            // Assume it's already a key
            key = urlOrKey;
            console.log(`   Usando como key diretamente: ${key}`);
        }
        
        if (!key) {
            console.error(`❌ Não foi possível obter key para gerar URL presignada`);
            return null;
        }
        
        // Request new presigned URL from backend
        console.log(`📤 Requisitando presigned URL do backend para key: ${key}`);
        const headers = await getApiAuthHeaders();
        const data = await $fetch<{ url?: string }>('/api/storage/presigned', {
            method: 'POST',
            headers,
            body: { key, contentType: 'image/*', operation: 'get' }
        });
        
        if (data?.url) {
            console.log(`✅ Presigned URL gerada com sucesso: ${data.url.substring(0, 100)}...`);
        } else {
            console.error(`❌ Backend retornou resposta sem URL:`, data);
        }
        
        return data?.url || null;
    } catch (error) {
        console.error('❌ Erro ao gerar URL presignada:', error);
        return null;
    }
};

/**
 * Decodifica URLs da Contabo que têm %3A (colon codificado) no bucket name.
 * A Contabo retorna erro 500 quando o bucket name tem %3A em vez de :.
 * Formato: https://endpoint/tenant%3Abucket/key -> https://endpoint/tenant:bucket/key
 */
// decodeContaboUrls extraido para utils/canvasJsonClassifiers.ts.

/**
 * Extrai bucket e key de uma URL da Contabo.
 */
const extractContaboBucketAndKey = (url: string): { bucket: string | null; key: string | null } => {
    try {
        const decodedUrl = decodeURIComponent(url);
        const urlObj = new URL(decodedUrl);
        const decodedPathname = decodeURIComponent(urlObj.pathname);
        const pathParts = decodedPathname.split('/').filter(p => p);

        if (pathParts.length === 0) {
            return { bucket: null, key: null };
        }

        const cfg = (useRuntimeConfig()?.public?.contabo as any) || {};
        const configuredBucket = (cfg.bucket || '475a29e42e55430abff00915da2fa4bc:jobupload').toString();
        const candidates = new Set<string>();
        if (configuredBucket) candidates.add(configuredBucket);

        const first = pathParts[0] ?? '';
        // Check if first part is bucket (may have : or match configured buckets)
        const firstLooksLikeBucket = first.includes(':') || candidates.has(first);
        const hostLooksLikeVirtualHost = [...candidates].some(b => b && urlObj.hostname.startsWith(`${b.toLowerCase()}.`));

        // Path-style: primeira parte do path é bucket/tenant:bucket → extrair bucket
        // Virtual-host: host já contém bucket → usar bucket configurado
        let bucket: string | null = null;
        let keyParts: string[];

        if (firstLooksLikeBucket && !hostLooksLikeVirtualHost) {
            bucket = first;
            keyParts = pathParts.slice(1);
        } else if (hostLooksLikeVirtualHost) {
            // Extrair bucket do hostname (virtual-host style)
            const hostParts = urlObj.hostname.split('.');
            bucket = hostParts[0] || null;
            keyParts = pathParts;
        } else {
            // Usar bucket padrão
            bucket = null; // Deixa o proxy usar o padrão
            keyParts = pathParts;
        }

        const key = keyParts.join('/');

        if (!key || key.length === 0) {
            return { bucket: null, key: null };
        }

        return { bucket, key };
    } catch (err) {
        console.error(`❌ Erro ao extrair bucket e key da URL: ${url.substring(0, 100)}`, err);
        return { bucket: null, key: null };
    }
};

/**
 * Extrai bucket e key de uma URL do Wasabi S3.
 * Formato esperado: https://s3.wasabisys.com/bucket/key...
 */
const extractWasabiBucketAndKey = (url: string): { bucket: string | null; key: string | null } => {
    try {
        const urlObj = new URL(url);
        const pathParts = urlObj.pathname.split('/').filter(p => p);

        if (pathParts.length === 0) {
            return { bucket: null, key: null };
        }

        // Wasabi path-style: /bucket/key...
        const bucket = pathParts[0] || null;
        const key = pathParts.slice(1).join('/');

        if (!key || key.length === 0) {
            return { bucket: null, key: null };
        }

        return { bucket, key };
    } catch (err) {
        console.error(`❌ Erro ao extrair bucket e key da URL Wasabi: ${url.substring(0, 100)}`, err);
        return { bucket: null, key: null };
    }
};

/**
 * Converte URLs da Contabo/Wasabi para usar o proxy local.
 * Isso evita problemas com URLs presignadas, encoding de caracteres especiais e CORS.
 * O proxy busca a imagem diretamente do S3 no backend, sem problemas de assinatura.
 */
// cloneCanvasDataForLoad extraido para utils/canvasJsonClassifiers.ts.

type PreparedCanvasLoadCacheEntry = {
    token: string;
    prepared: any;
    legacyProductCardImageRepair: {
        cardsScanned: number;
        imagesScanned: number;
        imagesRepaired: number;
        needsPostLoadRepair: boolean;
    };
};

type PrepareCanvasDataForLoadOptions = {
    cacheKey?: string | null;
    silent?: boolean;
};

const preparedCanvasDataLoadCache = new WeakMap<object, PreparedCanvasLoadCacheEntry>();
const preparedCanvasDataLoadCacheByKey = new Map<string, PreparedCanvasLoadCacheEntry>();
const PREPARED_CANVAS_LOAD_CACHE_LIMIT = 24;

// normalizePreparedCanvasLoadCacheKey extraido para utils/canvasJsonClassifiers.ts.

const rememberPreparedCanvasLoadCacheByKey = (cacheKey: string, entry: PreparedCanvasLoadCacheEntry) => {
    const normalizedKey = normalizePreparedCanvasLoadCacheKey(cacheKey);
    if (!normalizedKey) return;
    preparedCanvasDataLoadCacheByKey.delete(normalizedKey);
    preparedCanvasDataLoadCacheByKey.set(normalizedKey, entry);
    while (preparedCanvasDataLoadCacheByKey.size > PREPARED_CANVAS_LOAD_CACHE_LIMIT) {
        const oldestKey = preparedCanvasDataLoadCacheByKey.keys().next().value;
        if (!oldestKey) break;
        preparedCanvasDataLoadCacheByKey.delete(oldestKey);
    }
};

const readPreparedCanvasLoadCacheByKey = (
    cacheKey: string,
    token: string
): PreparedCanvasLoadCacheEntry | null => {
    const normalizedKey = normalizePreparedCanvasLoadCacheKey(cacheKey);
    if (!normalizedKey) return null;
    const cached = preparedCanvasDataLoadCacheByKey.get(normalizedKey);
    if (!cached) return null;
    if (cached.token !== token) {
        preparedCanvasDataLoadCacheByKey.delete(normalizedKey);
        return null;
    }
    preparedCanvasDataLoadCacheByKey.delete(normalizedKey);
    preparedCanvasDataLoadCacheByKey.set(normalizedKey, cached);
    return cached;
};

const prepareCanvasDataForLoadEntry = (
    raw: any,
    opts: PrepareCanvasDataForLoadOptions = {}
): PreparedCanvasLoadCacheEntry | null => {
    try {
        if (!raw || typeof raw !== 'object') return null;

        const cacheKey = raw as object;
        const cacheToken = getCanvasLoadCacheToken(raw);
        const normalizedCacheKey = normalizePreparedCanvasLoadCacheKey(opts.cacheKey);
        const cached = preparedCanvasDataLoadCache.get(cacheKey);
        if (cached && cached.token === cacheToken) {
            if (normalizedCacheKey) rememberPreparedCanvasLoadCacheByKey(normalizedCacheKey, cached);
            return cached;
        }
        if (normalizedCacheKey) {
            const cachedByKey = readPreparedCanvasLoadCacheByKey(normalizedCacheKey, cacheToken);
            if (cachedByKey) {
                preparedCanvasDataLoadCache.set(cacheKey, cachedByKey);
                return cachedByKey;
            }
        }

        const prepared = convertContaboToProxyUrls(raw, {
            clone: true,
            silent: !!opts.silent
        });
        const legacyProductCardImageRepair = normalizeLegacyProductCardImageTransformsInCanvasData(prepared);
        const entry: PreparedCanvasLoadCacheEntry = {
            token: cacheToken,
            prepared,
            legacyProductCardImageRepair
        };
        preparedCanvasDataLoadCache.set(cacheKey, entry);
        if (normalizedCacheKey) {
            rememberPreparedCanvasLoadCacheByKey(normalizedCacheKey, entry);
        }
        return entry;
    } catch {
        return null;
    }
};

// getCanvasLoadCacheToken extraido para utils/canvasJsonClassifiers.ts.

// walkCanvasObjects / getJsonGroupChildren / isStandalonePriceGroupJson /
// isLikelyProductCardJson / getCardBaseSizeForContainmentJson foram
// extraidos para utils/canvasJsonClassifiers.ts (Fase 2 da modularizacao).

// getJsonObjectSize / getJsonObjectCenterInParentPlane /
// setJsonObjectCenterInParentPlane / collectJsonDescendantsWithParent
// foram extraidos para utils/canvasJsonClassifiers.ts.

const DEFERRED_PRODUCT_IMAGE_LOAD_THRESHOLD = 24;
const DEFERRED_PRODUCT_IMAGE_LOAD_MAX = 72;

// isDeferredProductImageCandidateSrc + isProductCardImageSelectionCandidateJson
// extraidos para utils/canvasJsonClassifiers.ts.

// getPreferredProductImageFromCardJson extraido para utils/canvasJsonClassifiers.ts.

const buildProgressiveProductCardImageLoadPayload = (
    canvasData: any,
    opts: { clone?: boolean; totalImageCount?: number | null } = {}
): { data: any; deferredCount: number; totalImageCount: number } => {
    const rootObjects = Array.isArray(canvasData?.objects) ? canvasData.objects : [];
    if (!rootObjects.length) {
        return { data: canvasData, deferredCount: 0, totalImageCount: 0 };
    }

    const providedTotalImageCount = Number(opts.totalImageCount);
    const totalImageCount = Number.isFinite(providedTotalImageCount) && providedTotalImageCount > 0
        ? providedTotalImageCount
        : countCanvasJsonObjectsAndImages(canvasData).images;

    if (!Number.isFinite(totalImageCount) || totalImageCount < DEFERRED_PRODUCT_IMAGE_LOAD_THRESHOLD) {
        return { data: canvasData, deferredCount: 0, totalImageCount: Number.isFinite(totalImageCount) ? totalImageCount : 0 };
    }

    const cloned = opts.clone === false ? canvasData : cloneCanvasDataForLoad(canvasData);
    const clonedRootObjects = Array.isArray(cloned?.objects) ? cloned.objects : [];
    if (!clonedRootObjects.length) {
        return { data: cloned, deferredCount: 0, totalImageCount };
    }

    let deferredCount = 0;
    clonedRootObjects.forEach((card: any) => {
        if (deferredCount >= DEFERRED_PRODUCT_IMAGE_LOAD_MAX) return;
        if (!isLikelyProductCardJson(card)) return;

        const imageNode = getPreferredProductImageFromCardJson(card);
        if (!imageNode) return;

        const currentSrc = String((imageNode as any)?.src || '').trim();
        const originalSrc = String((imageNode as any)?.__originalSrc || '').trim();
        const sourceToKeep = originalSrc || currentSrc;
        if (!isDeferredProductImageCandidateSrc(sourceToKeep)) return;
        if (currentSrc === PLACEHOLDER_IMAGE_DATA_URL) return;

        if (!originalSrc) {
            (imageNode as any).__originalSrc = currentSrc;
        }
        imageNode.src = PLACEHOLDER_IMAGE_DATA_URL;
        imageNode.crossOrigin = 'anonymous';
        deferredCount += 1;
    });

    return { data: cloned, deferredCount, totalImageCount };
};

const normalizeLegacyProductCardImageTransformsInCanvasData = (
    canvasData: any
): { cardsScanned: number; imagesScanned: number; imagesRepaired: number; needsPostLoadRepair: boolean } => {
    const rootObjects = Array.isArray(canvasData?.objects) ? canvasData.objects : [];
    if (!rootObjects.length) {
        return { cardsScanned: 0, imagesScanned: 0, imagesRepaired: 0, needsPostLoadRepair: false };
    }

    let cardsScanned = 0;
    let imagesScanned = 0;
    let imagesRepaired = 0;
    let needsPostLoadRepair = false;

    rootObjects.forEach((card: any) => {
        if (!isLikelyProductCardJson(card)) return;

        cardsScanned += 1;
        const cardBase = getCardBaseSizeForContainmentJson(card);
        const descendants = collectJsonDescendantsWithParent(card);

        descendants.forEach(({ node, parent }) => {
            if (String(node?.type || '').toLowerCase() !== 'image') return;

            imagesScanned += 1;
            let changed = false;

            let nextScaleX = Number(node.scaleX ?? 1);
            let nextScaleY = Number(node.scaleY ?? 1);
            if (!Number.isFinite(nextScaleX) || nextScaleX === 0) {
                nextScaleX = 1;
                changed = true;
            }
            if (!Number.isFinite(nextScaleY) || nextScaleY === 0) {
                nextScaleY = 1;
                changed = true;
            }
            if (nextScaleX < 0 || nextScaleY < 0) {
                nextScaleX = Math.abs(nextScaleX) || 1;
                nextScaleY = Math.abs(nextScaleY) || 1;
                changed = true;
            }

            if (node.flipX || node.flipY) changed = true;
            if (node.lockScalingFlip !== true) changed = true;
            if (node.lockSkewingX !== true || node.lockSkewingY !== true) changed = true;

            const rawWidth = Number(node.width ?? 0);
            const rawHeight = Number(node.height ?? 0);
            const hasValidIntrinsicSize = Number.isFinite(rawWidth) && rawWidth > 0 && Number.isFinite(rawHeight) && rawHeight > 0;
            if (!hasValidIntrinsicSize) {
                needsPostLoadRepair = true;
            }

            if (parent === card && cardBase && hasValidIntrinsicSize) {
                const imageSize = getJsonObjectSize(node, { scaleX: nextScaleX, scaleY: nextScaleY });
                const center = getJsonObjectCenterInParentPlane(node, { scaleX: nextScaleX, scaleY: nextScaleY });
                if (imageSize && center) {
                    const cardLeft = -(cardBase.w / 2);
                    const cardTop = -(cardBase.h / 2);
                    const cardRight = cardBase.w / 2;
                    const cardBottom = cardBase.h / 2;
                    const minCx = Math.min(cardLeft + (imageSize.width / 2), cardRight - (imageSize.width / 2));
                    const maxCx = Math.max(cardLeft + (imageSize.width / 2), cardRight - (imageSize.width / 2));
                    const minCy = Math.min(cardTop + (imageSize.height / 2), cardBottom - (imageSize.height / 2));
                    const maxCy = Math.max(cardTop + (imageSize.height / 2), cardBottom - (imageSize.height / 2));
                    const constrainedCx = Math.min(maxCx, Math.max(minCx, center.x));
                    const constrainedCy = Math.min(maxCy, Math.max(minCy, center.y));
                    if (Math.abs(constrainedCx - center.x) > 0.001 || Math.abs(constrainedCy - center.y) > 0.001) {
                        if (setJsonObjectCenterInParentPlane(node, constrainedCx, constrainedCy, { scaleX: nextScaleX, scaleY: nextScaleY })) {
                            changed = true;
                        } else {
                            needsPostLoadRepair = true;
                        }
                    }
                } else {
                    needsPostLoadRepair = true;
                }
            }

            if (changed) {
                node.scaleX = nextScaleX;
                node.scaleY = nextScaleY;
                node.flipX = false;
                node.flipY = false;
                node.lockScalingFlip = true;
                node.lockSkewingX = true;
                node.lockSkewingY = true;
                imagesRepaired += 1;
            }
        });
    });

    return { cardsScanned, imagesScanned, imagesRepaired, needsPostLoadRepair };
};

const mapLimit = async <T>(
    items: T[],
    concurrency: number,
    worker: (item: T, index: number) => Promise<void>
): Promise<void> => {
    const limit = Math.max(1, Math.floor(concurrency || 1));
    let cursor = 0;
    const runWorker = async () => {
        while (true) {
            const index = cursor++;
            if (index >= items.length) return;
            await worker(items[index] as T, index);
        }
    };
    const tasks = Array.from({ length: Math.min(limit, items.length) }, () => runWorker());
    await Promise.all(tasks);
};

const collectContaboImageNodes = (canvasData: any): any[] => {
    const images: any[] = [];
    walkCanvasObjects(canvasData, (node) => {
        const src = String(node?.src || '');
        if (String(node?.type || '').toLowerCase() !== 'image') return;
        if (!src) return;
        if (!src.includes('contabostorage.com') && !src.includes('usc1.contabostorage.com')) return;
        images.push(node);
    });
    return images;
};

const refreshContaboUrlsInCanvasData = async (
    canvasData: any,
    opts: { concurrency?: number } = {}
): Promise<{ total: number; refreshed: number; failed: number }> => {
    const images = collectContaboImageNodes(canvasData);
    if (!images.length) return { total: 0, refreshed: 0, failed: 0 };

    const concurrency = Math.max(1, Number(opts.concurrency || 6));
    let refreshed = 0;
    let failed = 0;

    console.log(`🔄 Gerando novas URLs presignadas para ${images.length} imagem(ns)...`);
    await mapLimit(images, concurrency, async (imgObj) => {
        try {
            const result = extractContaboBucketAndKey(String(imgObj?.src || ''));
            const key = result?.key;
            if (!key) {
                console.warn(`⚠️ Não foi possível extrair chave da URL: ${String(imgObj?.src || '').substring(0, 80)}...`);
                if (!imgObj.__originalSrc) {
                    imgObj.__originalSrc = String(imgObj?.src || '');
                }
                imgObj.src = PLACEHOLDER_IMAGE_DATA_URL;
                failed++;
                return;
            }

            const newUrl = await generatePresignedUrl(key);
            if (newUrl) {
                imgObj.src = newUrl;
                refreshed++;
            } else {
                console.error(`❌ Falha ao gerar URL presignada para: ${key.substring(0, 50)}...`);
                if (!imgObj.__originalSrc) {
                    imgObj.__originalSrc = String(imgObj?.src || '');
                }
                imgObj.src = PLACEHOLDER_IMAGE_DATA_URL;
                failed++;
            }
        } catch (err) {
            console.error('❌ Erro ao gerar URL presignada:', err);
            console.error(`   URL original: ${String(imgObj?.src || '').substring(0, 100)}`);
            if (!imgObj.__originalSrc) {
                imgObj.__originalSrc = String(imgObj?.src || '');
            }
            imgObj.src = PLACEHOLDER_IMAGE_DATA_URL;
            failed++;
        }
    });

    return { total: images.length, refreshed, failed };
};

const convertContaboToProxyUrls = (
