async function resetCardPriceGroupToDefault(card: any) {
    if (!fabric || !card || card.type !== 'group' || typeof card.getObjects !== 'function') return;
    const objs = card.getObjects();
    const oldPg = objs.find((o: any) => o && o.type === 'group' && o.name === 'priceGroup');
    if (!oldPg) return;

    const oldParts = typeof oldPg.getObjects === 'function' ? oldPg.getObjects() : [];
    const oldPrice = oldParts.find((o: any) => o.name === 'smart_price' || o.name === 'price_value_text');
    const oldInt = oldParts.find((o: any) => o.name === 'price_integer_text');
    const oldDec = oldParts.find((o: any) => o.name === 'price_decimal_text');
    const oldUnit = oldParts.find((o: any) => o.name === 'price_unit_text');
    const oldPriceText =
        (oldInt && oldDec)
            ? `${oldInt.text || '0'}${oldDec.text || ',00'}`
            : (typeof oldPrice?.text === 'string' ? oldPrice.text : '0,00');
    const oldUnitText = typeof oldUnit?.text === 'string' ? oldUnit.text : undefined;
    const inferredUnit = oldUnitText && oldUnitText.trim().length ? normalizeUnitForLabel(oldUnitText) : inferUnitFromCard(card);

    const cardW = card._cardWidth ?? card.width ?? card.getScaledWidth?.() ?? 0;
    const cardH = card._cardHeight ?? card.height ?? card.getScaledHeight?.() ?? 0;
    if (!cardW || !cardH) return;

    const newPg = buildDefaultPriceGroupForCard(oldPriceText, cardW, cardH, oldPg.top ?? 0, inferredUnit);
    newPg.set({
        left: oldPg.left ?? 0,
        originX: oldPg.originX ?? 'center',
        originY: oldPg.originY ?? 'center',
        angle: oldPg.angle ?? 0
    });

    card.remove(oldPg);
    safeAddWithUpdate(card, newPg);
    // Freeze card dimensions (do NOT call safeAddWithUpdate which expands bounds)
    if (cardW && cardH) card.set({ width: cardW, height: cardH });
    card.dirty = true;
    card.setCoords();
}

// cloneTemplateGroupJson extraido para utils/canvasJsonClassifiers.ts.


const clonePriceGroupForRollback = async (priceGroup: any) => {
    if (!priceGroup || typeof priceGroup.toObject !== 'function') return null;
    const json = priceGroup.toObject([...CANVAS_CUSTOM_PROPS]);
    const clone = await enlivenObjectsAsync([json]);
    const restored = Array.isArray(clone) ? clone[0] : null;
    if (!restored) return null;
    restoreMissingManualTemplateFlags(restored);
    if (!(restored as any)._customId) (restored as any)._customId = makeCanvasObjectId();
    return restored;
};

const restoreCardPriceGroup = (card: any, currentPriceGroup: any, rollbackPriceGroup: any) => {
    if (!card || typeof card.getObjects !== 'function' || !rollbackPriceGroup) return false;
    try {
        if (currentPriceGroup) card.remove(currentPriceGroup);
    } catch {
        // ignore
    }
    safeAddWithUpdate(card, rollbackPriceGroup);
    const cardW = card._cardWidth ?? card.width ?? card.getScaledWidth?.() ?? 0;
    const cardH = card._cardHeight ?? card.height ?? card.getScaledHeight?.() ?? 0;
    if (cardW && cardH) card.set({ width: cardW, height: cardH });
    card.dirty = true;
    card.setCoords?.();
    return true;
};

type ApplyLabelTemplateToZoneOptions = {
    applyToExisting?: boolean;
    requestRender?: boolean;
    save?: boolean;
    cards?: any[];
};

async function applyLabelTemplateToZone(
    zone: any,
    templateId?: string,
    options: boolean | ApplyLabelTemplateToZoneOptions = false
) {
    if (!canvas.value || !zone || !isLikelyProductZone(zone)) return false;
    const applyOptions = typeof options === 'boolean'
        ? { applyToExisting: options, requestRender: true, save: true, cards: undefined }
        : {
            applyToExisting: !!options?.applyToExisting,
            requestRender: options?.requestRender !== false,
            save: options?.save !== false,
            cards: Array.isArray(options?.cards) ? options.cards.filter(Boolean) : undefined
        };
    const id = templateId || undefined;
    const prev = getZoneGlobalStyles(zone);
    const nextZoneStyles = normalizeGlobalStyles({ ...prev, splashTemplateId: id });
    const tpl = id
        ? labelTemplates.value.find((t: any) => String(t?.id || '') === String(id))
        : null;
    const snapshot = cloneTemplateGroupJson((tpl as any)?.group);

    if (applyOptions.applyToExisting) {
        const cards = applyOptions.cards && applyOptions.cards.length > 0
            ? applyOptions.cards
            : getZoneChildren(zone);
        const rollbackMap = new Map<any, any>();
        for (const card of cards) {
            const oldPg = typeof card?.getObjects === 'function'
                ? card.getObjects().find((o: any) => o && o.type === 'group' && o.name === 'priceGroup')
                : null;
            const rollbackClone = oldPg ? await clonePriceGroupForRollback(oldPg) : null;
            if (rollbackClone) rollbackMap.set(card, rollbackClone);
        }
        let failedCards = 0;
        for (const card of cards) {
            try {
                if (id) await applyLabelTemplateToCard(card, id);
                else await resetCardPriceGroupToDefault(card);
            } catch (err) {
                failedCards += 1;
                console.warn('[labelTemplates] Failed to apply zone template to card', err);
            }
        }
        if (failedCards > 0) {
            for (const card of cards) {
                const rollbackPriceGroup = rollbackMap.get(card);
                if (!rollbackPriceGroup) continue;
                const currentPg = typeof card?.getObjects === 'function'
                    ? card.getObjects().find((o: any) => o && o.type === 'group' && o.name === 'priceGroup')
                    : null;
                restoreCardPriceGroup(card, currentPg, rollbackPriceGroup);
            }
            if (applyOptions.requestRender) safeRequestRenderAll();
            console.warn(`[labelTemplates] Aborting zone template persistence because ${failedCards} card(s) failed`);
            return false;
        }

        (zone as any)._zoneGlobalStyles = nextZoneStyles;
        if (id) {
            (zone as any)._zoneTemplateSnapshotId = id;
            (zone as any)._zoneTemplateSnapshot = snapshot || null;
        } else {
            (zone as any)._zoneTemplateSnapshotId = undefined;
            (zone as any)._zoneTemplateSnapshot = undefined;
        }

        // Also re-apply colors/text style if the zone has global styles.
        const labelStyleProps = [
            'splashColor',
            'accentColor',
            'splashFill',
            'splashTextColor',
            'priceTextColor',
            'priceCurrencyColor',
            'priceFont',
            'priceFontWeight',
            'priceFontStyle',
            'currencySymbol',
            'priceFontSize',
            'splashTextScale',
            'splashStrokeWidth',
            'splashRoundness',
            'splashScale',
            'splashOffsetY'
        ];
        labelStyleProps.forEach((prop) => {
            applyGlobalStylesToCards(nextZoneStyles, zone, { cards, prop });
        });
    } else {
        (zone as any)._zoneGlobalStyles = nextZoneStyles;
        if (id) {
            (zone as any)._zoneTemplateSnapshotId = id;
            (zone as any)._zoneTemplateSnapshot = snapshot || null;
        } else {
            (zone as any)._zoneTemplateSnapshotId = undefined;
            (zone as any)._zoneTemplateSnapshot = undefined;
        }
    }

    if (applyOptions.requestRender) safeRequestRenderAll();
    if (applyOptions.save) await saveCurrentState();
    return true;
}

const applyTemplateToActiveZone = (templateId?: string) => {
    const zone = canvas.value?.getActiveObject?.();
    if (zone && isLikelyProductZone(zone)) {
        void applyLabelTemplateToZone(zone, templateId, { applyToExisting: true });
    }
}

async function setTemplateSplashImage(templateId: string, file: File) {
    if (!fabric) return;
    const idx = labelTemplates.value.findIndex(t => t.id === templateId);
    if (idx === -1) return;

    try {
        const uploaded = await uploadFile(file);
        if (!uploaded?.success || !uploaded?.url) return;

        const tpl = labelTemplates.value[idx]!;
        const g = await instantiatePriceGroupFromTemplate(tpl);

        const labelProxyUrl = toWasabiProxyUrl(uploaded.url) || uploaded.url;
        const img: any = await fabric.Image.fromURL(labelProxyUrl, { crossOrigin: 'anonymous' });
        img.set({
            name: 'price_bg_image',
            originX: 'center',
            originY: 'center',
            left: 0,
            top: 0,
            selectable: false,
            evented: false
        });

        const current = typeof g.getObjects === 'function' ? g.getObjects().slice() : [];
        current.forEach((o: any) => g.remove(o));
        safeAddWithUpdate(g, img);
        current.forEach((o: any) => safeAddWithUpdate(g, o));

        // Serialize back into the template
        const next: LabelTemplate = {
            ...tpl,
            group: serializePriceGroupForTemplate(g),
            updatedAt: new Date().toISOString()
        };
        (next as any).__fromDb = false;
        (next as any).__localOverride = true;
        next.previewDataUrl = await renderLabelTemplatePreview(next);

        const list = [...labelTemplates.value];
        list[idx] = next;
        labelTemplates.value = list;
        saveCurrentState();
        await upsertLabelTemplateToDb(next);
    } catch (err) {
        console.warn('[labelTemplates] Failed to set splash image', err);
    }
}

async function insertLabelTemplateToCanvas(templateId: string) {
    if (!canvas.value) return;
    const tpl = labelTemplates.value.find(t => t.id === templateId);
    if (!tpl) return;
    try {
        const g = await instantiatePriceGroupFromTemplate(tpl);
        restoreMissingManualTemplateFlags(g);
        // Match the preview pipeline: always stabilize bounds before inserting on the canvas.
        layoutPriceGroup(g, 320, 220);
        const center = getCenterOfView();
        g.set({
            left: center.x,
            top: center.y,
            originX: 'center',
            originY: 'center',
            selectable: true,
            evented: true,
            hasControls: true,
            hasBorders: true,
            excludeFromExport: true,
            name: 'priceGroup',
            subTargetCheck: true,
            interactive: true
        });
        if (typeof g.getObjects === 'function') {
            g.getObjects().forEach((child: any) => child.set({ selectable: true, evented: true, hasControls: true, hasBorders: true }));
        }
        (g as any)._customId = makeId();
        canvas.value.add(g);

        // Center using the actual rendered bounds. Some custom templates can have
        // an offset local origin, which makes `left/top = viewport center` appear off-screen.
        try {
            g.setCoords?.();
            const bounds = g.getBoundingRect?.(true);
            if (bounds && Number.isFinite(bounds.left) && Number.isFinite(bounds.top) && Number.isFinite(bounds.width) && Number.isFinite(bounds.height)) {
                const boundsCenterX = bounds.left + (bounds.width / 2);
                const boundsCenterY = bounds.top + (bounds.height / 2);
                const dx = center.x - boundsCenterX;
                const dy = center.y - boundsCenterY;
                if (Math.abs(dx) > 0.001 || Math.abs(dy) > 0.001) {
                    g.set({
                        left: Number(g.left || 0) + dx,
                        top: Number(g.top || 0) + dy
                    });
                    g.setCoords?.();
                }
            }
        } catch (centerErr) {
            console.warn('[labelTemplates] Failed to recenter inserted template bounds', centerErr);
        }

        canvas.value.setActiveObject(g);
        safeRequestRenderAll();
        saveCurrentState();
    } catch (err) {
        console.warn('[labelTemplates] Failed to insert template', err);
    }
}

function beginEditSelectedLabel() {
    if (!canvas.value) return;

    const active = canvas.value.getActiveObject();
    const card = getCardGroupFromAny(active);
    const pg = getPriceGroupFromAny(active);

    // Close modal so the user can interact with the canvas immediately.
    showLabelTemplatesModal.value = false;

    // Enable deep editing on the card so sub-targets can be selected.
    if (card && card.type === 'group') {
        card.set({ subTargetCheck: true, interactive: true });
        if (typeof card.getObjects === 'function') {
            card.getObjects().forEach((child: any) => {
                child.set({
                    selectable: true,
                    evented: true,
                    hasControls: true,
                    hasBorders: true,
                    lockMovementX: false,
                    lockMovementY: false,
                    lockScalingX: false,
                    lockScalingY: false,
                    lockRotation: false
                });
                child.setCoords?.();
            });
        }
        card.setCoords?.();
        canvas.value.setActiveObject(card);
    }

    // Also enable editing inside the priceGroup directly (2nd level).
    if (pg && pg.type === 'group') {
        pg.set({ subTargetCheck: true, interactive: true });
        if (typeof pg.getObjects === 'function') {
            pg.getObjects().forEach((child: any) => {
                const isBgImage = child?.name === 'price_bg_image' || child?.name === 'splash_image';
                child.set({
                    selectable: !isBgImage,
                    evented: !isBgImage,
                    hasControls: !isBgImage,
                    hasBorders: !isBgImage,
                    lockMovementX: false,
                    lockMovementY: false,
                    lockScalingX: false,
                    lockScalingY: false,
                    lockRotation: false
                });
                child.setCoords?.();
            });
        }
        pg.setCoords?.();
    }

    safeRequestRenderAll();
    triggerRef(selectedObjectRef);
}

async function handleUpdateTemplateFromMiniEditor(
    templateId: string,
    updates: { group: any; previewDataUrl?: string; name?: string },
    done?: (result: { ok: boolean; message?: string }) => void
) {
    try {
        const idx = labelTemplates.value.findIndex(t => t.id === templateId);
        if (idx === -1) {
            done?.({ ok: false, message: 'Modelo não encontrado para salvar.' });
            return;
        }

        const prev = labelTemplates.value[idx]!;
        const rawGroup: any = (updates.group ?? prev.group);
        let nextGroup: any = rawGroup;
        try {
            nextGroup = (typeof structuredClone === 'function')
                ? structuredClone(rawGroup)
                : JSON.parse(JSON.stringify(rawGroup));
        } catch {
            // Fallback to raw object if cloning is not possible.
            nextGroup = rawGroup;
        }

        if (nextGroup && typeof nextGroup === 'object') {
            delete nextGroup.layoutManager;
            delete nextGroup.layout;
            // Mini editor is explicit manual mode: preserve exact element layout on cards/reload.
            nextGroup.__preserveManualLayout = true;
            nextGroup.__isCustomTemplate = true;
            // Preserve explicit canonical flag (only if the template opted into it).
            if (nextGroup.__forceAtacarejoCanonical == null && prev?.group && (prev.group as any).__forceAtacarejoCanonical != null) {
                nextGroup.__forceAtacarejoCanonical = (prev.group as any).__forceAtacarejoCanonical;
            }
            const useVariantSnapshots = shouldUseAtacVariantSnapshotsForTemplate(nextGroup);
            if (!useVariantSnapshots) {
                (nextGroup as any).__atacVariantGroups = {};
            }
            // Guard against serializer/runtime paths that may omit this metadata.
            // Never drop previously saved per-variant settings on update.
            if (
                (nextGroup as any).__atacValueVariants == null &&
                prev?.group &&
                typeof (prev.group as any).__atacValueVariants === 'object'
            ) {
                try {
                    (nextGroup as any).__atacValueVariants =
                        typeof structuredClone === 'function'
                            ? structuredClone((prev.group as any).__atacValueVariants)
                            : JSON.parse(JSON.stringify((prev.group as any).__atacValueVariants));
                } catch {
                    (nextGroup as any).__atacValueVariants = (prev.group as any).__atacValueVariants;
                }
            }
            if (
                useVariantSnapshots &&
                (nextGroup as any).__atacVariantGroups == null &&
                prev?.group &&
                typeof (prev.group as any).__atacVariantGroups === 'object'
            ) {
                try {
                    (nextGroup as any).__atacVariantGroups =
                        typeof structuredClone === 'function'
                            ? structuredClone((prev.group as any).__atacVariantGroups)
                            : JSON.parse(JSON.stringify((prev.group as any).__atacVariantGroups));
                } catch {
                    (nextGroup as any).__atacVariantGroups = (prev.group as any).__atacVariantGroups;
                }
            }
            const manualTemplateProps = MANUAL_TEMPLATE_STABLE_PROPS;
            for (const key of manualTemplateProps) {
                if ((nextGroup as any)[key] == null && prev?.group && (prev.group as any)[key] != null) {
                    try {
                        (nextGroup as any)[key] = typeof structuredClone === 'function'
                            ? structuredClone((prev.group as any)[key])
                            : JSON.parse(JSON.stringify((prev.group as any)[key]));
                    } catch {
                        (nextGroup as any)[key] = (prev.group as any)[key];
                    }
                }
            }
        }
        sanitizeRedBurstTemplateGroupJson(nextGroup);

        const next: LabelTemplate = {
            ...prev,
            name: (updates.name ?? prev.name),
            group: nextGroup,
            updatedAt: new Date().toISOString()
        };
        const regeneratedPreview = await renderLabelTemplatePreview(next);
        next.previewDataUrl = regeneratedPreview ?? updates.previewDataUrl ?? prev.previewDataUrl;
        (next as any).__previewRenderVersion = regeneratedPreview
            ? LABEL_TEMPLATE_PREVIEW_RENDER_VERSION
            : Number((prev as any)?.__previewRenderVersion || 0);

        (next as any).__fromDb = false;
        (next as any).__localOverride = true;
        const list = [...labelTemplates.value];
        list[idx] = next;
        labelTemplates.value = list;
        // Keep template definitions aligned across all pages so reload/page-switch
        // cannot bring back stale template snapshots from another page.
        syncLabelTemplatesIntoProjectPages('user');
        saveCurrentState({
            reason: 'mini-editor:template-update',
            skipCoalesce: true,
            skipIfUnchanged: false
        });

        const saved = await upsertLabelTemplateToDb(next);
        if (!saved) {
            console.warn('[labelTemplates] Edição salva no projeto, mas não foi persistida na biblioteca de templates (DB)');
        }

        // If this template is in use by any zone, re-apply it to keep cards in sync.
        if (canvas.value) {
            const zones = canvas.value.getObjects().filter((o: any) => isLikelyProductZone(o));
            for (const z of zones) {
                const usedByStyle = String((z as any)?._zoneGlobalStyles?.splashTemplateId || '').trim();
                const usedBySnapshot = String((z as any)?._zoneTemplateSnapshotId || '').trim();
                if (usedByStyle === templateId || usedBySnapshot === templateId) {
                    // Template edited in mini editor: refresh existing cards that already use it.
                    await applyLabelTemplateToZone(z, templateId, true);
                }
            }
        }

        // Save template edits remotely before returning control to UI
        // so reload/navigation does not drop latest mini editor changes.
        if (hasUnsavedChanges.value) {
            triggerAutoSave();
            try {
                await flushAutoSave();
            } catch (persistErr) {
                console.warn('[labelTemplates] Falha ao forcar flush remoto apos salvar mini editor', persistErr);
            }
        }

        done?.({ ok: true });
    } catch (err: any) {
        console.error('[labelTemplates] Falha ao salvar edição do mini editor', err);
        done?.({ ok: false, message: String(err?.message || 'Falha ao salvar a etiqueta.') });
    }
}

// Helper for Responsive Card Layout
const buildCardRelayoutSignature = (group: any, w: number, h: number, styles?: Partial<GlobalStyles>) => {
    const num = (v: any, precision = 3) => {
        const n = Number(v);
        if (!Number.isFinite(n)) return null;
        return Number(n.toFixed(precision));
    };
    const txt = (v: any) => {
        if (v === null || v === undefined) return '';
        return String(v);
    };

    const productData = ((group as any)?._productData && typeof (group as any)._productData === 'object')
        ? ((group as any)._productData as Record<string, any>)
        : {};
    const s = (styles && typeof styles === 'object') ? styles : ({} as Partial<GlobalStyles>);

    // Include ALL visual style values so resizeSmartObject re-applies when any style changes.
    const styleSig = {
        __refCellW: num((s as any).__refCellW),
        __refCellH: num((s as any).__refCellH),
        splashTemplateId: txt((s as any).splashTemplateId),
        splashScale: num((s as any).splashScale),
        splashOffsetY: num((s as any).splashOffsetY),
        splashTextScale: num((s as any).splashTextScale),
        splashFill: txt((s as any).splashFill),
        splashColor: txt((s as any).splashColor ?? (s as any).accentColor),
        splashTextColor: txt((s as any).splashTextColor),
        splashStrokeWidth: num((s as any).splashStrokeWidth),
        priceTextColor: txt((s as any).priceTextColor),
        priceCurrencyColor: txt((s as any).priceCurrencyColor),
        priceFont: txt((s as any).priceFont),
        priceFontSize: num((s as any).priceFontSize),
        priceFontWeight: txt((s as any).priceFontWeight),
        priceFontStyle: txt((s as any).priceFontStyle),
        currencySymbol: txt((s as any).currencySymbol),
        prodNameScale: num((s as any).prodNameScale),
        prodNameTransform: txt((s as any).prodNameTransform),
        prodNameLineHeight: num((s as any).prodNameLineHeight),
        prodNameOffsetY: num((s as any).prodNameOffsetY),
        cardBorderRadius: num((s as any).cardBorderRadius),
        // Visual props — invalidate cache when colors/fonts change
        cardColor: txt((s as any).cardColor),
        isProdBgTransparent: !!(s as any).isProdBgTransparent,
        cardBorderColor: txt((s as any).cardBorderColor),
        cardBorderWidth: num((s as any).cardBorderWidth),
        prodNameColor: txt((s as any).prodNameColor),
        prodNameFont: txt((s as any).prodNameFont),
        prodNameWeight: txt((s as any).prodNameWeight),
        prodNameAlign: txt((s as any).prodNameAlign),
        limitColor: txt((s as any).limitColor),
        limitFont: txt((s as any).limitFont)
    };

    const pricingSig = {
        price: txt((group as any)?.price ?? productData.price),
        pricePack: txt((group as any)?.pricePack ?? productData.pricePack),
        priceUnit: txt((group as any)?.priceUnit ?? productData.priceUnit),
        priceSpecial: txt((group as any)?.priceSpecial ?? productData.priceSpecial),
        priceSpecialUnit: txt((group as any)?.priceSpecialUnit ?? productData.priceSpecialUnit),
        priceWholesale: txt((group as any)?.priceWholesale ?? productData.priceWholesale),
        wholesaleTrigger: txt((group as any)?.wholesaleTrigger ?? productData.wholesaleTrigger),
        wholesaleTriggerUnit: txt((group as any)?.wholesaleTriggerUnit ?? productData.wholesaleTriggerUnit),
        packQuantity: txt((group as any)?.packQuantity ?? productData.packQuantity),
        packUnit: txt((group as any)?.packUnit ?? productData.packUnit),
        packageLabel: txt((group as any)?.packageLabel ?? productData.packageLabel),
        specialCondition: txt((group as any)?.specialCondition ?? productData.specialCondition),
        imageUrl: txt((group as any)?.imageUrl ?? productData.imageUrl ?? productData.image),
        // Product name and limit affect internal layout (title height, badge visibility)
        name: txt(productData.name),
        limitText: txt(productData.limitText || productData.limit)
    };

    return JSON.stringify({
        w: num(w),
        h: num(h),
        styleSig,
        pricingSig
    });
};

const resolvePriceGroupBaseScale = (priceGroup: any, axis: 'x' | 'y', zoneScale: number) => {
    const originalKey = axis === 'x' ? '__originalScaleX' : '__originalScaleY';
    const scaleKey = axis === 'x' ? 'scaleX' : 'scaleY';
    const originalScale = Math.abs(Number((priceGroup as any)?.[originalKey]));
    if (Number.isFinite(originalScale) && originalScale > 0.02) {
        return originalScale;
    }

    const currentScale = Math.abs(Number((priceGroup as any)?.[scaleKey]));
    const safeCurrentScale = Number.isFinite(currentScale) && currentScale > 0.02 ? currentScale : 1;
    const safeZoneScale = Math.abs(Number(zoneScale));
    if (Number.isFinite(safeZoneScale) && safeZoneScale > 0.02) {
        const inferredBase = safeCurrentScale / safeZoneScale;
        if (Number.isFinite(inferredBase) && inferredBase > 0.02) {
            return inferredBase;
        }
    }

    return safeCurrentScale;
};

const resizeSmartObject = (group: any, w: number, h: number, styles?: Partial<GlobalStyles>) => {
    // FIX: Permanently disable Fabric v7 LayoutManager on product card groups.
    // Card layout is fully managed by resizeSmartObject — Fabric's auto-layout
    // only causes corruption by recalculating bounds from children at stale positions.
    // A permanent no-op is simpler and eliminates recursion/wrapper-chain bugs.
    const cardLm = (group as any).layoutManager;
    if (cardLm && cardLm.performLayout) cardLm.performLayout = () => {};

    // CRITICAL FIX: Check signature BEFORE calling group.set({ width, height }).
    // In Fabric v7, group.set({ width, height }) shifts the group's internal coordinate
    // system (center origin), which displaces ALL children. If we can skip the relayout
    // (signature matches), we must NOT touch width/height to avoid this corruption.
    const relayoutSignature = buildCardRelayoutSignature(group, w, h, styles);
    const forceRelayout = (group as any).__forceCardRelayout === true;
    const CARD_RELAYOUT_SIG_TTL_MS = 60000; // 1 minuto — evita layout stale após mudanças externas
    const sigAge = Date.now() - Number((group as any).__lastCardRelayoutAt || 0);
    const sigValid = !forceRelayout &&
        (group as any).__lastCardRelayoutSignature === relayoutSignature &&
        Number.isFinite(sigAge) && sigAge >= 0 && sigAge < CARD_RELAYOUT_SIG_TTL_MS;
    if (sigValid) {
        // Dimensions and styles match — skip relayout entirely.
        // Only update stored card dimensions (for serialization) without touching the group.
        (group as any)._cardWidth = w;
        (group as any)._cardHeight = h;
        group.dirty = true;
        group.setCoords?.();
        return;
    }
    (group as any).__lastCardRelayoutSignature = relayoutSignature;
    (group as any).__lastCardRelayoutAt = Date.now();
    (group as any).__forceCardRelayout = false;

    // Preservar _productData antes de operações que podem perdê-la
    const savedProductData = ((group as any)?._productData && typeof (group as any)._productData === 'object')
        ? JSON.parse(JSON.stringify((group as any)._productData))
        : null;

    // Now that we know we're doing a full relayout, set dimensions.
    // Reset scale first to ensure clean internal layout.
    group.scale(1);
    group.set({ width: w, height: h });

    // Restaurar _productData caso Fabric a tenha perdido no set()
    if (savedProductData && (!(group as any)?._productData || typeof (group as any)._productData !== 'object')) {
        (group as any)._productData = savedProductData;
    }
    
    const halfW = w / 2;
    const halfH = h / 2;
    const _refH = Number((styles as any)?.__refCellH) || h;
    const baseSize = Math.min(w, h);
    const clamp = (n: number, min: number, max: number) => Math.min(max, Math.max(min, n));
    const objects = group.getObjects();
    let bg: any = null;
    let title: any = null;
    let limit: any = null;
    let img: any = null;
    let namedSplash: any = null;
    let fallbackSplashGroup: any = null;
    let directPriceGroup: any = null;
    let topMostText: any = null;
    let topMostTextTop = Infinity;
    let largestRect: any = null;
    let largestRectArea = -1;
    let rectCount = 0;
    let imageCount = 0;
    let loneImage: any = null;

    // Single-pass lookup to keep relayout fast when many cards are updated.
    for (const obj of objects) {
        if (!obj) continue;
        const name = String(obj.name || '');
        const type = String(obj.type || '').toLowerCase();

        if (!bg && name === 'offerBackground') bg = obj;
        if (!title && name === 'smart_title') title = obj;
        if (!img && name === 'smart_image') img = obj;
        if (!namedSplash && (name === 'smart_price' || name === 'smart_splash')) namedSplash = obj;
        if (!directPriceGroup && type === 'group' && name === 'priceGroup') directPriceGroup = obj;
        if (!fallbackSplashGroup && type === 'group') fallbackSplashGroup = obj;
        if (!limit && (name === 'smart_limit' || name === 'limitText' || name === 'product_limit' || obj?.data?.smartType === 'product-limit')) {
            limit = obj;
        }

        if (type === 'rect') {
            rectCount += 1;
            const area = (obj?.width || 0) * (obj?.height || 0) * (obj?.scaleX || 1) * (obj?.scaleY || 1);
            if (area >= largestRectArea) {
                largestRectArea = area;
                largestRect = obj;
            }
        }

        if (isTextLikeObject(obj)) {
            const top = typeof obj?.top === 'number' ? obj.top : Infinity;
            if (top <= topMostTextTop) {
                topMostTextTop = top;
                topMostText = obj;
            }
        }

        if (type === 'image') {
            imageCount += 1;
            loneImage = obj;
        }
    }

    // Fallback: The background is usually the largest rect that fills most of the card.
    if (!bg && largestRect && rectCount > 0) {
        bg = largestRect;
        bg.name = 'offerBackground'; // Repair name
    }

    // Fallback: title is usually the top-most text object.
    if (!title && topMostText) {
        title = topMostText;
        title.name = 'smart_title';
    }

    // Fallback: image is often the only image in the card.
    if (!img && imageCount === 1 && loneImage) {
        img = loneImage;
        img.name = 'smart_image';
    }

    // Splash can vary names; prefer the canonical price label group when present (even when nested).
    const isDescendantOfGroup = (candidate: any, root: any) => {
        let current = candidate;
        while (current) {
            if (current === root) return true;
            current = current.group;
        }
        return false;
    };

    let priceGroup = (group as any).__priceGroupRef;
    if (!(priceGroup && priceGroup.type === 'group' && isDescendantOfGroup(priceGroup, group))) {
        priceGroup = directPriceGroup ?? getPriceGroupFromAny(group);
        (group as any).__priceGroupRef = priceGroup ?? null;
    }

    const splash = priceGroup ?? namedSplash ?? fallbackSplashGroup;

    // When the user moves an inner element (deep select), we mark it with `__manualTransform`.
    // During zone relayout (and on reload), we must NOT override these user placements.
    const isManual = (o: any) => !!(o && (o as any).__manualTransform);

    // If the card size changes (ex: more items in the zone, zone resize, preset change),
    // reposition manual elements proportionally so they keep their relative placement.
    const maybeRescaleManualTransforms = (o: any) => {
        if (!o || !isManual(o)) return;
        const prevW = Number((o as any).__manualTransformCardW);
        const prevH = Number((o as any).__manualTransformCardH);

        // Initialize baseline on first layout pass.
        if (!Number.isFinite(prevW) || prevW <= 0 || !Number.isFinite(prevH) || prevH <= 0) {
            (o as any).__manualTransformCardW = w;
            (o as any).__manualTransformCardH = h;
            return;
        }

        // Skip micro-deltas to avoid drift on repeated relayouts with same size.
        const dw = Math.abs(prevW - w);
        const dh = Math.abs(prevH - h);
        if (dw < 0.5 && dh < 0.5) return;

        const rx = w / prevW;
        const ry = h / prevH;
        if (!Number.isFinite(rx) || !Number.isFinite(ry) || rx <= 0 || ry <= 0) return;

        if (typeof o.left === 'number') o.left = o.left * rx;
        if (typeof o.top === 'number') o.top = o.top * ry;
        o.setCoords?.();

        (o as any).__manualTransformCardW = w;
        (o as any).__manualTransformCardH = h;
    };
    objects.forEach((o: any) => maybeRescaleManualTransforms(o));
    
    // 1. Background Fill
    if (bg) {
        if(bg.type === 'rect') {
             // Keep the background centered on the group origin to avoid drifting bounds/selection boxes.
             bg.set({
                 width: w,
                 height: h,
                 scaleX: 1,
                 scaleY: 1,
                 originX: 'center',
                 originY: 'center',
                 left: 0,
                 top: 0
             });

             if (styles) {
                 // Só aplicar cor se o card já tinha uma cor definida (não forçar cor em cards transparentes)
                 const currentFill = typeof bg.fill === 'string' ? bg.fill : '';
                 const hadExplicitBg = currentFill && currentFill !== 'transparent' && currentFill !== '';
                 if (styles.isProdBgTransparent) bg.set('fill', 'transparent');
                 else if (styles.cardColor && hadExplicitBg) bg.set('fill', styles.cardColor);
                 if (typeof styles.cardBorderRadius === 'number') bg.set({ rx: styles.cardBorderRadius, ry: styles.cardBorderRadius });

                 // Apply border color and width.
                 // If width is 0, keep border fully disabled (default cards without outline).
                 if (styles.cardBorderColor) {
                     const borderWidth = Math.max(0, Number(styles.cardBorderWidth ?? 0));
                     if (borderWidth > 0) {
                         bg.set('stroke', styles.cardBorderColor);
                         bg.set('strokeWidth', borderWidth);
                     } else {
                         bg.set('stroke', undefined);
                         bg.set('strokeWidth', 0);
                     }
                 } else if (typeof styles.cardBorderWidth === 'number') {
                     const borderWidth = Math.max(0, Number(styles.cardBorderWidth ?? 0));
                     if (borderWidth > 0) {
                         bg.set('strokeWidth', borderWidth);
                     } else {
                         bg.set('stroke', undefined);
                         bg.set('strokeWidth', 0);
                     }
                 }
             }
        } else {
             bg.set({ scaleX: w / bg.width, scaleY: h / bg.height, left: 0, top: 0, originX: 'center', originY: 'center' });
        }
    }
    
    // 2. Title (Top)
    let titleH = 0;
    if (title) {
        const persistedTitleWidth = Number((group as any)?._productData?.titleTextWidth);
        const persistedTitleWidthRatio = Number((group as any)?._productData?.titleTextWidthRatio);
        if (
            !(title as any).__manualTransform &&
            (
                (Number.isFinite(persistedTitleWidthRatio) && persistedTitleWidthRatio > 0) ||
                (Number.isFinite(persistedTitleWidth) && persistedTitleWidth > 0)
            )
        ) {
            (title as any).__manualTransform = true;
            if (Number.isFinite(persistedTitleWidth) && persistedTitleWidth > 0) {
                (title as any).__manualTextWidth = persistedTitleWidth;
            }
            if (Number.isFinite(persistedTitleWidthRatio) && persistedTitleWidthRatio > 0) {
                (title as any).__manualTextWidthRatio = Math.min(1, Math.max(0.1, persistedTitleWidthRatio));
            }
            if (w > 0) (title as any).__manualTransformCardW = w;
            if (h > 0) (title as any).__manualTransformCardH = h;
        }
        // Margin Top: 5% of height
        const marginTop = h * 0.05;
        const _rawNameOffY = typeof styles?.prodNameOffsetY === 'number' ? styles.prodNameOffsetY : 0;
        const titleOffsetY = _rawNameOffY * (h / _refH);
        if (!isManual(title)) {
            title.set({
                originX: 'center',
                originY: 'top',
                left: 0,
                top: -halfH + marginTop + titleOffsetY,
                scaleX: 1, scaleY: 1
            });
        }

        if (styles) {
            if (styles.prodNameFont) title.set('fontFamily', styles.prodNameFont);
            if (styles.prodNameColor) title.set('fill', styles.prodNameColor);
            if (styles.prodNameWeight !== undefined) title.set('fontWeight', styles.prodNameWeight as any);
            if (styles.prodNameAlign) title.set('textAlign', styles.prodNameAlign);
            if (typeof styles.prodNameLineHeight === 'number') title.set('lineHeight', styles.prodNameLineHeight);

            const rawKey = '__rawText';
            const curText = String((title as any).text ?? '');
            if (typeof (title as any)[rawKey] !== 'string') (title as any)[rawKey] = curText;
            const mode = styles.prodNameTransform ?? 'none';
            if (mode === 'none') {
                (title as any)[rawKey] = curText;
            } else {
                const baseText = String((title as any)[rawKey] ?? curText);
                const nextText = mode === 'upper' ? baseText.toUpperCase() : mode === 'lower' ? baseText.toLowerCase() : baseText;
                if (nextText !== curText) title.set('text', nextText);
            }

            const scale = typeof styles.prodNameScale === 'number' ? styles.prodNameScale : 1;
            const baseFont = baseSize * 0.09;
            const nextFont = clamp(baseFont * scale, 10, baseSize * 0.22);
            title.set('fontSize', nextFont);
        }
        
        // Responsive Text Width
        if (title.type === 'textbox') {
            const manualTitleWidth = Number((title as any).__manualTextWidth);
            const manualTitleWidthRatio = Number((title as any).__manualTextWidthRatio);
            let nextTitleWidth = w * 0.9; // default auto width
            if (isManual(title)) {
                if (Number.isFinite(manualTitleWidthRatio) && manualTitleWidthRatio > 0) {
                    nextTitleWidth = w * manualTitleWidthRatio;
                } else if (Number.isFinite(manualTitleWidth) && manualTitleWidth > 0) {
                    nextTitleWidth = manualTitleWidth;
                }
            }
            nextTitleWidth = clamp(nextTitleWidth, 20, Math.max(20, w));
            title.set({ width: nextTitleWidth });
            if (isManual(title)) {
                (title as any).__manualTextWidth = nextTitleWidth;
                const ratio = w > 0 ? (nextTitleWidth / w) : Number.NaN;
                if (Number.isFinite(ratio) && ratio > 0) {
                    (title as any).__manualTextWidthRatio = Math.min(1, Math.max(0.1, ratio));
                }
            }
            if (typeof title.initDimensions === 'function') title.initDimensions();
        } else {
            // Scale down if too wide
            if (title.width > w * 0.9) {
                title.scale((w * 0.9) / title.width);
            }
        }
        if (typeof title.initDimensions === 'function') title.initDimensions();
        titleH = title.getScaledHeight() + marginTop;
    }

    // 2.1 Limit badge/text (Below Title)
    let limitH = 0;
        if (limit && String(limit.type || '').includes('text')) {
            const marginTop = h * 0.05;
            const gap = Math.max(4, h * 0.015);
            const _rawLimitNameOffY = typeof styles?.prodNameOffsetY === 'number' ? styles.prodNameOffsetY : 0;
            const titleOffsetY = _rawLimitNameOffY * (h / _refH);

            const titleHeight = title ? (title.getScaledHeight?.() ?? title.height ?? 0) : 0;
            if (!isManual(limit)) {
                limit.set({
                    originX: 'center',
                    originY: 'top',
                    left: 0,
                    top: -halfH + marginTop + titleOffsetY + titleHeight + gap,
                    scaleX: 1,
                    scaleY: 1
                });
            }

        if (styles) {
            if (styles.limitFont) limit.set('fontFamily', styles.limitFont);
            if (styles.limitColor) limit.set('fill', styles.limitColor);

            // Dynamic sizing: base on card size, and respect legacy `limitSize` as multiplier (default ~14).
            const mult = (typeof styles.limitSize === 'number' && styles.limitSize > 0) ? (styles.limitSize / 14) : 1;
            const baseFont = baseSize * 0.045;
            const nextFont = clamp(baseFont * mult, 8, baseSize * 0.12);
            limit.set('fontSize', nextFont);
        } else {
            // Reasonable default if older cards have this text but no styles passed
            const baseFont = baseSize * 0.045;
            limit.set('fontSize', clamp(baseFont, 8, baseSize * 0.12));
        }

        // Hide if empty
        const txt = String((limit as any).text ?? '').trim();
        limit.visible = txt.length > 0;

        if (limit.type === 'textbox') {
            limit.set({ width: w * 0.9 });
            if (typeof (limit as any).initDimensions === 'function') (limit as any).initDimensions();
        }

        if (typeof (limit as any).initDimensions === 'function') (limit as any).initDimensions();
        limitH = limit.visible ? ((limit.getScaledHeight?.() ?? 0) + gap) : 0;
    }

	    // 3. Bottom Element (Splash/Price)
	    let bottomH = 0;
	    if (splash) {
	        const marginBottom = h * 0.05;
	        const splashManual = isManual(splash);
	        let preserveTemplateVisual = false;
	        let layoutScaleX = 1;
	        let layoutScaleY = 1;
	        const manualScaleX = Math.abs(Number((splash as any)?.__manualScaleX ?? 1)) || 1;
	        const manualScaleY = Math.abs(Number((splash as any)?.__manualScaleY ?? 1)) || 1;
	        const hasManualScaleOverride = Math.abs(manualScaleX - 1) > 0.0001 || Math.abs(manualScaleY - 1) > 0.0001;

        if ((splash as any).objectCaching) (splash as any).objectCaching = false;
        if ((splash as any).statefullCache) (splash as any).statefullCache = false;

        // Extract priceBg for later use (shadow update needs pillH from layout)
        let priceBg: any = null;

        if (splash.type === 'group' && splash.name === 'priceGroup') {
            preserveTemplateVisual = shouldPreserveManualTemplateVisual(splash);
            // Apply label styling overrides (local to the selected zone/design; never mutates templates).
            if (styles && typeof splash.getObjects === 'function') {
                const parts = collectObjectsDeep(splash);
                const getName = (o: any) => String(o?.name || '');
                const priceBgNames = new Set(['price_bg', 'atac_retail_bg', 'atac_wholesale_bg']);
                const currencyTextNames = new Set(['price_currency_text', 'retail_currency_text', 'wholesale_currency_text']);
                const integerTextNames = new Set(['price_integer_text', 'retail_integer_text', 'wholesale_integer_text']);
                const decimalTextNames = new Set(['price_decimal_text', 'retail_decimal_text', 'wholesale_decimal_text']);
                const priceTextNames = new Set([
                    'price_integer_text',
                    'price_decimal_text',
                    'price_unit_text',
                    'price_value_text',
                    'retail_integer_text',
                    'retail_decimal_text',
                    'retail_unit_text',
                    'wholesale_integer_text',
                    'wholesale_decimal_text',
                    'wholesale_unit_text'
                ]);
                const allPriceBgs = parts.filter((o: any) => priceBgNames.has(getName(o)));
                const currencyTexts = parts.filter((o: any) => currencyTextNames.has(getName(o)) && isTextLikeObject(o));
                const integerTexts = parts.filter((o: any) => integerTextNames.has(getName(o)) && isTextLikeObject(o));
                const decimalTexts = parts.filter((o: any) => decimalTextNames.has(getName(o)) && isTextLikeObject(o));
                const priceTexts = parts.filter((o: any) => priceTextNames.has(getName(o)) && isTextLikeObject(o));
                priceBg = allPriceBgs[0] || null;
                const normalizeColorToken = (value: any) => {
                    const raw = String(value ?? '').trim().toLowerCase();
                    if (!raw) return '';
                    return raw.startsWith('#') ? raw : `#${raw}`;
                };
                const defaultPriceFont = String(DEFAULT_GLOBAL_STYLES.priceFont || '').trim().toLowerCase();
                const defaultSplashTextColor = normalizeColorToken(DEFAULT_GLOBAL_STYLES.splashTextColor || '');
                const defaultSplashFill = normalizeColorToken(DEFAULT_GLOBAL_STYLES.splashFill || '');
                const defaultAccentColor = normalizeColorToken(
                    DEFAULT_GLOBAL_STYLES.splashColor ?? DEFAULT_GLOBAL_STYLES.accentColor ?? ''
                );

                const accent = styles.splashColor ?? styles.accentColor;
                const hasExplicitAccent = !!String(accent ?? '').trim() && (
                    !preserveTemplateVisual || normalizeColorToken(accent) !== defaultAccentColor
                );
                const hasExplicitFill = typeof styles.splashFill === 'string' && styles.splashFill.trim().length > 0 && (
                    !preserveTemplateVisual || normalizeColorToken(styles.splashFill) !== defaultSplashFill
                );
                const hasExplicitRoundness = typeof styles.splashRoundness === 'number' && (
                    !preserveTemplateVisual ||
                    Math.abs(Number(styles.splashRoundness) - Number(DEFAULT_GLOBAL_STYLES.splashRoundness ?? 1)) > 0.0001
                );
                const hasExplicitStrokeWidth = typeof styles.splashStrokeWidth === 'number' && Number.isFinite(styles.splashStrokeWidth);
                const hasExplicitPriceFont = typeof styles.priceFont === 'string' && styles.priceFont.trim().length > 0 && (
                    !preserveTemplateVisual || styles.priceFont.trim().toLowerCase() !== defaultPriceFont
                );
                const hasExplicitPriceWeight = styles.priceFontWeight !== undefined && (
                    !preserveTemplateVisual ||
                    String(styles.priceFontWeight) !== String(DEFAULT_GLOBAL_STYLES.priceFontWeight ?? '')
                );
                const hasExplicitPriceStyle = typeof styles.priceFontStyle === 'string' && styles.priceFontStyle.trim().length > 0 && (
                    !preserveTemplateVisual ||
                    styles.priceFontStyle !== (DEFAULT_GLOBAL_STYLES.priceFontStyle ?? 'normal')
                );
                const hasExplicitPriceTextColor = typeof styles.priceTextColor === 'string' && styles.priceTextColor.trim().length > 0;
                const hasExplicitSplashTextColor = typeof styles.splashTextColor === 'string' && styles.splashTextColor.trim().length > 0 && (
                    !preserveTemplateVisual || normalizeColorToken(styles.splashTextColor) !== defaultSplashTextColor
                );
                const hasExplicitCurrencyColor = typeof styles.priceCurrencyColor === 'string' && styles.priceCurrencyColor.trim().length > 0;

                allPriceBgs.forEach((bg: any) => {
                    // Apply styles to price background
                    // Priority: explicit splashFill > template fill > default
                    if (hasExplicitFill) {
                        bg.set('fill', styles.splashFill);
                    }
                    if (hasExplicitRoundness && typeof styles.splashRoundness === 'number') {
                        const roundness = clamp(styles.splashRoundness, 0, 1);
                        (bg as any).__roundness = roundness;
                        if (String(bg?.type || '').toLowerCase() === 'rect') {
                            const hRaw = Number(bg.height || 0);
                            if (Number.isFinite(hRaw) && hRaw > 0) {
                                const radius = (hRaw / 2) * roundness;
                                bg.set({ rx: radius, ry: radius });
                            }
                        }
                    }
                    if (hasExplicitStrokeWidth) {
                        const strokeVal = Math.max(0, Number(styles.splashStrokeWidth) || 0);
                        (bg as any).__strokeWidth = strokeVal;
                        if (!preserveTemplateVisual) bg.set('strokeWidth', strokeVal);
                    }

                    // Apply accent/splash color - always apply if set, regardless of template
                    // This allows users to override template colors with zone styles
                    if (hasExplicitAccent && accent) {
                        bg.set('stroke', accent);
                    }
                });

                const applyTextShared = (t: any) => {
                    if (!t || !String(t.type || '').includes('text')) return;
                    // Always apply font and weight if explicitly set (overrides template)
                    if ((!preserveTemplateVisual || hasExplicitPriceFont) && styles.priceFont) t.set('fontFamily', styles.priceFont);
                    if ((!preserveTemplateVisual || hasExplicitPriceWeight) && styles.priceFontWeight !== undefined) {
                        t.set('fontWeight', styles.priceFontWeight as any);
                    }
                    if (!preserveTemplateVisual || hasExplicitPriceStyle) {
                        t.set('fontStyle', styles.priceFontStyle === 'italic' ? 'italic' : 'normal');
                    }

                    const mult = typeof styles.splashTextScale === 'number' ? styles.splashTextScale : 1;
                    if (preserveTemplateVisual) {
                        const originalFont = Number((t as any).__originalFontSize);
                        const currentFont = Number(t.fontSize || 0);
                        const baseFont = Number((t as any).__fontSizeBase);
                        const fallbackBase = Number.isFinite(originalFont) && originalFont > 0
                            ? originalFont
                            : (Number.isFinite(currentFont) && currentFont > 0 ? currentFont : 0);
                        const sourceBase = Number.isFinite(baseFont) && baseFont > 0 ? baseFont : fallbackBase;
                        if (sourceBase > 0) {
                            (t as any).__fontSizeBase = sourceBase;
                            t.set({
                                fontSize: sourceBase * mult,
                                scaleX: 1,
                                scaleY: 1
                            });
                        }
                    } else if (typeof t.__fontScale === 'number') {
                        if (typeof t.__fontScaleBase !== 'number') t.__fontScaleBase = t.__fontScale;
                        t.__fontScale = t.__fontScaleBase * mult;
                    }
                    if (typeof t.initDimensions === 'function') t.initDimensions();
                };

                const applyPriceText = (t: any) => {
                    applyTextShared(t);
                    if (!t || !String(t.type || '').includes('text')) return;
                    // Apply text color if set (explicit override)
                    if (hasExplicitPriceTextColor) t.set('fill', styles.priceTextColor);
                    else if ((!preserveTemplateVisual && typeof styles.splashTextColor === 'string' && styles.splashTextColor.trim())
                        || (preserveTemplateVisual && hasExplicitSplashTextColor)) {
                        t.set('fill', styles.splashTextColor);
                    }
                };

                const applyCurrencyText = (t: any) => {
                    applyTextShared(t);
                    if (!t || !String(t.type || '').includes('text')) return;
                    // Apply currency color if explicitly set
                    if (hasExplicitCurrencyColor) t.set('fill', styles.priceCurrencyColor);
                };

                currencyTexts.forEach(applyCurrencyText);
                priceTexts.forEach(applyPriceText);
                if (styles.currencySymbol !== undefined) {
                    currencyTexts.forEach((ct: any) => {
                        ct.set('text', String(styles.currencySymbol));
                        if (typeof ct.initDimensions === 'function') ct.initDimensions();
                    });
                }
                if (typeof styles.priceFontSize === 'number' && Number.isFinite(styles.priceFontSize) && styles.priceFontSize > 0) {
                    const baseFontSize = styles.priceFontSize;
                    (splash as any).__priceFontSizeOverride = baseFontSize;
                    integerTexts.forEach((txt: any) => {
                        txt.set('fontSize', baseFontSize);
                        if (typeof txt.initDimensions === 'function') txt.initDimensions();
                    });
                    decimalTexts.forEach((txt: any) => {
                        txt.set('fontSize', Math.round(baseFontSize * 0.6));
                        if (typeof txt.initDimensions === 'function') txt.initDimensions();
                    });
                }
                if (preserveTemplateVisual) {
                    // Keep authored geometry, but expand the manual template when typography grows.
                    refreshManualTemplateAfterTypographyChange(splash);
                }
            }

            // Propagar splashTextScale como metadado para as funções de layout.
            (splash as any).__splashTextScale = typeof styles?.splashTextScale === 'number' ? styles!.splashTextScale! : 1;

            // Use reference cell dimensions (from zone layout) so that pill size
            // is uniform across highlight and normal cards.
            const _refW = Number((styles as any)?.__refCellW) || w;
            // _refH already declared in outer scope with same value — reuse it
            const layout = layoutPriceGroup(splash, _refW, _refH);

            if (layout) {
                const { pillH } = layout;
                // fitScale: escala que layoutPriceGroup aplicou para caber no card.
                // Este é o "base scale" — splashScale multiplica por cima dele.
                const fitScaleX = Math.abs(Number(splash.scaleX)) || 1;
                const fitScaleY = Math.abs(Number(splash.scaleY)) || 1;
                const rawScale = typeof styles?.splashScale === 'number' ? styles!.splashScale! : 1;
                const rawOffsetY = typeof styles?.splashOffsetY === 'number' ? styles!.splashOffsetY! : 0;
                const scale = rawScale;
                // Scale offsetY proportionally so the displacement looks the same
                // on highlight (taller) and normal cards.
                const offsetY = rawOffsetY * (h / _refH);

                // Update shadow color to match accent (after we have pillH for proper blur calculation)
                const accent = styles?.splashColor ?? styles?.accentColor;
                if (!preserveTemplateVisual && accent && priceBg && fabric?.Shadow) {
                    priceBg.set('stroke', accent);
                    const blur = Math.max(6, Math.min(26, pillH * 0.22));
                    priceBg.set('shadow', new fabric.Shadow({ color: accent, blur, offsetX: 0, offsetY: 0 }));
                }

                // Force dirty flag to ensure Fabric.js updates the object
                splash.dirty = true;

	                if (!splashManual) {
	                    const newTop = halfH - ((pillH * scale) / 2) - marginBottom + offsetY;
                    // Para manual templates, fitScale é a escala base que o layout calculou.
                    // Guardar como __originalScale ANTES de multiplicar por splashScale.
                    if (preserveTemplateVisual) {
                        (splash as any).__originalScaleX = fitScaleX;
                        (splash as any).__originalScaleY = fitScaleY;
                    }
	                    const finalScaleX = preserveTemplateVisual ? (fitScaleX * scale * manualScaleX) : (scale * manualScaleX);
	                    const finalScaleY = preserveTemplateVisual ? (fitScaleY * scale * manualScaleY) : (scale * manualScaleY);
	                    splash.set({
                        scaleX: finalScaleX,
                        scaleY: finalScaleY,
                        originX: 'center',
                        originY: 'center',
                        left: 0,
                        top: newTop
                    });
	                } else {
                    // Manual positioning: keep left/top, but still apply the zone-level scale.
                    if (preserveTemplateVisual) {
                        (splash as any).__originalScaleX = fitScaleX;
                        (splash as any).__originalScaleY = fitScaleY;
                    }
	                    const finalScaleX = preserveTemplateVisual ? (fitScaleX * scale * manualScaleX) : (scale * manualScaleX);
	                    const finalScaleY = preserveTemplateVisual ? (fitScaleY * scale * manualScaleY) : (scale * manualScaleY);
	                    splash.set({ scaleX: finalScaleX, scaleY: finalScaleY });
	                }

	                if (!splashManual && !hasManualScaleOverride) {
	                    normalizePriceGroupPlacementInCard(splash, w, h, null);
	                }
                
                // Force coordinate update
                splash.setCoords();
                
	                bottomH = (pillH * scale * manualScaleY) + marginBottom;
	            } else {
                // Fallback to generic scaling for older cards without named parts
                // Apply global styles even in fallback mode
                const globalScale = typeof styles?.splashScale === 'number' ? styles!.splashScale! : 1;
                const _rawOffY = typeof styles?.splashOffsetY === 'number' ? styles!.splashOffsetY! : 0;
                const offsetY = _rawOffY * (h / _refH);

                // Calcular escala proporcional ao tamanho do card sem acumulação.
                // Usar tamanho de referência fixo (300px) para evitar capturar valores inflados.
                const SPLASH_REF_WIDTH = 300;
                const sizeRatio = Math.max(0.3, Math.min(3, w / SPLASH_REF_WIDTH));
	                let sScaleX = sizeRatio * globalScale * manualScaleX;
	                let sScaleY = sizeRatio * globalScale * manualScaleY;

                // Force dirty flag to ensure Fabric.js updates the object
                splash.dirty = true;

                if (!splashManual) {
                    const newTop = halfH - marginBottom + offsetY;
                    splash.set({
                        scaleX: sScaleX,
                        scaleY: sScaleY,
                        originX: 'center',
                        originY: 'bottom',
                        left: 0,
                        top: newTop
                    });
                } else {
                    splash.set({ scaleX: sScaleX, scaleY: sScaleY });
                }

                // Force coordinate update
                splash.setCoords();

                bottomH = (splash.height * sScaleY) + marginBottom;
            }
        } else {
            const globalScale = typeof styles?.splashScale === 'number' ? styles!.splashScale! : 1;
            const _rawOffY2 = typeof styles?.splashOffsetY === 'number' ? styles!.splashOffsetY! : 0;
            const offsetY = _rawOffY2 * (h / _refH);

            if (typeof (splash as any).__originalScaleX !== 'number') {
                (splash as any).__originalScaleX = splash.scaleX || 1;
                (splash as any).__originalScaleY = splash.scaleY || 1;
            }

            const baseScaleX = (splash as any).__originalScaleX || 1;
            const baseScaleY = (splash as any).__originalScaleY || 1;
            const sScaleX = baseScaleX * globalScale;
            const sScaleY = baseScaleY * globalScale;
            
            if (!splashManual) {
                splash.set({
                    scaleX: sScaleX,
                    scaleY: sScaleY,
                    originX: 'center',
                    originY: 'bottom',
                    left: 0,
                    top: halfH - marginBottom + offsetY
                });
            } else {
                splash.set({
                    scaleX: sScaleX,
                    scaleY: sScaleY
                });
            }
            
            bottomH = (splash.height * sScaleY) + marginBottom;
        }

        // If the user positioned the splash manually, reserve space based on its current size,
        // not the auto-layout computation above (prevents image layout from hiding it).
        if (splashManual) {
            const sh = typeof splash.getScaledHeight === 'function'
                ? splash.getScaledHeight()
                : (Number(splash.height || 0) * Number(splash.scaleY || 1));
            bottomH = Math.max(0, Number(sh) || 0) + marginBottom;
        }
    }
    
    // 4. Image (Middle - Object Fit: Contain)
    if (img) {
        const imgManual = isManual(img);
        const availH = h - titleH - limitH - bottomH - 20; // 20px buffer
        const availW = w * 0.9;

        // Product images inside cards should never flip during resize interactions.
        img.set({
            lockScalingFlip: true,
            lockSkewingX: true,
            lockSkewingY: true,
            flipX: false,
            flipY: false
        });
        if ((Number(img.scaleX ?? 1) || 1) < 0) img.set('scaleX', Math.abs(Number(img.scaleX ?? 1)) || 1);
        if ((Number(img.scaleY ?? 1) || 1) < 0) img.set('scaleY', Math.abs(Number(img.scaleY ?? 1)) || 1);
        
        if (availH > 20) {
            // Restore scale 1 to measure
            const currentScale = img.scaleX; 
            // We use raw img.width/height assuming scale=1 is base assets.
            
            const iW = img.width;
            const iH = img.height;
            const iRatio = iW / iH;
            const availRatio = availW / availH;
            
            let scale = 1;
            if (iRatio > availRatio) {
                // Width constrained
                scale = availW / iW;
            } else {
                // Height constrained
                scale = availH / iH;
            }
            
            // Center in available space
            // Space starts at: -halfH + titleH
            // Space center: (-halfH + titleH) + (availH / 2)
            const centerY = (-halfH + titleH + limitH) + (availH / 2);
            
            img.visible = true;
            if (!imgManual) {
                img.set({
                    scaleX: scale,
                    scaleY: scale,
                    originX: 'center',
                    originY: 'center',
                    left: 0,
                    top: centerY
                });
            }
        } else {
            // Hide only when auto-layout controls the image; a manual image should remain visible.
            if (!imgManual) img.visible = false;
            else img.visible = true;
        }
    }

    // Keep user-positioned inner elements inside the card bounds after any resize/relayout.
    // This avoids "teleporting" on reload when the card size changes (zone preset/columns/etc.).
    const clampChildToCard = (obj: any) => {
        if (!obj || typeof obj.getScaledWidth !== 'function' || typeof obj.getScaledHeight !== 'function') return;
        const objW = obj.getScaledWidth();
        const objH = obj.getScaledHeight();
        let minX = -halfW;
        let maxX = halfW;
        let minY = -halfH;
        let maxY = halfH;
        if (obj.originX === 'center') { minX = -halfW + objW / 2; maxX = halfW - objW / 2; }
        else if (obj.originX === 'left') { maxX = halfW - objW; }
        if (obj.originY === 'center') { minY = -halfH + objH / 2; maxY = halfH - objH / 2; }
        else if (obj.originY === 'top') { maxY = halfH - objH; }
        if (minX > maxX) { const t = minX; minX = maxX; maxX = t; }
        if (minY > maxY) { const t = minY; minY = maxY; maxY = t; }
        if (typeof obj.left === 'number') obj.left = Math.min(maxX, Math.max(minX, obj.left));
        if (typeof obj.top === 'number') obj.top = Math.min(maxY, Math.max(minY, obj.top));
        obj.setCoords?.();
    };
    objects.forEach((o: any) => {
        if (!o || o === bg) return;
        const allowOverflowOutsideCard = o === splash || String(o?.name || '') === 'priceGroup';
        if (isManual(o) && !allowOverflowOutsideCard) clampChildToCard(o);
    });

    // Ensure stacking order stays predictable (image should not hide the title).
    // We reorder via the internal array to avoid coordinate transforms from remove/add.
    const stackList = (group as any)?._objects;
    if (Array.isArray(stackList)) {
        const moveToIndex = (obj: any, index: number) => {
            if (!obj) return;
            const from = stackList.indexOf(obj);
            if (from === -1) return;
            stackList.splice(from, 1);
            const to = Math.max(0, Math.min(index, stackList.length));
            stackList.splice(to, 0, obj);
        };
        const moveToEnd = (obj: any) => moveToIndex(obj, stackList.length);
        moveToIndex(bg, 0);
        moveToIndex(img, 1);
        moveToEnd(title);
        moveToEnd(splash);
        if (typeof (group as any)._onStackOrderChanged === 'function') {
            (group as any)._onStackOrderChanged();
        }
    }
    
    (group as any)._cardWidth = w;
    (group as any)._cardHeight = h;
    // CRITICAL: Do NOT call safeAddWithUpdate(group) — Fabric's LayoutManager recalculates
    // bounds from ALL children. If splash/shadows extend beyond the intended w×h, Fabric
    // expands the group and shifts its center, causing the background to be offset and the
    // splash/price label to visually ESCAPE the card. Instead, freeze the group dimensions.
    group.set({ width: w, height: h });
    // Update coords for all children (replaces _updateObjectsCoords that safeAddWithUpdate would do)
    objects.forEach((o: any) => {
        if (o && typeof o.setCoords === 'function') o.setCoords();
    });
    group.dirty = true;
    if (typeof group.setCoords === 'function') group.setCoords();

    // LayoutManager is permanently disabled (no-op) at the top of this function.
    // No wrapper needed — dimensions are explicitly set by resizeSmartObject.
}

// getZoneRect / isLikelyProductZone / isStandalonePriceGroup / isLikelyProductCard
// foram extraidos para utils/fabricObjectClassifiers.ts (Fase 2).

const repairLegacyProductCardImageTransforms = (
    cards: any[],
    opts: { verbose?: boolean } = {}
): { cardsScanned: number; imagesScanned: number; imagesRepaired: number } => {
    const verbose = opts.verbose === true;
    if (!Array.isArray(cards) || cards.length === 0) {
        return { cardsScanned: 0, imagesScanned: 0, imagesRepaired: 0 };
    }

    let cardsScanned = 0;
    let imagesScanned = 0;
    let imagesRepaired = 0;

    cards.forEach((card: any) => {
        if (!card || card.type !== 'group') return;
        if (isStandalonePriceGroup(card)) return;

        cardsScanned += 1;
        const descendants = typeof card.getObjects === 'function' ? collectObjectsDeep(card) : [];
        const images = descendants.filter((o: any) => String(o?.type || '').toLowerCase() === 'image');

        images.forEach((img: any) => {
            imagesScanned += 1;
            let changed = false;

            let nextScaleX = Number(img.scaleX ?? 1);
            let nextScaleY = Number(img.scaleY ?? 1);
            if (!Number.isFinite(nextScaleX) || nextScaleX === 0) {
                nextScaleX = 1;
                changed = true;
            }
            if (!Number.isFinite(nextScaleY) || nextScaleY === 0) {
                nextScaleY = 1;
                changed = true;
            }
            if (nextScaleX < 0 || nextScaleY < 0) {
                nextScaleX = Math.abs(nextScaleX) || 1;
                nextScaleY = Math.abs(nextScaleY) || 1;
                changed = true;
            }

            if (img.flipX || img.flipY) changed = true;
            if (img.lockScalingFlip !== true) changed = true;
            if (img.lockSkewingX !== true || img.lockSkewingY !== true) changed = true;

            // Repair invalid intrinsic dimensions when legacy/corrupted state has zero or NaN sizes.
            const rawW = Number(img.width ?? 0);
            const rawH = Number(img.height ?? 0);
            let nextWidth = rawW;
            let nextHeight = rawH;
            if (!Number.isFinite(rawW) || rawW <= 0 || !Number.isFinite(rawH) || rawH <= 0) {
                const el: any = (img as any)._originalElement || (img as any)._element || null;
                const naturalW = Number(el?.naturalWidth ?? el?.width ?? 0);
                const naturalH = Number(el?.naturalHeight ?? el?.height ?? 0);
                if (Number.isFinite(naturalW) && naturalW > 0 && Number.isFinite(naturalH) && naturalH > 0) {
                    nextWidth = naturalW;
                    nextHeight = naturalH;
                    changed = true;
                }
            }

            if (changed) {
                img.set({
                    scaleX: nextScaleX,
                    scaleY: nextScaleY,
                    flipX: false,
                    flipY: false,
                    lockScalingFlip: true,
                    lockSkewingX: true,
                    lockSkewingY: true
                });
                if (Number.isFinite(nextWidth) && nextWidth > 0 && Number.isFinite(nextHeight) && nextHeight > 0) {
                    img.set({
                        width: nextWidth,
                        height: nextHeight
                    });
                }
                img.setCoords?.();
                imagesRepaired += 1;
            }

            // Always clamp inside card after load to prevent detached images from legacy states.
            applyContainmentConstraints(img);
        });
    });

    if (verbose && imagesRepaired > 0) {
        console.log('[repairLegacyProductCardImageTransforms] repaired:', {
            cardsScanned,
            imagesScanned,
            imagesRepaired
        });
    }

    return { cardsScanned, imagesScanned, imagesRepaired };
}

const ensureZoneSanity = (zone: any) => {
    if (!zone) return;
    if (!zone._customId) zone._customId = makeId();
    let needsBoundsUpdate = false;

    // CRITICAL: Product zones should NOT have clipPath as it causes rendering errors
    // Cards are added separately to canvas, not as children of the zone group
    if (zone.clipPath) {
        zone.clipPath = null;
    }

    // Keep Fabric group padding at 0 to avoid inflating the selection bounds.
    // Use `_zonePadding` for layout math instead (used by recalculateZoneLayout).
    if (typeof zone._zonePadding !== 'number') {
        const currentPad = typeof zone.padding === 'number' ? zone.padding : 0;
        // Legacy zones used `group.padding` for layout; older defaults used 5 just for selection padding.
        zone._zonePadding = currentPad >= 10 ? currentPad : 20;
    }
    if (zone.padding !== 0) {
        zone.set('padding', 0);
        needsBoundsUpdate = true;
    }

    // Preserve explicit fixed rows from the zone inspector.
    // Only coerce invalid legacy values back to auto (`0`).
    if (typeof (zone as any).rows !== 'number' || !Number.isFinite((zone as any).rows) || (zone as any).rows < 0) {
        (zone as any).rows = 0;
    } else {
        (zone as any).rows = Math.max(0, Math.round((zone as any).rows));
    }

    // CRITICAL: Initialize _zoneWidth and _zoneHeight if missing (for persistence after reload)
    // This ensures the zone dimensions are correctly restored from the inner rect or calculated bounds
    if (typeof zone._zoneWidth !== 'number' || typeof zone._zoneHeight !== 'number') {
        const rect = typeof zone.getObjects === 'function' 
            ? zone.getObjects().find((o: any) => o?.type === 'rect') 
            : null;
        const rectWidth = rect ? (rect.width ?? 0) * (rect.scaleX ?? 1) : 0;
        const rectHeight = rect ? (rect.height ?? 0) * (rect.scaleY ?? 1) : 0;
        const zoneScaleX = Math.abs(zone.scaleX ?? 1);
        const zoneScaleY = Math.abs(zone.scaleY ?? 1);
        
        if (typeof zone._zoneWidth !== 'number') {
            zone._zoneWidth = rectWidth ? rectWidth * zoneScaleX : (zone.getScaledWidth?.() ?? zone.width ?? 400);
        }
        if (typeof zone._zoneHeight !== 'number') {
            zone._zoneHeight = rectHeight ? rectHeight * zoneScaleY : (zone.getScaledHeight?.() ?? zone.height ?? 600);
        }
        console.log('🔧 [ensureZoneSanity] Initialized zone dimensions:', { _zoneWidth: zone._zoneWidth, _zoneHeight: zone._zoneHeight });
    }

    // Ensure stable interaction flags
    // NOTE: we intentionally do NOT set objectCaching/statefullCache here.
    // Those props are in CANVAS_CUSTOM_PROPS; forcing them to false on zones
    // persists the value and degrades rendering performance for all subsequent
    // loads. If a zone needs a cache refresh, call zone.set('dirty', true).
    zone.set({
        lockScalingFlip: true,
        selectable: true,
        evented: true,
        hasControls: true,
        hasBorders: true,
        subTargetCheck: false
    });

    // Normalize the inner rect scale so it always matches the group bounds while scaling.
    const rect = getZoneRect(zone);
    if (rect) {
        const sx = rect.scaleX ?? 1;
        const sy = rect.scaleY ?? 1;
        if (sx !== 1 || sy !== 1) {
            rect.set({
                width: (rect.width ?? 0) * sx,
                height: (rect.height ?? 0) * sy,
                scaleX: 1,
                scaleY: 1
            });
            needsBoundsUpdate = true;
        }
        rect.set({
            selectable: false,
            evented: false,
            strokeUniform: true
        });
    }

    // FIX: Do NOT call safeAddWithUpdate(zone) here — it invokes triggerLayout()
    // which recalculates the group bounding box from ALL children (rect + labels).
    // This shifts the group center away from the rect center, corrupting all
    // subsequent getZoneMetrics calculations that derive card positions.
    // Instead, manually sync group dimensions to match the rect.
    // ALWAYS sync (not just on needsBoundsUpdate) — after JSON deserialization the
    // group width/height may not match the rect if it was saved in a corrupt state.
    if (rect) {
        const rectW = Math.abs((rect.width ?? 0) * (rect.scaleX ?? 1));
        const rectH = Math.abs((rect.height ?? 0) * (rect.scaleY ?? 1));
        if (rectW > 0 && rectH > 0) {
            const groupW = zone.width ?? 0;
            const groupH = zone.height ?? 0;
            if (Math.abs(groupW - rectW) > 1 || Math.abs(groupH - rectH) > 1) {
                zone.set({ width: rectW, height: rectH });
                zone.dirty = true;
            }
        }
    } else if (needsBoundsUpdate) {
        zone.dirty = true;
    }
    // FIX: Permanently disable LayoutManager on zone groups (same as product cards).
    // Zone layout is fully managed by recalculateZoneLayout.
    const zoneLm = (zone as any).layoutManager;
    if (zoneLm && typeof zoneLm.performLayout === 'function' && zoneLm.performLayout.toString() !== '() => {}') {
        zoneLm.performLayout = () => {};
    }
    zone.setCoords();
}

const getZoneMetrics = (zone: any) => {
    if (!zone) return null;

    // CRITICAL FIX: Always derive zone size from the INNER RECT, not the group bounding box.
    // getBoundingRect(true) includes text labels and other non-rect children, which inflates
    // the reported zone size.  This causes cards to grow larger each save/reload cycle because
    // recalculateZoneLayout computes slotW/slotH from inflated zone dimensions.
    const rect = getZoneRect(zone);
    if (rect) {
        const rectW = Math.abs((rect.width ?? 0) * (rect.scaleX ?? 1));
        const rectH = Math.abs((rect.height ?? 0) * (rect.scaleY ?? 1));

        if (rectW > 0 && rectH > 0) {
            // FIX: Calculate the rect's ABSOLUTE center by transforming its local coords
            // through the group's transform matrix. This is more reliable than
            // zone.getCenterPoint() which returns the group's CENTER — not the rect's
            // center — and can drift when the zone group contains non-rect children
            // (e.g., text labels) that shift the group bounding box after triggerLayout().
            let rectCenterX: number | null = null;
            let rectCenterY: number | null = null;

            try {
                if (typeof zone.calcTransformMatrix === 'function' && fabric?.util?.transformPoint && fabric?.Point) {
                    const m = zone.calcTransformMatrix();
                    const localX = Number(rect.left ?? 0);
                    const localY = Number(rect.top ?? 0);
                    const p = new fabric.Point(localX, localY);
                    const abs = fabric.util.transformPoint(p, m);
                    rectCenterX = Number(abs?.x);
                    rectCenterY = Number(abs?.y);
                    if (!Number.isFinite(rectCenterX) || !Number.isFinite(rectCenterY)) {
                        rectCenterX = null;
                        rectCenterY = null;
                    }
                }
            } catch {
                rectCenterX = null;
                rectCenterY = null;
            }

            // Fallback: use zone.getCenterPoint() if transform-based calculation failed
            if (rectCenterX === null || rectCenterY === null) {
                const center = typeof zone.getCenterPoint === 'function'
                    ? zone.getCenterPoint()
                    : null;
                if (center) {
                    rectCenterX = center.x;
                    rectCenterY = center.y;
                }
            }

            if (rectCenterX !== null && rectCenterY !== null) {
                // Sync stored dims from the actual rect (not group bounds)
                zone._zoneWidth = rectW;
                zone._zoneHeight = rectH;
                const result = {
                    left: rectCenterX - (rectW / 2),
                    top: rectCenterY - (rectH / 2),
                    width: rectW,
                    height: rectH,
                    centerX: rectCenterX,
                    centerY: rectCenterY
                };
                return result;
            }

            // No center point — use rect's absolute position
            const liveBounds = zone.getBoundingRect ? zone.getBoundingRect(true) : null;
            const cx = liveBounds ? liveBounds.left + (liveBounds.width / 2) : (zone.left ?? 0);
            const cy = liveBounds ? liveBounds.top + (liveBounds.height / 2) : (zone.top ?? 0);
            zone._zoneWidth = rectW;
            zone._zoneHeight = rectH;
            return {
                left: cx - (rectW / 2),
                top: cy - (rectH / 2),
                width: rectW,
                height: rectH,
                centerX: cx,
                centerY: cy
            };
        }
    }

    // Fallback: use stored dims or group bounding rect when inner rect is unavailable
    const liveBounds = zone.getBoundingRect ? zone.getBoundingRect(true) : null;
    const liveW = liveBounds ? Math.abs(liveBounds.width) : 0;
    const liveH = liveBounds ? Math.abs(liveBounds.height) : 0;

    if (liveBounds && liveW > 0 && liveH > 0) {
        const hasStoredDims = typeof zone._zoneWidth === 'number' && zone._zoneWidth > 0 &&
                              typeof zone._zoneHeight === 'number' && zone._zoneHeight > 0;

        const useW = hasStoredDims ? zone._zoneWidth : liveW;
        const useH = hasStoredDims ? zone._zoneHeight : liveH;

        if (!hasStoredDims) {
            zone._zoneWidth = liveW;
            zone._zoneHeight = liveH;
        }

        const center = typeof zone.getCenterPoint === 'function'
            ? zone.getCenterPoint()
            : { x: liveBounds.left + liveW / 2, y: liveBounds.top + liveH / 2 };

        return {
            left: center.x - (useW / 2),
            top: center.y - (useH / 2),
            width: useW,
            height: useH,
            centerX: center.x,
            centerY: center.y
        };
    }

    // Fallback for early-load scenarios where getBoundingRect isn't ready yet
    let width = 0;
    let height = 0;

    if (typeof zone._zoneWidth === 'number' && zone._zoneWidth > 0 &&
        typeof zone._zoneHeight === 'number' && zone._zoneHeight > 0) {
        width = zone._zoneWidth;
        height = zone._zoneHeight;
    } else {
        const rect = getZoneRect(zone);
        const rectScaleX = rect?.scaleX ?? 1;
        const rectScaleY = rect?.scaleY ?? 1;
        const baseWidth = rect?.width ? rect.width * rectScaleX : zone.width;
        const baseHeight = rect?.height ? rect.height * rectScaleY : zone.height;
        const scaleX = Math.abs(zone.scaleX ?? 1);
        const scaleY = Math.abs(zone.scaleY ?? 1);
        width = baseWidth ? baseWidth * scaleX : zone.getScaledWidth?.() ?? 0;
        height = baseHeight ? baseHeight * scaleY : zone.getScaledHeight?.() ?? 0;
    }

    if (!width || !height) return null;

    const center = zone.getCenterPoint ? zone.getCenterPoint() : { x: zone.left ?? 0, y: zone.top ?? 0 };
    return {
        left: center.x - (width / 2),
        top: center.y - (height / 2),
        width,
        height,
        centerX: center.x,
        centerY: center.y
    };
}

const getResolvedZoneFrameId = (zone: any): string | undefined => {
    if (!canvas.value || !zone) return undefined;

    let frameId = String((zone as any).parentFrameId || '').trim() || undefined;
    if (frameId && !getFrameById(frameId)) {
        frameId = undefined;
    }

    if (!frameId) {
        const detected = findFrameUnderObject(zone);
        if (detected && detected._customId) {
            frameId = String(detected._customId);
        }
    }

    if ((zone as any).parentFrameId !== frameId) {
        (zone as any).parentFrameId = frameId;
        invalidateFrameRuntimeCache();
    }

    return frameId;
}

const applyCardFrameBinding = (card: any, frameId?: string) => {
    if (!card || card.excludeFromExport || card.isFrame) return;
    const isCardLike = !!(card.isSmartObject || card.isProductCard || isLikelyProductCard(card));
    if (!isCardLike) return;

    const nextFrameId = String(frameId || '').trim() || undefined;
    if ((card as any).parentFrameId !== nextFrameId) {
        (card as any).parentFrameId = nextFrameId;
        invalidateFrameRuntimeCache();
    }

    // Product cards are never clipped by frame clipPath.
    const hadClip = !!card.clipPath || !!(card as any)._frameClipOwner;
    if (card.clipPath) {
        card.set?.('clipPath', null);
    }
    if ((card as any)._frameClipOwner) {
        delete (card as any)._frameClipOwner;
    }
    if (hadClip) {
        card.set?.('dirty', true);
        card.setCoords?.();
    }
}

const syncZoneCardFrameBindings = (zone: any, cards?: any[]) => {
    if (!zone) return;
    const zoneFrameId = getResolvedZoneFrameId(zone);
    const list = Array.isArray(cards) ? cards : getZoneChildren(zone);
    list.forEach((card: any) => applyCardFrameBinding(card, zoneFrameId));
}

const getZoneChildCandidates = (zone: any) => {
    if (!canvas.value || !zone) return [];
    const topLevel = canvas.value.getObjects() || [];
    const zoneId = String((zone as any)?._customId || '').trim();
    const isCandidateGroup = (o: any) => {
        if (!o || o === zone) return false;
        // FIX: Do NOT skip invisible objects when they are explicitly bound to
        // this zone via parentZoneId.  Viewport culling sets visible=false but
        // may clear __viewportCulled during cleanup, leaving "orphan-hidden"
        // cards.  These cards must still be found so recalculateZoneLayout can
        // reposition and re-show them.
        const isBoundToThisZone = zoneId && String((o as any)?.parentZoneId || '').trim() === zoneId;
        if (o.visible === false && !isBoundToThisZone) return false;
        if ((o as any).excludeFromExport) return false;
        if ((o as any).isFrame) return false;
        if (isLikelyProductZone(o)) return false;
        if (o.type !== 'group' || typeof o.getObjects !== 'function') return false;
        // Exclude only bare price labels, not misnamed legacy product cards.
        if (isStandalonePriceGroup(o)) return false;
        return true;
    };

    const appendUnique = (target: any[], list: any[]) => {
        list.forEach((item: any) => {
            if (!item || target.includes(item)) return;
            target.push(item);
        });
    };

    const topCandidates = topLevel.filter(isCandidateGroup);

    // Legacy states can mix top-level cards with nested product cards.
    // Merge both sets instead of short-circuiting on the first top-level match.
    const deepCandidates: any[] = [];
    const seen = new Set<any>();
    const stack = [...topLevel];
    while (stack.length > 0) {
        const cur = stack.pop();
        if (!cur || seen.has(cur)) continue;
        seen.add(cur);
        if (cur.type === 'group' && typeof cur.getObjects === 'function') {
            if (isCandidateGroup(cur)) deepCandidates.push(cur);
            const children = cur.getObjects() || [];
            for (const child of children) {
                if (child?.type === 'group') stack.push(child);
            }
        }
    }

    const mergedCandidates: any[] = [];
    appendUnique(mergedCandidates, topCandidates);
    appendUnique(mergedCandidates, deepCandidates);
    return mergedCandidates;
};

const getZoneChildren = (zone: any) => {
    if (!canvas.value || !zone) return [];
    const candidates = getZoneChildCandidates(zone);

    const zoneBounds = getZoneMetrics(zone) ?? zone.getBoundingRect(true);
    const zoneFrameId = getResolvedZoneFrameId(zone);
    const zoneId = String((zone as any)?._customId || '').trim();
    const zonesByIdForFrameRepair = new Map<string, any>();
    try {
        (canvas.value.getObjects?.() || []).forEach((obj: any) => {
            if (!obj || !isLikelyProductZone(obj)) return;
            const id = String((obj as any)?._customId || '').trim();
            if (id) zonesByIdForFrameRepair.set(id, obj);
        });
    } catch {
        // best-effort repair map only
    }
    const isCardFrameCompatibleWithZone = (card: any) => {
        const cardFrameId = String((card as any)?.parentFrameId || '').trim();
        if (!zoneFrameId || !cardFrameId) return true;
        return cardFrameId === zoneFrameId;
    };
    const pointsToZoneInAnotherFrame = (zoneIdRaw: any, card: any) => {
        const otherZoneId = String(zoneIdRaw || '').trim();
        if (!otherZoneId || otherZoneId === zoneId) return false;
        const cardFrameId = String((card as any)?.parentFrameId || '').trim();
        if (!zoneFrameId || !cardFrameId || cardFrameId !== zoneFrameId) return false;
        const otherZone = zonesByIdForFrameRepair.get(otherZoneId);
        const otherFrameId = otherZone ? String(getResolvedZoneFrameId(otherZone) || (otherZone as any)?.parentFrameId || '').trim() : '';
        return !!otherFrameId && otherFrameId !== cardFrameId;
    };
    const recoveryCenterMargin = (() => {
        const pad = typeof (zone as any)._zonePadding === 'number' ? (zone as any)._zonePadding : 20;
        const base = Math.min(zoneBounds.width || 0, zoneBounds.height || 0);
        // Keep a small snap tolerance for legacy cards without stealing neighbors from adjacent zones.
        return Math.max(20, Math.min(72, pad * 0.5 + base * 0.04));
    })();

    const getZoneAssociation = (o: any) => {
        const objBounds = o.getBoundingRect();
        const center = typeof o.getCenterPoint === 'function'
            ? o.getCenterPoint()
            : { x: (o.left ?? 0), y: (o.top ?? 0) };
        const isInside =
            objBounds.left >= zoneBounds.left &&
            objBounds.top >= zoneBounds.top &&
            objBounds.left + objBounds.width <= zoneBounds.left + zoneBounds.width &&
            objBounds.top + objBounds.height <= zoneBounds.top + zoneBounds.height;
        const centerInside =
            center.x >= zoneBounds.left &&
            center.x <= (zoneBounds.left + zoneBounds.width) &&
            center.y >= zoneBounds.top &&
            center.y <= (zoneBounds.top + zoneBounds.height);
        const centerNearZone =
            center.x >= (zoneBounds.left - recoveryCenterMargin) &&
            center.x <= (zoneBounds.left + zoneBounds.width + recoveryCenterMargin) &&
            center.y >= (zoneBounds.top - recoveryCenterMargin) &&
            center.y <= (zoneBounds.top + zoneBounds.height + recoveryCenterMargin);

        const overlapLeft = Math.max(zoneBounds.left, objBounds.left);
        const overlapTop = Math.max(zoneBounds.top, objBounds.top);
        const overlapRight = Math.min(zoneBounds.left + zoneBounds.width, objBounds.left + objBounds.width);
        const overlapBottom = Math.min(zoneBounds.top + zoneBounds.height, objBounds.top + objBounds.height);
        const overlapWidth = Math.max(0, overlapRight - overlapLeft);
        const overlapHeight = Math.max(0, overlapBottom - overlapTop);
        const overlapArea = overlapWidth * overlapHeight;
        const objArea = Math.max(1, (objBounds.width || 0) * (objBounds.height || 0));
        const overlapRatio = overlapArea / objArea;

        let intersects = false;
        try {
            intersects = !!zone.intersectsWithObject(o);
        } catch {
            intersects = false;
        }

        return {
            centerInside,
            centerNearZone,
            intersects,
            isInside,
            overlapRatio
        };
    };

    const canSafelyRecoverCard = (o: any) => {
        const assoc = getZoneAssociation(o);
        if (assoc.isInside || assoc.centerInside) return true;
        if (assoc.intersects && assoc.overlapRatio >= 0.35) return true;
        return assoc.centerNearZone && assoc.overlapRatio >= 0.2;
    };

    const normalizeLegacyCard = (o: any, explicitCard: boolean) => {
        if (!explicitCard) {
            // Upgrade legacy card objects (old saves) so the rest of the engine can rely on flags.
            o.isProductCard = true;
            o.isSmartObject = true;
        }

        // Always normalize interactivity for cards (legacy and explicit cards alike).
        o.subTargetCheck = true;
        o.interactive = true;
        o.selectable = true;
        o.evented = true;

        // Ensure inner elements are selectable with controls
        if (typeof o.getObjects === 'function') {
            o.getObjects().forEach((child: any) => {
                const n = String(child?.name || '');
                const isBackground = n === 'offerBackground' || n === 'price_bg' || n === 'price_bg_image' || n === 'splash_image';
                child.selectable = !isBackground;
                child.evented = !isBackground;
                child.hasControls = !isBackground;
                child.hasBorders = !isBackground;
            });
        }
        if (typeof o.setCoords === 'function') o.setCoords();
    };

    const explicitBound: any[] = [];
    const slotBound: any[] = [];
    const legacyCandidates: any[] = [];

    const hasStrongCardSignature = (o: any) => {
        if (!o || typeof o.getObjects !== 'function') return false;
        const cw = Number((o as any)?._cardWidth);
        const ch = Number((o as any)?._cardHeight);
        if (Number.isFinite(cw) && cw > 0 && Number.isFinite(ch) && ch > 0) return true;

        const children = o.getObjects() || [];
        if (!Array.isArray(children) || children.length === 0) return false;

        const hasOfferBg = children.some((c: any) => String(c?.name || '') === 'offerBackground');
        if (hasOfferBg) return true;

        const hasPriceGroup = children.some((c: any) => String(c?.type || '').toLowerCase() === 'group' && String(c?.name || '') === 'priceGroup');
        const hasImage = children.some((c: any) => String(c?.type || '').toLowerCase() === 'image');
        return hasPriceGroup && hasImage;
    };

    candidates.forEach((o: any) => {
        const explicitCard = !!(o.isProductCard || o.isSmartObject || String(o.name || '').startsWith('product-card'));
        const likelyCard = explicitCard ? true : isLikelyProductCard(o);
        if (!likelyCard) return;

        const boundId = String((o as any)?.parentZoneId || '').trim();
        if (zoneId && boundId && boundId === zoneId) {
            if (!isCardFrameCompatibleWithZone(o)) return;
            normalizeLegacyCard(o, explicitCard);
            applyCardFrameBinding(o, zoneFrameId);
            explicitBound.push(o);
            return;
        }

        // Keep deterministic binding when slot metadata exists (important after undo/reload).
        const slotZoneId = String((o as any)?._zoneSlot?.zoneId || '').trim();
        if (zoneId && slotZoneId && slotZoneId === zoneId) {
            if (!isCardFrameCompatibleWithZone(o)) return;
            // CORRECAO A5: se boundId existe e aponta para OUTRA zona, o parentZoneId
            // e autoritativo — nao sequestrar o card aqui. Isso evita que um card
            // pertencente a Z1 apareca tambem em Z2 so porque _zoneSlot ficou stale
            // depois de um drag/undo.
            if (boundId && boundId !== zoneId) {
                return;
            }
            normalizeLegacyCard(o, explicitCard);
            o.parentZoneId = zoneId;
            applyCardFrameBinding(o, zoneFrameId);
            slotBound.push(o);
            return;
        }

        // Frame-duplicate repair: copied cards can keep parentZoneId/_zoneSlot from the
        // original zone while parentFrameId already points at the copied frame. In that
        // state, replacing products in the copied zone edits/removes the original zone.
        // If the card is physically in this zone's frame and near this zone, rebind it here.
        if (
            zoneId &&
            zoneFrameId &&
            (pointsToZoneInAnotherFrame(boundId, o) || pointsToZoneInAnotherFrame(slotZoneId, o)) &&
            canSafelyRecoverCard(o)
        ) {
            normalizeLegacyCard(o, explicitCard);
            o.parentZoneId = zoneId;
            (o as any)._zoneSlot = null;
            applyCardFrameBinding(o, zoneFrameId);
            explicitBound.push(o);
            return;
        }

        // Hard stop: a card already bound to ANOTHER zone must never be auto-captured here.
        if ((boundId && boundId !== zoneId) || (slotZoneId && slotZoneId !== zoneId)) {
            return;
        }

        legacyCandidates.push(o);
    });

    // Recover unbound but strongly-identifiable product cards that are still inside/near the zone.
    // This keeps old/corrupted layouts responsive after resize without stealing objects from other zones.
    const recoveredUnbound = legacyCandidates.filter((o: any) => {
        const boundId = String((o as any)?.parentZoneId || '').trim();
        const slotZoneId = String((o as any)?._zoneSlot?.zoneId || '').trim();
        if (boundId || slotZoneId) return false;
        if (!hasStrongCardSignature(o)) return false;
        if (!canSafelyRecoverCard(o)) return false;

        const explicitCard = !!(o.isProductCard || o.isSmartObject || String(o.name || '').startsWith('product-card'));
        normalizeLegacyCard(o, explicitCard);
        o.parentZoneId = zoneId || zone._customId;
        applyCardFrameBinding(o, zoneFrameId);
        return true;
    });

    // If the zone already has explicit bindings, keep strict mode but include recovered unbound cards.
    // This prevents false positives while fixing detached cards from legacy/buggy states.
    if (explicitBound.length > 0 || slotBound.length > 0) {
        return [...explicitBound, ...slotBound, ...recoveredUnbound];
    }

    // Legacy rescue mode: only when no explicit cards exist for the zone.
    return legacyCandidates.filter((o: any) => {
        // Legacy rescue should only capture truly unbound cards with a strong card signature.
        const boundId = String((o as any)?.parentZoneId || '').trim();
        const slotZoneId = String((o as any)?._zoneSlot?.zoneId || '').trim();
        if (boundId || slotZoneId) return false;
        if (!hasStrongCardSignature(o)) return false;
        if (!canSafelyRecoverCard(o)) return false;

        const explicitCard = !!(o.isProductCard || o.isSmartObject || String(o.name || '').startsWith('product-card'));
        normalizeLegacyCard(o, explicitCard);
        o.parentZoneId = zoneId || zone._customId;
        applyCardFrameBinding(o, zoneFrameId);
        return true;
    });
}

const moveZoneChildren = (zone: any, dx: number, dy: number, children?: any[]) => {
    if (!zone || (!dx && !dy)) return;
    const list = children && children.length > 0 ? children : getZoneChildren(zone);
    list.forEach((child: any) => {
        child.set({
            left: child.left + dx,
            top: child.top + dy
        });
        child.setCoords();
    });
}

const normalizeZoneScale = (zone: any) => {
    if (!zone || !zone.getObjects) return;
    if (zone.scaleX === 1 && zone.scaleY === 1) return;
    applyZoneScaleToRect(zone);
}

const applyZoneScaleToRect = (zone: any, minSize = 60) => {
    if (!zone || !zone.getObjects) return null;
    const zoneRect = zone.getObjects().find((o: any) => o.type === 'rect');
    if (!zoneRect) return null;

    // Normalizar rect para scale=1 antes de calcular dimensões finais.
    // Evita duplicar escala quando rect já absorveu scale de iterações anteriores.
    const rawRectW = Math.abs((zoneRect.width ?? 0) * (zoneRect.scaleX ?? 1));
    const rawRectH = Math.abs((zoneRect.height ?? 0) * (zoneRect.scaleY ?? 1));
    zoneRect.set({ width: rawRectW, height: rawRectH, scaleX: 1, scaleY: 1 });

    const zoneScaleX = Math.abs(zone.scaleX ?? 1);
    const zoneScaleY = Math.abs(zone.scaleY ?? 1);
    const nextWidth = Math.max(minSize, rawRectW * zoneScaleX);
    const nextHeight = Math.max(minSize, rawRectH * zoneScaleY);
    if (!nextWidth || !nextHeight) return null;

    // FIX: capture zone center BEFORE resetting scale, so we can detect if
    // safeAddWithUpdate shifts the group origin and compensate child cards.
    const prevLeft = zone.left ?? 0
    const prevTop = zone.top ?? 0

    zoneRect.set({
        width: nextWidth,
        height: nextHeight,
        scaleX: 1,
        scaleY: 1
    });

    // FIX: Sync group dimensions to match rect. LayoutManager is permanently
    // disabled on zones, so safeAddWithUpdate/triggerLayout won't recalculate
    // the group bounding box. We must set width/height explicitly.
    zone.set({
        width: nextWidth,
        height: nextHeight,
        scaleX: 1,
        scaleY: 1,
        flipX: false,
        flipY: false
    });

    // Não usar safeAddWithUpdate — triggerLayout recalcula bounds do grupo
    // e desloca zone.left/top, quebrando posição dos cards.
    zone.dirty = true;
    zone.setCoords();

    zone._zoneWidth = nextWidth;
    zone._zoneHeight = nextHeight;
    return { width: nextWidth, height: nextHeight };
}

/**
 * Normaliza o scale de retângulos após redimensionamento.
 * Converte scaleX/scaleY em width/height reais e preserva o border-radius proporcional.
 * Igual ao Figma: usa dimensões reais em vez de scale para evitar distorção dos cantos.
 */
const normalizeRectScale = (obj: any, minSize = 1) => {
    if (!obj) return;

    // Apenas para retângulos (rect, Rect)
    if (obj.type !== 'rect') return;

    // Se não há scale para normalizar, retorna
    if (obj.scaleX === 1 && obj.scaleY === 1) return;

    const newWidth = Math.max(minSize, Math.abs(obj.getScaledWidth?.() ?? (obj.width * obj.scaleX)));
    const newHeight = Math.max(minSize, Math.abs(obj.getScaledHeight?.() ?? (obj.height * obj.scaleY)));

    // Calcular o novo border-radius proporcional, limitado a metade da menor dimensão
    // Isso evita cantos quebrados e mantém a aparência visual consistente
    const originalRx = obj.rx || 0;
    const originalRy = obj.ry || 0;

    // Fator de escala aplicado
    const scaleFatorX = newWidth / obj.width;
    const scaleFatorY = newHeight / obj.height;

    // Novo radius proporcional (média dos fatores de escala para manter aparência)
    const newRadius = Math.min(
        (originalRx * Math.max(scaleFatorX, scaleFatorY)),
        newWidth / 2,
        newHeight / 2
    );

    obj.set({
        width: newWidth,
        height: newHeight,
        rx: newRadius,
        ry: newRadius,
        scaleX: 1,
        scaleY: 1,
        flipX: false,
        flipY: false
    });

    obj.setCoords();
    return { width: newWidth, height: newHeight, rx: newRadius, ry: newRadius };
};

/**
 * Normaliza o scale de grupos que contêm retângulos com border-radius.
 * Percorre todos os objetos dentro do grupo e normaliza os retângulos.
 */
const normalizeGroupRects = (group: any) => {
    if (!group || !group.getObjects || group.type !== 'group') return;

    const objects = group.getObjects();
    if (!Array.isArray(objects)) return;

    objects.forEach((obj: any) => {
        if (obj.type === 'rect') {
            normalizeRectScale(obj);
        } else if (obj.type === 'group') {
            // Recursivo para grupos aninhados
            normalizeGroupRects(obj);
        }
    });
};

const stableHash32 = (s: string): number => {
    // FNV-1a 32-bit hash (stable across sessions).
    let h = 0x811c9dc5;
    for (let i = 0; i < s.length; i++) {
        h ^= s.charCodeAt(i);
        h = Math.imul(h, 0x01000193);
    }
    return h >>> 0;
};

const getZoneHighlightPredicate = (zone: any, cards: any[]) => {
    const count = Array.isArray(cards) ? cards.length : 0;
    const rawCount = Number((zone as any)?.highlightCount ?? 0);
    const want = Math.max(0, Math.min(count, Math.round(Number.isFinite(rawCount) ? rawCount : 0)));
    const rawMult = Number((zone as any)?.highlightHeight ?? 1);
    const mult = Math.max(1, Math.min(4, Number.isFinite(rawMult) ? rawMult : 1));
    const pos = String((zone as any)?.highlightPos ?? 'first').toLowerCase();

    if (!want || mult <= 1) {
        return { count: 0, mult: 1, isHighlighted: (_card: any, _index: number) => false };
    }

    // Random = stable per-zone/per-card identity (does NOT reshuffle every relayout).
    if (pos === 'random') {
        const zoneId = String((zone as any)?._customId ?? 'zone');
        const scored = cards.map((c: any, idx: number) => {
            const id = String(c?._customId ?? c?.id ?? idx);
            return { id, score: stableHash32(`${zoneId}:${id}`) };
        });
        scored.sort((a, b) => a.score - b.score);
        const picked = scored.slice(0, want);
        const idSet = new Set<string>(picked.map(p => p.id));
        return {
            count: want,
            mult,
            isHighlighted: (card: any, index: number) => idSet.has(String(card?._customId ?? card?.id ?? index))
        };
    }

    if (pos === 'center') {
        const start = Math.max(0, Math.floor((count - want) / 2));
        const end = Math.min(count, start + want);
        return {
            count: want,
            mult,
            isHighlighted: (_card: any, index: number) => index >= start && index < end
        };
    }

    if (pos === 'last' || pos === 'bottom') {
        return {
            count: want,
            mult,
            isHighlighted: (_card: any, index: number) => index >= (count - want)
        };
    }

    // Default = first/top
    return {
        count: want,
        mult,
        isHighlighted: (_card: any, index: number) => index < want
    };
};

type RecalculateZoneLayoutOptions = {
    save?: boolean;
    requestRender?: boolean;
    trustCachedChildren?: boolean;
    /** @deprecated No longer used — resizeSmartObject always runs to fix Fabric v7 group center shifts */
    preserveCardInternals?: boolean;
    /** When true, only reposition cards (set left/top) without calling resizeSmartObject.
     *  Used on rehydrate to preserve card internal layout (text sizes, positions) from JSON. */
    skipResize?: boolean;
    /** When true, resize cards proportionally but do NOT re-apply zone global styles
     *  (colors, fonts, borders). Used on zone move/resize to preserve existing card styling. */
    preserveStyles?: boolean;
};

const recalculateZoneLayout = (zone: any, cachedChildren?: any[], opts: RecalculateZoneLayoutOptions = {}) => {
    if (!zone || !canvas.value) return;
    const shouldSave = opts.save !== false;
    const shouldRender = opts.requestRender !== false;
    const cachedList = Array.isArray(cachedChildren) ? cachedChildren.filter(Boolean) : [];
    
    // 1. Find cards in zone (Use cache if available for performance)
    const canvasObjects = canvas.value ? new Set(canvas.value.getObjects()) : null;
    const zoneIdForCachedChildren = String((zone as any)?._customId || '').trim();
    const canTrustCachedChildren = cachedList.length > 0 && cachedList.every((card: any) => {
        if (!card) return false;
        if (canvasObjects && !canvasObjects.has(card)) return false;
        const parentZoneId = String((card as any)?.parentZoneId || '').trim();
        const slotZoneId = String((card as any)?._zoneSlot?.zoneId || '').trim();
        return !!zoneIdForCachedChildren && (parentZoneId === zoneIdForCachedChildren || slotZoneId === zoneIdForCachedChildren);
    });
    const cardMap = new Map<any, any>();
    cachedList.forEach((card: any) => {
        // Ignore cached cards that were removed from canvas (stale cache)
        if (canvasObjects && !canvasObjects.has(card)) return;
        const key = card._customId ?? card.id ?? card;
        cardMap.set(key, card);
    });

    if ((!opts.trustCachedChildren && !canTrustCachedChildren) || cachedList.length === 0) {
        getZoneChildren(zone).forEach((card: any) => {
            const key = card._customId ?? card.id ?? card;
            cardMap.set(key, card);
        });
    }
    
    let cards = Array.from(cardMap.values());
    
    if (cards.length === 0) return;
    
    // 2. Sort by stable zone order when available, otherwise fall back to visual order.
    const hasAllOrders = cards.every((c: any) => Number.isFinite((c as any)._zoneOrder));
    if (hasAllOrders) {
        cards.sort((a: any, b: any) => ((a as any)._zoneOrder ?? 0) - ((b as any)._zoneOrder ?? 0));
    } else {
        cards.sort((a: any, b: any) => {
            const rowDiff = (a.top ?? 0) - (b.top ?? 0);
            if (Math.abs(rowDiff) > 50) return rowDiff; // Same row tolerance
            return (a.left ?? 0) - (b.left ?? 0);
        });
        cards.forEach((c: any, i: number) => ((c as any)._zoneOrder = i));
    }
    
    // 3. Setup Grid Vars
    const zoneRect = getZoneMetrics(zone) ?? zone.getBoundingRect(true);
    const clamp = (n: number, min: number, max: number) => Math.min(max, Math.max(min, n));
    const minSlotSize = 12;

    const rawPadding = Math.max(0, Number(typeof zone._zonePadding === 'number' ? zone._zonePadding : (zone.padding ?? 20)) || 0);
    const rawGapX = Math.max(0, Number(zone.gapHorizontal ?? rawPadding) || 0);
    const rawGapY = Math.max(0, Number(zone.gapVertical ?? rawPadding) || 0);
    // Default to `fill` so the grid always uses the full zone width (no empty space).
    const lastRowBehavior = zone.lastRowBehavior || 'fill'; 
    const layoutDirection = zone.layoutDirection || 'horizontal';
    const stylesToApply: Partial<GlobalStyles> = getZoneGlobalStyles(zone);
    const zoneFrameId = getResolvedZoneFrameId(zone);
    
    const count = cards.length;
    
    const zoneConfig: ProductZone = {
        x: zoneRect.left,
        y: zoneRect.top,
        width: zoneRect.width,
        height: zoneRect.height,
        padding: rawPadding,
        gapHorizontal: rawGapX,
        gapVertical: rawGapY,
        columns: typeof zone.columns === 'number' ? zone.columns : 0,
        rows: typeof zone.rows === 'number' ? zone.rows : 0,
        cardAspectRatio: zone.cardAspectRatio ?? 'fill',
        lastRowBehavior: lastRowBehavior
    };
    
    const { cols: computedCols, rows: computedRows } = calculateGridLayout(zoneConfig, count);
    const cols = Math.max(1, Math.round(Number(computedCols) || 1));
    const rows = Math.max(1, Math.round(Number(computedRows) || 1));
    const effectiveRows = Math.max(rows, Math.ceil(count / cols));

    // Fit spacing to available area so cards never overflow the product zone.
    const fitSpacing = (colCount: number, rowCount: number) => {
        let padding = rawPadding;
        let gapX = rawGapX;
        let gapY = rawGapY;

        if (colCount > 1) {
            const maxGapForMinWidth = (zoneRect.width - (padding * 2) - (colCount * minSlotSize)) / (colCount - 1);
            gapX = clamp(gapX, 0, Math.max(0, maxGapForMinWidth));
        }
        if (rowCount > 1) {
            const maxGapForMinHeight = (zoneRect.height - (padding * 2) - (rowCount * minSlotSize)) / (rowCount - 1);
            gapY = clamp(gapY, 0, Math.max(0, maxGapForMinHeight));
        }

        const maxPadByWidth = (zoneRect.width - (colCount * minSlotSize) - ((colCount - 1) * gapX)) / 2;
        const maxPadByHeight = (zoneRect.height - (rowCount * minSlotSize) - ((rowCount - 1) * gapY)) / 2;
        const padLimit = Math.max(0, Math.min(maxPadByWidth, maxPadByHeight));
        padding = clamp(padding, 0, padLimit);

        const usableW = Math.max(2, zoneRect.width - (padding * 2));
        const usableH = Math.max(2, zoneRect.height - (padding * 2));

        if (colCount > 1) {
            const maxGapByUsableWidth = (usableW - (colCount * minSlotSize)) / (colCount - 1);
            gapX = clamp(gapX, 0, Math.max(0, maxGapByUsableWidth));
        }
        if (rowCount > 1) {
            const maxGapByUsableHeight = (usableH - (rowCount * minSlotSize)) / (rowCount - 1);
            gapY = clamp(gapY, 0, Math.max(0, maxGapByUsableHeight));
        }

        const MIN_GAP = 2;
        const MIN_PAD = 2;
        return {
            padding: Math.max(MIN_PAD, padding),
            gapX: Math.max(MIN_GAP, gapX),
            gapY: Math.max(MIN_GAP, gapY),
            usableW,
            usableH,
            startX: zoneRect.left + Math.max(MIN_PAD, padding),
            startY: zoneRect.top + Math.max(MIN_PAD, padding)
        };
    };

    const spacing = fitSpacing(cols, effectiveRows);
    const padding = spacing.padding;
    const gapX = spacing.gapX;
    const gapY = spacing.gapY;
    const usableW = spacing.usableW;
    const usableH = spacing.usableH;
    
    // 4. Layout Execution
    const startX = spacing.startX;
    const startY = spacing.startY;
    const maxSlotX = zoneRect.left + zoneRect.width - padding;
    const maxSlotY = zoneRect.top + zoneRect.height - padding;

    // Compute standard (non-highlight) cell dimensions as reference so that
    // price tags, Y offsets and label sizing are uniform across all cards
    // — including highlight (featured) cards that get larger slots.
    const _refCellW = (usableW - (cols - 1) * gapX) / Math.max(1, cols);
    const _refCellH = (usableH - (effectiveRows - 1) * gapY) / Math.max(1, effectiveRows);
    if (Number.isFinite(_refCellW) && _refCellW > 2 && Number.isFinite(_refCellH) && _refCellH > 2) {
        (stylesToApply as any).__refCellW = _refCellW;
        (stylesToApply as any).__refCellH = _refCellH;
    }

    // Helper: resize & position a single card in its slot
    const placeCard = (card: any, x: number, y: number, w: number, h: number, order: number) => {
        const slotW = Math.max(2, w);
        const slotH = Math.max(2, h);
        const boundedX = clamp(x, startX, Math.max(startX, maxSlotX - slotW));
        const boundedY = clamp(y, startY, Math.max(startY, maxSlotY - slotH));
        // FIX: Restore visibility for cards that were hidden by viewport culling.
        // Viewport culling can set visible=false and then clear __viewportCulled,
        // leaving cards permanently hidden.  Since we're actively placing this card
        // in a layout slot, it must be visible.
        if (card.visible === false) {
            card.set('visible', true);
            card.visible = true;
            card.dirty = true;
            delete (card as any).__viewportCulled;
            delete (card as any).__viewportCullPrevVisible;
        }
        card.parentZoneId = zone._customId;
        applyCardFrameBinding(card, zoneFrameId);
        card._zoneOrder = order;
        (card as any)._zoneSlot = { zoneId: zone._customId, left: boundedX, top: boundedY, width: slotW, height: slotH };
        const cx = boundedX + slotW / 2;
        const cy = boundedY + slotH / 2;
        // Ensure LayoutManager is disabled on card groups (resizeSmartObject also does this)
        const pcLm = (card as any).layoutManager;
        if (pcLm && pcLm.performLayout) pcLm.performLayout = () => {};

        if (card.isSmartObject || card.name?.startsWith('product-card')) {
            if (opts.skipResize) {
                // skipResize: preserve card internal layout from JSON.
                // Only reposition — don't touch children or saved dimensions.
                // CRITICAL FIX: If card already has valid saved dimensions, preserve them.
                // Overwriting with slot dimensions causes proportional mismatch because
                // internal elements (text, images, prices) keep their old positions/sizes.
                // Slot dimensions may differ from saved due to zone metric rounding after
                // normalizeZoneScale / ensureZoneSanity.
                const savedW = Number((card as any)._cardWidth) || Number(card.width) || 0;
                const savedH = Number((card as any)._cardHeight) || Number(card.height) || 0;
                // Guard against corrupted saved dimensions (e.g. 3000px from old bugs)
                const dimsLookValid = savedW > 0 && savedH > 0 &&
                    savedW <= Math.max(slotW * 3, 3000) &&
                    savedH <= Math.max(slotH * 3, 3000) &&
                    savedW >= slotW * 0.1 &&
                    savedH >= slotH * 0.1;
                if (dimsLookValid) {
                    card.set({ width: savedW, height: savedH });
                    (card as any)._cardWidth = savedW;
                    (card as any)._cardHeight = savedH;
                } else {
                    card.set({ width: slotW, height: slotH });
                    (card as any)._cardWidth = slotW;
                    (card as any)._cardHeight = slotH;
                }
            } else if (opts.preserveStyles) {
                // preserveStyles: resize card proportionally but don't re-apply zone styles.
                // If card dimensions haven't changed, skip resize entirely to preserve template layout.
                const prevW = Number((card as any)._cardWidth) || card.width || 0;
                const prevH = Number((card as any)._cardHeight) || card.height || 0;
                const dimChanged = Math.abs(prevW - slotW) > 1 || Math.abs(prevH - slotH) > 1;
                if (dimChanged) {
                    try {
                        // CORRECAO A8: passar stylesToApply ao resize mesmo com preserveStyles=true.
                        // Antes passavamos undefined, o que zerava title/splash/image scales para
                        // defaults — contradizendo a intencao de "preservar" o template visual.
                        // O resizeSmartObject reaplica estilos internos mas sem tocar em zone
                        // globals que ja estao no proprio card.
                        resizeSmartObject(card, slotW, slotH, stylesToApply);
                    } catch (resizeErr) {
                        console.warn('[placeCard] resizeSmartObject (preserveStyles) failed:', resizeErr);
                    }
                } else {
                    // Do not call card.set({ width, height }) here. In Fabric v7, even a
                    // near-identical width/height assignment can shift a group's internal
                    // coordinate system and move children such as priceGroup labels.
                    (card as any)._cardWidth = prevW || slotW;
                    (card as any)._cardHeight = prevH || slotH;
                }
            } else {
                try {
                    resizeSmartObject(card, slotW, slotH, stylesToApply);
                } catch (resizeErr) {
                    console.warn('[placeCard] resizeSmartObject failed, positioning card at slot:', resizeErr);
                }
            }
            card.set({ left: cx, top: cy, originX: 'center', originY: 'center', scaleX: 1, scaleY: 1 });
        } else {
            card.set({ left: cx, top: cy, originX: 'center', originY: 'center', scaleX: slotW / (card.width || 1), scaleY: slotH / (card.height || 1) });
        }
        card.setCoords();
    };

    // Highlight detection
    const hl = getZoneHighlightPredicate(zone, cards);

    if (hl.count > 0 && hl.mult > 1) {
        // ══════════════ FEATURED LAYOUT ══════════════
        // Highlighted cards get their own COLUMN SECTION (spanning full height).
        // Normal cards fill the remaining width as a sub-grid.
        const hlCards: any[] = [];
        const normCards: any[] = [];
        cards.forEach((card, i) => {
            if (hl.isHighlighted(card, i)) hlCards.push(card);
            else normCards.push(card);
        });

        // Edge case: all cards highlighted → fall through to standard grid
        if (normCards.length > 0) {
            const rawHighlightPos = String((zone as any)?.highlightPos ?? 'first').toLowerCase();
            const useHorizontalFeatured =
                rawHighlightPos === 'top' ||
                rawHighlightPos === 'bottom' ||
                rawHighlightPos === 'center';

            if (useHorizontalFeatured) {
                const normalCols = Math.max(1, (zone.columns && zone.columns > 0)
                    ? cols
                    : Math.max(1, Math.round(Math.sqrt(normCards.length * (usableW / Math.max(1, usableH)))))
                );

                const normRowCount = Math.max(1, Math.ceil(normCards.length / normalCols));
                // Gaps já são descontados em normSectionH e normCardH; não pré-descontar para evitar contagem dupla
                const totalGapsY = 0;
                const totalUnitsY = normRowCount + hl.mult;
                const unitH = (usableH - totalGapsY) / Math.max(1, totalUnitsY);

                if (Number.isFinite(unitH) && unitH > 2) {
                    const hlSectionH = unitH * hl.mult;
                    const normSectionH = usableH - hlSectionH - gapY;
                    const normCardH = (normSectionH - (Math.max(0, normRowCount - 1) * gapY)) / Math.max(1, normRowCount);
                    const baseNormCellW = (usableW - ((normalCols - 1) * gapX)) / Math.max(1, normalCols);

                    const highlightCols = Math.max(1, Math.min(cols, hlCards.length));
                    const highlightRows = Math.max(1, Math.ceil(hlCards.length / highlightCols));
                    const highlightCellW = (usableW - ((highlightCols - 1) * gapX)) / Math.max(1, highlightCols);
                    const highlightCellH = (hlSectionH - (Math.max(0, highlightRows - 1) * gapY)) / Math.max(1, highlightRows);

                    const canApplyHorizontalFeatured =
                        normSectionH > 2 &&
                        normCardH > 2 &&
                        baseNormCellW > 2 &&
                        highlightCellW > 2 &&
                        highlightCellH > 2;

                    if (canApplyHorizontalFeatured) {
                        const placeAtBottom = rawHighlightPos === 'bottom';
                        const centerHighlightRows = rawHighlightPos === 'center';

                        const hlSectionY = placeAtBottom
                            ? (startY + usableH - hlSectionH)
                            : startY;
                        const normSectionY = placeAtBottom
                            ? startY
                            : (hlSectionY + hlSectionH + gapY);

                        hlCards.forEach((card: any, i: number) => {
                            const row = Math.floor(i / highlightCols);
                            const col = i % highlightCols;
                            const isLastRow = row === highlightRows - 1;
                            const itemsInRow = isLastRow ? (hlCards.length % highlightCols || highlightCols) : highlightCols;
                            const rowW = (itemsInRow * highlightCellW) + ((itemsInRow - 1) * gapX);
                            const rowStartX = centerHighlightRows
                                ? (startX + (usableW - rowW) / 2)
                                : startX;
                            const x = rowStartX + (col * (highlightCellW + gapX));
                            const y = hlSectionY + (row * (highlightCellH + gapY));
                            placeCard(card, x, y, highlightCellW, highlightCellH, cards.indexOf(card));
                        });

                        normCards.forEach((card: any, i: number) => {
                            const col = i % normalCols;
                            const row = Math.floor(i / normalCols);
                            const isLastRow = row === normRowCount - 1;
                            const itemsInRow = isLastRow ? (normCards.length % normalCols || normalCols) : normalCols;

                            let cellW = baseNormCellW;
                            let rowGapX = gapX;
                            let rowStartX = startX;

                            if (isLastRow && itemsInRow < normalCols) {
                                if ((lastRowBehavior === 'fill' || lastRowBehavior === 'stretch') && itemsInRow > 1) {
                                    cellW = (usableW - ((itemsInRow - 1) * gapX)) / Math.max(1, itemsInRow);
                                    rowGapX = gapX;
                                    rowStartX = startX;
                                } else {
                                    const rowW = (itemsInRow * cellW) + ((itemsInRow - 1) * rowGapX);
                                    if (lastRowBehavior === 'center' || (itemsInRow === 1 && (lastRowBehavior === 'fill' || lastRowBehavior === 'stretch'))) {
                                        rowStartX = startX + (usableW - rowW) / 2;
                                    }
                                    else if (lastRowBehavior === 'left') rowStartX = startX;
                                }
                            }

                            const x = rowStartX + (col * (cellW + rowGapX));
                            const y = normSectionY + (row * (normCardH + gapY));
                            placeCard(card, x, y, cellW, normCardH, cards.indexOf(card));
                        });

                        if (shouldRender) safeRequestRenderAll();
                        if (shouldSave) saveCurrentState();
                        return;
                    }
                }
            }

            const hlOnLeft = rawHighlightPos !== 'last';

            // Column distribution for normal section
            const normalCols = Math.max(1, (zone.columns && zone.columns > 0)
                ? cols - 1
                : Math.max(1, Math.round(Math.sqrt(normCards.length * (usableW / Math.max(1, usableH)))))
            );

            // Width: highlight section = hl.mult units, normal cols = 1 unit each
            // Total gaps: 1 between hl and normal + (normalCols - 1) between normal cols = normalCols gaps
            const totalGapsX = normalCols * gapX;
            const totalUnits = normalCols + hl.mult;
            const unitW = (usableW - totalGapsX) / Math.max(1, totalUnits);

            if (Number.isFinite(unitW) && unitW > 2) {
                const hlW = unitW * hl.mult;
                const normSectionW = usableW - hlW - gapX;

                // Heights (each section fills full height independently)
                const hlRowCount = hlCards.length;
                const hlGapH = Math.max(0, hlRowCount - 1) * gapY;
                const hlCardH = (usableH - hlGapH) / Math.max(1, hlRowCount);

                const normRowCount = Math.max(1, Math.ceil(normCards.length / normalCols));
                const normGapH = Math.max(0, normRowCount - 1) * gapY;
                const normCardH = (usableH - normGapH) / normRowCount;
                const baseNormCellW = (normSectionW - ((normalCols - 1) * gapX)) / Math.max(1, normalCols);

                const canApplyFeatured =
                    normSectionW > 2 &&
                    hlCardH > 2 &&
                    normCardH > 2 &&
                    baseNormCellW > 2;

                if (canApplyFeatured) {
                    // Position highlight cards (full-height column section)
                    const hlSectionX = hlOnLeft ? startX : (startX + usableW - hlW);
                    hlCards.forEach((card: any, i: number) => {
                        const y = startY + i * (hlCardH + gapY);
                        placeCard(card, hlSectionX, y, hlW, hlCardH, cards.indexOf(card));
                    });

                    // Position normal cards in sub-grid
                    const normSectionX = hlOnLeft ? (startX + hlW + gapX) : startX;

                    normCards.forEach((card: any, i: number) => {
                        const col = i % normalCols;
                        const row = Math.floor(i / normalCols);

                        // Last row fill
                        const isLastRow = row === normRowCount - 1;
                        const itemsInRow = isLastRow ? (normCards.length % normalCols || normalCols) : normalCols;
                        // Match standard grid semantics:
                        // - fill: keep card size, expand gaps (but clamp to avoid huge "holes" on sparse last rows)
                        // - stretch: stretch cards
                        // - center: keep card size, center row
                        let cellW = baseNormCellW;
                        let rowGapX = gapX;
                        let rowStartX = normSectionX;
                        if (isLastRow && itemsInRow < normalCols) {
                            if ((lastRowBehavior === 'fill' || lastRowBehavior === 'stretch') && itemsInRow > 1) {
                                // "fill" in sparse last rows: prefer stretching cards instead of exploding gaps.
                                cellW = (normSectionW - ((itemsInRow - 1) * gapX)) / Math.max(1, itemsInRow);
                                rowGapX = gapX;
                                rowStartX = normSectionX;
                            }
                            const rowW = (itemsInRow * cellW) + ((itemsInRow - 1) * rowGapX);
                            const shouldCenter =
                                lastRowBehavior === 'center' ||
                                (itemsInRow === 1 && (lastRowBehavior === 'fill' || lastRowBehavior === 'stretch'));
                            if (shouldCenter) {
                                rowStartX = normSectionX + (normSectionW - rowW) / 2;
                            } else if (lastRowBehavior === 'left') {
                                rowStartX = normSectionX;
                            }
                        }

                        let x = rowStartX + col * (cellW + rowGapX);

                        const y = startY + row * (normCardH + gapY);
                        placeCard(card, x, y, cellW, normCardH, cards.indexOf(card));
                    });

                    if (shouldRender) safeRequestRenderAll();
                    if (shouldSave) saveCurrentState();
                    return;
                }
            }
        }
    }

    // ══════════════ STANDARD GRID LAYOUT ══════════════
    // For vertical layout, compute the effective number of columns used (otherwise we can
    // end up with "empty columns" to the right when count < cols * rows).
    const gridCols = layoutDirection === 'vertical'
        ? Math.max(1, Math.ceil(count / Math.max(1, effectiveRows)))
        : cols;

    const totalGapW = (gridCols - 1) * gapX;
    const totalGapH = (effectiveRows - 1) * gapY;
    const slotW = (usableW - totalGapW) / gridCols;
    const slotH = (usableH - totalGapH) / effectiveRows;

    // Aplicar cardAspectRatio para obter dimensões reais do card.
    let itemW = slotW;
    let itemH = slotH;
    const aspectRatioStr = zone.cardAspectRatio as string | undefined;
    const hasAspectConstraint = !!aspectRatioStr && aspectRatioStr !== 'auto' && aspectRatioStr !== 'fill';
    if (hasAspectConstraint) {
        const arVal = getAspectRatioValue(aspectRatioStr!);
        if (arVal && arVal > 0) {
            const hFromRatio = itemW / arVal;
            if (hFromRatio <= itemH) {
                itemH = hFromRatio;
            } else {
                itemW = itemH * arVal;
            }
        }
    }

    // Aplicar verticalAlign — posicionar o grid quando há espaço vertical sobrando.
    const vAlign = String((zone as any).verticalAlign || 'stretch').toLowerCase();
    let gridStartY = startY;
    let gridGapY = gapY;

    if (hasAspectConstraint && itemH < slotH) {
        const totalGridH = (effectiveRows * itemH) + ((effectiveRows - 1) * gapY);
        const excessH = usableH - totalGridH;
        if (excessH > 1) {
            if (vAlign === 'center') {
                gridStartY = startY + excessH / 2;
            } else if (vAlign === 'bottom') {
                gridStartY = startY + excessH;
            } else if (vAlign === 'stretch') {
                // Distribuir espaço extra entre as linhas.
                if (effectiveRows > 1) {
                    gridGapY = gapY + excessH / (effectiveRows - 1);
                } else {
                    gridStartY = startY + excessH / 2;
                }
            }
            // 'top': keep gridStartY as-is.
        }
    }

    // Centralizar horizontalmente quando aspect ratio restringe a largura.
    let gridStartX = startX;
    let gridGapX = gapX;

    if (hasAspectConstraint && itemW < slotW) {
        const totalGridW = (gridCols * itemW) + ((gridCols - 1) * gapX);
        const excessW = usableW - totalGridW;
        if (excessW > 1) {
            if (gridCols > 1) {
                gridGapX = gapX + excessW / (gridCols - 1);
            } else {
                gridStartX = startX + excessW / 2;
            }
        }
    }

    if (!Number.isFinite(itemW) || !Number.isFinite(itemH) || itemW <= 0 || itemH <= 0) {
        return;
    }

    cards.forEach((card: any, index: number) => {
      try {
        const col = layoutDirection === 'vertical'
            ? Math.floor(index / Math.max(1, effectiveRows))
            : (index % cols);
        const row = layoutDirection === 'vertical'
            ? (index % Math.max(1, effectiveRows))
            : Math.floor(index / cols);

        // Vertical flow: last column can be incomplete (itemsInCol < effectiveRows)
        // Horizontal flow: last row can be incomplete (itemsInRow < cols)
        const isLastRow = layoutDirection !== 'vertical' && row === effectiveRows - 1;
        const itemsInRow = isLastRow ? (count % cols || cols) : cols;
        const isLastCol = layoutDirection === 'vertical' && col === (gridCols - 1);
        const itemsInCol = isLastCol ? (count % effectiveRows || effectiveRows) : effectiveRows;

        // Handle vertical "last column" alignment/fill (analogous to last-row behavior).
        if (layoutDirection === 'vertical' && isLastCol && itemsInCol < effectiveRows) {
            let colItemH = itemH;
            let colGapY = gridGapY;
            let colStartY = gridStartY;

            if ((lastRowBehavior === 'fill' || lastRowBehavior === 'stretch') && itemsInCol >= 1) {
                // Fill the full height by stretching items (gaps stay consistent).
                colItemH = (usableH - ((itemsInCol - 1) * gapY)) / Math.max(1, itemsInCol);
                colGapY = gapY;
                colStartY = startY;
            } else if (lastRowBehavior === 'center') {
                const colH = (itemsInCol * colItemH) + ((itemsInCol - 1) * colGapY);
                colStartY = startY + (usableH - colH) / 2;
            } else if (lastRowBehavior === 'left') {
                // Treat "left" as "top" for vertical flow.
                colStartY = gridStartY;
            }

            let x = gridStartX + (col * (itemW + gridGapX));
            let y = colStartY + (row * (colItemH + colGapY));

            x = clamp(x, startX, Math.max(startX, maxSlotX - itemW));
            y = clamp(y, startY, Math.max(startY, maxSlotY - colItemH));
            placeCard(card, x, y, itemW, colItemH, index);
            return;
        }

        // Last row handling:
        // - center: keep card size, center the row
        // - fill: keep card size, expand gaps to occupy full width (preserves label/card proportions)
        // - stretch: stretch card width to occupy full width
        // - left: keep card size, align left
        let rowItemW = itemW;
        let rowGapX = gridGapX;
        let rowStartX = gridStartX;

        if (isLastRow && itemsInRow < cols) {
            if ((lastRowBehavior === 'fill' || lastRowBehavior === 'stretch') && itemsInRow > 1) {
                // Prefer stretching cards (consistent gap) instead of creating huge gaps between items.
                rowItemW = (usableW - ((itemsInRow - 1) * gapX)) / Math.max(1, itemsInRow);
                rowGapX = gapX;
                rowStartX = startX;
            } else {
                const rowW = (itemsInRow * rowItemW) + ((itemsInRow - 1) * rowGapX);
                const shouldCenter =
                    lastRowBehavior === 'center' ||
                    (itemsInRow === 1 && (lastRowBehavior === 'fill' || lastRowBehavior === 'stretch'));
                if (shouldCenter) rowStartX = startX + (usableW - rowW) / 2;
                else if (lastRowBehavior === 'left') rowStartX = gridStartX;
            }
        }

        let x = rowStartX + (col * (rowItemW + rowGapX));
        let y = gridStartY + (row * (itemH + gridGapY));

        x = clamp(x, startX, Math.max(startX, maxSlotX - rowItemW));
        y = clamp(y, startY, Math.max(startY, maxSlotY - itemH));
        placeCard(card, x, y, rowItemW, itemH, index);
      } catch (err) {
        console.warn(`[recalculateZoneLayout] Failed to place card ${index}:`, err);
      }
    });

    if (shouldRender) safeRequestRenderAll();
    if (shouldSave) saveCurrentState();
}

const rehydrateCanvasZones = (
    opts: {
        relayout?: boolean;
        applyZoneStyles?: boolean;
        legacyImageRepairMode?: 'auto' | 'force' | 'skip';
    } = {}
) => {
    if (!canvas.value) return;
    const relayout = opts.relayout !== false;
    const applyZoneStyles = opts.applyZoneStyles !== false;
    const legacyImageRepairMode = opts.legacyImageRepairMode || 'auto';

    const prevHistory = isHistoryProcessing.value;
    isHistoryProcessing.value = true;
    try {
        let objs = canvas.value.getObjects();

        // Ensure IDs exist (used for parentZoneId mapping and selection)
        objs.forEach((o: any) => {
            if (!o._customId) o._customId = makeId();
        });

        // CRITICAL: Clear clipPath from all product zones to prevent rendering errors
        // Product zones should not have clipPath as cards are added separately to canvas
        objs.forEach((o: any) => {
            if (isMisnamedProductCardGroup(o)) {
                const currentLayerName = String((o as any)?.layerName || '').trim();
                const repairedName = currentLayerName && currentLayerName !== 'priceGroup'
                    ? currentLayerName
                    : 'product-card';
                o.name = repairedName;
                if (!currentLayerName || currentLayerName === 'priceGroup') {
                    (o as any).layerName = repairedName;
                }
            }
            if (o.clipPath && (o.isGridZone || o.isProductZone || o.name === 'gridZone' || o.name === 'productZoneContainer')) {
                o.clipPath = null;
            }
            // CRITICAL: Ensure all remaining clipPaths have _objects initialized
            // This prevents "forEach of undefined" errors in fabric.js createClipPathLayer
            if (o.clipPath && o.clipPath._objects === undefined) {
                o.clipPath._objects = [];
            }

            // CRITICAL: Normalize product cards to Canva-like behavior:
            // - Default: select/move the whole card (subTargetCheck OFF)
            // - Double click: enable deep select for inner elements (handled elsewhere)
            // Also supports legacy projects where flags were not serialized yet (heuristic-based detection).
            // Only normalize objects that are explicitly tagged as product cards OR have
            // strong internal signals (offerBackground, priceGroup, _cardWidth).
            // This prevents generic groups from being mutated by rehydration heuristics.
            const hasStrongCardSignals = (obj: any) => {
                if (obj.isProductCard || obj.isSmartObject) return true;
                const children = typeof obj.getObjects === 'function' ? obj.getObjects() : [];
                const hasOfferBg = children.some((c: any) => String(c?.name || '') === 'offerBackground');
                const hasPriceGroup = children.some((c: any) => String(c?.type || '').toLowerCase() === 'group' && String(c?.name || '') === 'priceGroup');
                const hasCardDims = Number.isFinite(Number((obj as any)?._cardWidth)) && Number((obj as any)?._cardWidth) > 0;
                return hasOfferBg || hasPriceGroup || hasCardDims;
            };
            const isCardLike =
                (o.isProductCard || o.isSmartObject || isLikelyProductCard(o)) &&
                o.type === 'group' &&
                !isLikelyPriceGroupObject(o) &&
                hasStrongCardSignals(o);
            if (isCardLike) {
                if (!o.isProductCard && !o.isSmartObject && isLikelyProductCard(o)) {
                    o.isProductCard = true;
                    o.isSmartObject = true;
                }

                // Normalize origin to center for stable containment math.
                try {
                    const cp = typeof o.getCenterPoint === 'function'
                        ? o.getCenterPoint()
                        : { x: (o.left ?? 0), y: (o.top ?? 0) };
                    if (o.originX !== 'center' || o.originY !== 'center') {
                        o.set({ originX: 'center', originY: 'center', left: cp.x, top: cp.y });
                    }
                } catch (e) {
                    // ignore
                }
                // Single-click deep select: user can click directly on inner elements.
                if (o.subTargetCheck !== true) o.subTargetCheck = true;
                if (o.interactive !== true) o.interactive = true;
                if (o.selectable !== true) o.selectable = true;
                if (o.evented !== true) o.evented = true;
                // Ensure internal elements are selectable with controls
                if (typeof o.getObjects === 'function') {
                    o.getObjects().forEach((child: any) => {
                        const childName = String(child?.name || '');
                        const isBackground = childName === 'offerBackground'
                            || childName === 'price_bg'
                            || childName === 'price_bg_image'
                            || childName === 'splash_image';
                        child.selectable = !isBackground;
                        child.evented = !isBackground;
                        child.hasControls = !isBackground;
                        child.hasBorders = !isBackground;
                    });
                }
            }
        });

        // Re-apply custom rendering patches (e.g. per-corner rounded rects) recursively.
        const patchTree = (o: any) => {
            if (!o) return;
            if (isRectObject(o) && o.cornerRadii) applyRectCornerRadiiPatch(o);
            // Re-apply sticker outline patch for images loaded from JSON
            if (String(o.type || '').toLowerCase() === 'image' && o.__stickerOutlineEnabled) {
                applyStickerOutlinePatch(o);
                // Images may not have their element loaded yet after loadFromJSON
                // Schedule additional retries to ensure outline is generated
                setTimeout(() => {
                    if (o.__stickerOutlineEnabled && !o.__stickerOutlineCache) {
                        applyStickerOutlinePatch(o);
                    }
                }, 1500);
                setTimeout(() => {
                    if (o.__stickerOutlineEnabled && !o.__stickerOutlineCache) {
                        applyStickerOutlinePatch(o);
                    }
                }, 4000);
            }
            if (o.type === 'group' && typeof o.getObjects === 'function') {
                o.getObjects().forEach((c: any) => patchTree(c));
            }
        };
        objs.forEach((o: any) => patchTree(o));

        const isFrameLike = (o: any) => {
            if (!o) return false;
            const nRaw = (o?.name ?? '').toString();
            const n = nRaw.toUpperCase();
            // Prefer explicit flag.
            if (o?.isFrame) return true;
            // Common legacy names.
            if (n === 'FRAME' || n === 'FRAMER' || /^FRAME\s+\d+\s*$/i.test(nRaw)) return true;
            // Heuristic for older saves where custom props were missing:
            // A Frame is a Rect with clipContent + Figma blue stroke.
            const stroke = (o?.stroke ?? '').toString().toLowerCase();
            const isRect = isRectObject(o) || o?.type === 'rect';
            if (isRect && (o?.clipContent === true || o?.clipContent === 1) && stroke === '#0d99ff') return true;
            return false;
        };

        // Frames: restore flags + clip behavior
        const frames = objs.filter((o: any) => isFrameLike(o));

        // Normalize default Frame names (Figma-like): Frame 1, Frame 2, ...
        // Only touch frames that were never explicitly renamed (no layerName) and have a generic name.
        let maxFrameN = 0;
        frames.forEach((f: any) => {
            const n = (f?.layerName || f?.name || '').toString();
            const m = /^Frame\s+(\d+)\s*$/i.exec(n);
            if (m) maxFrameN = Math.max(maxFrameN, Number(m[1] || 0));
        });
        const nextFrameName = () => `Frame ${++maxFrameN}`;
        frames.forEach((f: any) => {
            // CRITICAL: Always restore isFrame flag (even if missing from JSON)
            f.isFrame = true;
            if (typeof f.clipContent !== 'boolean') f.clipContent = true;

            // CRITICAL: Ensure frames always have originX='center' and originY='center'.
            // Preserve the visual center while normalizing. Changing originX/originY
            // directly shifts legacy frames on reload, which then breaks clipping and
            // parentFrameId geometry.
            if (f.originX !== 'center' || f.originY !== 'center') {
                try {
                    const center = typeof f.getCenterPoint === 'function'
                        ? f.getCenterPoint()
                        : { x: Number(f.left || 0), y: Number(f.top || 0) };
                    f.set?.({
                        originX: 'center',
                        originY: 'center',
                        left: Number(center?.x ?? f.left ?? 0),
                        top: Number(center?.y ?? f.top ?? 0)
                    });
                } catch {
                    f.originX = 'center';
                    f.originY = 'center';
                }
                f.setCoords?.();
            }
            
            // Normalize name: if user renamed via layerName, keep it. Otherwise ensure proper "Frame N" name.
            if (!f.layerName) {
                const n = (f?.name || '').toString().trim();
                const isGeneric = !n || /^frame$/i.test(n) || /^framer$/i.test(n) || /^ret(â|a)ngulo$/i.test(n);
                const isNumbered = /^Frame\s+\d+\s*$/i.test(n);
                if (isGeneric) {
                    // Force normalize generic names to "Frame N"
                    f.name = nextFrameName();
                    console.log(`🔄 Frame normalizado: "${n}" → "${f.name}"`);
                } else if (!isNumbered && !/^Frame\s+\d+/.test(n)) {
                    // Custom name - leave as-is but ensure it's not empty
                    if (!f.name) f.name = nextFrameName();
                }
            } else {
                // User renamed - keep layerName, but also ensure name is set for display
                if (!f.name || /^ret(â|a)ngulo$/i.test(f.name)) {
                    f.name = f.layerName;
                }
            }
            
            // Ensure stroke is Figma blue if missing (helps with detection)
            if (!f.stroke || String(f.stroke).toLowerCase() !== '#0d99ff') {
                f.stroke = '#0d99ff';
            }
            
            if (isRectObject(f) && f.cornerRadii) applyRectCornerRadiiPatch(f);
            getOrCreateFrameClipRect(f);
        });

        const frameIds = new Set<string>(frames.map((f: any) => f._customId).filter(Boolean));
        const framesById = new Map<string, any>(
            frames
                .filter((f: any) => !!f?._customId)
                .map((f: any) => [String(f._customId), f])
        );
        objs.forEach((o: any) => {
            if (o?.parentFrameId && !frameIds.has(o.parentFrameId)) {
                o.parentFrameId = undefined;
                if (o._frameClipOwner) {
                    o.clipPath = null;
                    delete o._frameClipOwner;
                }
            }
        });

        // CRITICAL: Clear parentFrameId for objects that are NOT inside their supposed parent frame
        // This prevents clipping issues when objects are moved outside frames
        objs.forEach((o: any) => {
            if (!o?.parentFrameId || o?.isFrame) return;
            const frame = framesById.get(String(o.parentFrameId || ''));
            if (!frame) {
                o.parentFrameId = undefined;
                if (o._frameClipOwner) {
                    o.clipPath = null;
                    delete o._frameClipOwner;
                }
                return;
            }
            
            // Keep frame binding only while the object is mostly inside the frame.
            // This also repairs old saves where a large rectangle kept a stale
            // frame clip after being dragged/resized outside the frame.
            if (!isObjectMostlyInsideFrame(o, frame)) {
                console.log(`🔓 Removendo parentFrameId de objeto fora da maior parte do frame:`, {
                    object: o.name || o._customId,
                    frame: frame.name || frame._customId
                });
                o.parentFrameId = undefined;
                if (o._frameClipOwner) {
                    o.clipPath = null;
                    delete o._frameClipOwner;
                }
            }
        });

        // Re-apply clipPaths using shared frame clip rects (prevents stale deserialized clip rects).
        objs.forEach((o: any) => {
            if (o?.parentFrameId || o?._frameClipOwner) syncObjectFrameClip(o);
        });
        frames.forEach((f: any) => syncFrameClips(f));

        // Remove legacy zone rectangles from the deprecated renderer.
        // Keeping them causes duplicate/overlapping zone behaviors after spacing edits.
        const legacyZoneRects = objs.filter((o: any) =>
            o?.type === 'rect' &&
            (
                o?.id === 'product_zone_container' ||
                o?.name === 'product_zone_container' ||
                (o?.isZone === true && o?.isProductZone === true)
            )
        );
        if (legacyZoneRects.length > 0) {
            legacyZoneRects.forEach((o: any) => {
                canvas.value.remove(o);
            });
            console.log(`[rehydrateCanvasZones] Removed ${legacyZoneRects.length} legacy zone rect(s)`);
            objs = canvas.value.getObjects();
        }

        let zones = objs.filter((o: any) => o?.type === 'group' && isLikelyProductZone(o));

        // Diagnóstico: logar todas as zonas detectadas para debug
        if (zones.length > 0) {
            console.log(`[rehydrateCanvasZones] Detectadas ${zones.length} zona(s) de produtos:`, zones.map((z: any) => ({
                id: z._customId,
                name: z.name,
                visible: z.visible,
                left: Math.round(z.left ?? 0),
                top: Math.round(z.top ?? 0),
                width: Math.round(z._zoneWidth ?? z.width ?? 0),
                height: Math.round(z._zoneHeight ?? z.height ?? 0),
                children: typeof z.getObjects === 'function' ? z.getObjects().length : 0,
                isGridZone: z.isGridZone,
                isProductZone: z.isProductZone,
                parentFrameId: z.parentFrameId
            })));
        }

        // FIX: Multiple zones per frame are fully supported — the user can have as many
        // product zones as needed. If two zones share the EXACT SAME _customId (corruption),
        // regenerate the duplicate's ID instead of removing it. This prevents zones from
        // disappearing after save/reload.
        if (zones.length > 1) {
            const seenIds = new Set<string>();
            zones.forEach((z: any) => {
                const zid = String((z as any)._customId || '').trim();
                if (!zid) return;
                if (seenIds.has(zid)) {
                    // Mesmo _customId — regenerar em vez de remover
                    const oldId = z._customId;
                    z._customId = makeId();
                    seenIds.add(z._customId);
                    console.warn(`[rehydrateCanvasZones] Zona com _customId duplicado. Regenerado: ${oldId} -> ${z._customId}`);
                } else {
                    seenIds.add(zid);
                }
            });
        }

        restoreMissingManualTemplateFlagsInCanvas(canvas.value, 'rehydrate');

        zones.forEach((z: any) => {
            if (z.name === 'gridZone') z.isGridZone = true;
            if (z.name === 'productZoneContainer') z.isProductZone = true;
            if (!z.isGridZone && !z.isProductZone) z.isGridZone = true;
            if (!(z as any).zoneName) (z as any).zoneName = getNextProductZoneName(z);
            if (!(z as any).role) (z as any).role = 'grid';
            if (!(z as any).contentSource) (z as any).contentSource = 'manual';
            if (!(z as any).overflowPolicy) (z as any).overflowPolicy = 'warn';
            getResolvedZoneFrameId(z);

            // CRITICAL: Clear clipPath from zone AND all its children
            if (z.clipPath) {
                z.clipPath = null;
            }
            if (typeof z.getObjects === 'function') {
                z.getObjects().forEach((child: any) => {
                    if (child.clipPath) {
                        child.clipPath = null;
                    }
                });
            }

            // Keep persisted visibility, but never show a zone whose parent frame is hidden.
            const zoneFrameId = String((z as any).parentFrameId || '').trim();
            const hiddenByFrame = !!(zoneFrameId && getFrameById(zoneFrameId)?.visible === false);
            // FIX: Force zones visible unless hidden by frame (same rationale as cards above).
            if (!hiddenByFrame) z.visible = true;
            else z.visible = false;
            if (typeof z.opacity !== 'number') z.opacity = 1;
            if (!hiddenByFrame && z.opacity === 0) z.opacity = 1;

            ensureZoneSanity(z);

            // Zones should start with no background by default.
            // Fabric defaults rect fill to black when fill is unset/undefined; we normalize using `z.backgroundColor`.
            const zr = getZoneRect(z);
            if (zr) {
                const desired = typeof (z as any).backgroundColor === 'string' ? String((z as any).backgroundColor).trim() : '';
                if (!desired || desired === 'transparent') {
                    zr.set('fill', 'transparent');
                } else {
                    zr.set('fill', desired);
                }
            }

            normalizeZoneScale(z);
            // NOTE: safeAddWithUpdate is already called inside normalizeZoneScale ->
            // applyZoneScaleToRect.  Calling it again here would recalculate group
            // bounds a second time, potentially shifting zone.left/top without
            // compensating child cards (causing them to escape the zone).
            // If scaleX/Y were already 1 (normalizeZoneScale bailed early), we still
            // need to ensure coords are fresh for getBoundingRect to work in relayout.
            z.setCoords?.();


            const rawZoneStyles = (z as any)._zoneGlobalStyles;
            const hasPersistedZoneStyles =
                !!rawZoneStyles &&
                typeof rawZoneStyles === 'object' &&
                !Array.isArray(rawZoneStyles);

            // Normalizar sempre que _zoneGlobalStyles existir (mesmo parcial/vazio).
            // Objeto vazio significa "manter defaults, sem overrides" — diferente de undefined.
            if (hasPersistedZoneStyles) {
                (z as any)._zoneGlobalStyles = normalizeGlobalStyles(rawZoneStyles as Partial<GlobalStyles>);
            }
            const zoneStyles = hasPersistedZoneStyles ? getZoneGlobalStyles(z) : null;
            if (applyZoneStyles && zoneStyles) {
                const zoneCards = getZoneChildren(z);
                if (zoneCards.length > 0) {
                    applyGlobalStylesToCards(zoneStyles, z);
                } else if (import.meta.dev) {
                    console.debug('[rehydrateCanvasZones] Zone has no cards; skipping style reapply:', z._customId);
                }
            }
            syncZoneDerivedMetadata(z);
        });

        ensureProductZoneNamesDistinct(zones);

        // ═══════════════════════════════════════════════════════════════════
        // CRITICAL FIX: Sync composable state from persisted zone data.
        // After reload the composable starts with DEFAULT_GLOBAL_STYLES / DEFAULT_PRODUCT_ZONE.
        // The real source of truth lives on the Fabric zone object (_zoneGlobalStyles + zone props).
        // Without this sync, the ProductZoneSettings UI shows stale defaults until the user
        // manually clicks the zone (which triggers refreshSelectedRef).
        // ═══════════════════════════════════════════════════════════════════
        if (zones.length > 0) {
            const resolvedZoneForSync = (() => {
                const current = getCurrentZoneObject();
                if (current && zones.includes(current)) return current;
                if (zones.length === 1) return zones[0];
                // Fallback: usar a primeira zona que tenha estilos persistidos
                const withStyles = zones.find((z: any) => z._zoneGlobalStyles && typeof z._zoneGlobalStyles === 'object');
                if (withStyles) return withStyles;
                // Último fallback: primeira zona disponível (NUNCA retornar null se há zonas)
                return zones[0];
            })();

            if (resolvedZoneForSync) {
                const pad = typeof resolvedZoneForSync._zonePadding === 'number'
                    ? resolvedZoneForSync._zonePadding
                    : (typeof resolvedZoneForSync.padding === 'number' ? resolvedZoneForSync.padding : 20);
                const zoneConfig: ProductZone = {
                    ...DEFAULT_PRODUCT_ZONE,
                    enabled: true,
                    name: resolvedZoneForSync.zoneName || 'Zona de Produtos',
                    columns: resolvedZoneForSync.columns || 0,
                    rows: resolvedZoneForSync.rows || 0,
                    padding: pad,
                    gapHorizontal: typeof resolvedZoneForSync.gapHorizontal === 'number' ? resolvedZoneForSync.gapHorizontal : pad,
                    gapVertical: typeof resolvedZoneForSync.gapVertical === 'number' ? resolvedZoneForSync.gapVertical : pad,
                    layoutDirection: resolvedZoneForSync.layoutDirection || 'horizontal',
                    cardAspectRatio: resolvedZoneForSync.cardAspectRatio || 'fill',
                    lastRowBehavior: resolvedZoneForSync.lastRowBehavior || 'fill',
                    verticalAlign: resolvedZoneForSync.verticalAlign || 'stretch',
                    highlightCount: resolvedZoneForSync.highlightCount || 0,
                    highlightPos: resolvedZoneForSync.highlightPos || 'first',
                    highlightHeight: resolvedZoneForSync.highlightHeight || 1.5,
                    role: resolvedZoneForSync.role || 'grid',
                    contentSource: resolvedZoneForSync.contentSource || 'manual',
                    contentStatus: resolvedZoneForSync.contentStatus || 'filled',
                    overflowPolicy: resolvedZoneForSync.overflowPolicy || 'warn',
                };
                productZoneState.globalStyles.value = getZoneGlobalStyles(resolvedZoneForSync);
                productZoneState.productZone.value = zoneConfig;
            }
            // NUNCA resetar para defaults quando há zonas — preservar estado existente do composable
        }

        const zonesById = new Map<string, any>();
        zones.forEach((z: any) => zonesById.set(z._customId, z));

        const cards = objs.filter((o: any) => (o?.isSmartObject || o?.isProductCard || isLikelyProductCard(o)) && o !== null && o !== undefined);

        const validZoneIds = new Set<string>(zones.map((z: any) => String(z?._customId || '').trim()).filter(Boolean));
        const hadAnyValidBinding = cards.some((c: any) => {
            const id = String(c?.parentZoneId || '').trim();
            return id && validZoneIds.has(id);
        });

        // CRITICAL: Ensure all product cards are visible and have valid properties
        cards.forEach((card: any) => {
            if (!card.isProductCard && !card.isSmartObject && isLikelyProductCard(card)) {
                card.isProductCard = true;
                card.isSmartObject = true;
            }
            // Keep persisted visibility, but never show cards whose frame is hidden.
            let cardFrameId = String((card as any).parentFrameId || '').trim();
            if (!cardFrameId) {
                const zoneId = String((card as any).parentZoneId || (card as any)?._zoneSlot?.zoneId || '').trim();
                const boundZone = zoneId ? zonesById.get(zoneId) : null;
                const fallbackFrameId = String((boundZone as any)?.parentFrameId || '').trim();
                if (fallbackFrameId) {
                    cardFrameId = fallbackFrameId;
                    (card as any).parentFrameId = fallbackFrameId;
                }
            }
            const cardHiddenByFrame = !!(cardFrameId && getFrameById(cardFrameId)?.visible === false);
            // FIX: ALWAYS force visible:true for cards not hidden by frame.
            // Previously we only set visible when `typeof visible !== 'boolean'`,
            // but viewport culling could have saved cards with visible:false.
            // The __viewportCulled flag is transient (not in CANVAS_CUSTOM_PROPS),
            // so on reload we cannot distinguish culled-hidden from intentionally-hidden.
            // Product cards should ALWAYS be visible unless their parent frame is hidden.
            if (!cardHiddenByFrame) card.visible = true;
            else card.visible = false;
            if (typeof card.opacity !== 'number') card.opacity = 1;
            if (!cardHiddenByFrame && card.opacity === 0) card.opacity = 1;

            // CRITICAL: Disable objectCaching on cards after reload.
            // During creation, cards get objectCaching:false, but this prop is NOT
            // in CANVAS_CUSTOM_PROPS so it reverts to true after loadFromJSON.
            // Without this, style changes via resizeSmartObject may not render.
            card.set({ objectCaching: false, statefullCache: false, dirty: true });

            // CRITICAL: Permanently disable Fabric v7 LayoutManager on card groups.
            // Card layout is fully managed by resizeSmartObject — Fabric's auto-layout
            // only causes corruption by recalculating bounds from children at stale positions.
            const cardLm = (card as any).layoutManager;
            if (cardLm && cardLm.performLayout) cardLm.performLayout = () => {};

            // Restore saved dimensions — LayoutManager may have corrupted them
            // between loadFromJSON and this rehydrate code.
            const savedW = Number((card as any)._cardWidth) || 0;
            const savedH = Number((card as any)._cardHeight) || 0;
            if (savedW > 0 && savedH > 0) {
                card.set({ width: savedW, height: savedH });
            }

            // Also disable caching and LayoutManager on nested groups (e.g. priceGroup)
            if (typeof card.getObjects === 'function') {
                card.getObjects().forEach((child: any) => {
                    if (child && child.type === 'group') {
                        child.set({ objectCaching: false, statefullCache: false, dirty: true });
                        const nestedLm = (child as any).layoutManager;
                        if (nestedLm && nestedLm.performLayout) nestedLm.performLayout = () => {};
                    }
                });
            }

            // Prevent random black rectangles: Fabric defaults rect fill to black when fill is unset/undefined.
            // If a card's background fill becomes invalid, restore a safe default.
            if (card.type === 'group' && typeof card.getObjects === 'function') {
                const bg = card.getObjects().find((c: any) => c?.name === 'offerBackground' && c?.type === 'rect');
                if (bg && (bg.fill === undefined || bg.fill === null || bg.fill === '')) {
                    bg.set('fill', 'transparent');
                }
            }

            // Ensure the card is properly initialized
            if (typeof card.setCoords === 'function') card.setCoords();
        });

        // Auto-repair legacy/corrupted image transforms inside product cards
        // (negative scales, flips, invalid dimensions) before reflowing zone layout.
        const shouldRunLegacyImageRepair = legacyImageRepairMode !== 'skip';
        const repairStats = shouldRunLegacyImageRepair
            ? repairLegacyProductCardImageTransforms(cards, { verbose: import.meta.dev })
            : { cardsScanned: 0, imagesScanned: 0, imagesRepaired: 0 };
        if (import.meta.dev && repairStats.imagesRepaired > 0) {
            console.log('[rehydrateCanvasZones] Legacy image repair applied:', repairStats);
        }

        // CRITICAL FIX: Repair atacarejo price text names and re-apply pricing.
        // During initial creation, Fabric v7 dropped text names → setPriceOnPriceGroup
        // renamed them to `price_*` → applyAtacarejoPricingToPriceGroup couldn't find
        // `retail_*` names → retail tier was saved with empty text content.
        // This repair step fixes names and re-populates prices from stored _productData.
        cards.forEach((card: any) => {
            if (!card || card.type !== 'group' || typeof card.getObjects !== 'function') return;
            const productData = (card as any)?._productData;
            if (!productData || typeof productData !== 'object') return;

            // Find the priceGroup inside the card
            const children = card.getObjects() || [];
            const priceGroup = children.find((c: any) =>
                c?.type === 'group' && (c?.name === 'priceGroup' || String(c?.name || '').includes('price'))
            );
            if (!priceGroup || typeof priceGroup.getObjects !== 'function') return;

            // Check if this is an atacarejo template (has atac_retail_bg)
            const pgChildren = collectObjectsDeep(priceGroup);
            const hasAtacBg = pgChildren.some((o: any) => o?.name === 'atac_retail_bg');
            if (!hasAtacBg) return;

            // Check if retail tier is missing prices (empty or just "R$")
            const retailInteger = pgChildren.find((o: any) => o?.name === 'retail_integer_text');
            const hasPriceIntNamedCorrectly = !!retailInteger;
            const retailIntText = String(retailInteger?.text || '').trim();
            const retailMissing = !hasPriceIntNamedCorrectly || !retailIntText || retailIntText === '0';

            if (retailMissing) {
                // Re-apply atacarejo pricing from stored product data
                try {
                    applyAtacarejoPricingToPriceGroup(priceGroup, productData);
                } catch (e) {
                    // ignore repair failures
                }
            }
        });

        // Repair missing parentZoneId by intersection (helps after old history/undo states)
        const cardsWithSavedParentZone = new Set<any>();
        cards.forEach((card: any) => {
            if (!card._customId) card._customId = makeId();
            if (card._cardWidth == null) card._cardWidth = card.width;
            if (card._cardHeight == null) card._cardHeight = card.height;

            // If card already has a valid parentZoneId from saved data, preserve it
            // only when the zone lives in the same frame. Older duplicated frames can
            // contain cards whose parentFrameId points at the copy while parentZoneId
            // still points at the original zone, making replacement hit the original.
            if (card.parentZoneId && zonesById.has(card.parentZoneId)) {
                const boundZone = zonesById.get(card.parentZoneId);
                const boundZoneFrameId = String(getResolvedZoneFrameId(boundZone) || (boundZone as any)?.parentFrameId || '').trim();
                const currentCardFrameId = String((card as any)?.parentFrameId || '').trim();
                if (!currentCardFrameId || !boundZoneFrameId || currentCardFrameId === boundZoneFrameId) {
                    cardsWithSavedParentZone.add(card);
                    return;
                }
            }
            
            // Only repair cards that are missing parentZoneId
            card.parentZoneId = undefined;

            const center = typeof card.getCenterPoint === 'function'
                ? card.getCenterPoint()
                : { x: (card.left ?? 0), y: (card.top ?? 0) };

            let bestZone: any = null;
            let bestD2 = Infinity;

            for (const zone of zones) {
                if (zone.intersectsWithObject && zone.intersectsWithObject(card)) {
                    card.parentZoneId = zone._customId;
                    bestZone = null;
                    bestD2 = Infinity;
                    break;
                }

                // Fallback: distance from card center to zone rect (more robust than center-to-center).
                const zm = getZoneMetrics(zone) ?? zone.getBoundingRect(true);
                const dx = (center.x < zm.left)
                    ? (zm.left - center.x)
                    : (center.x > (zm.left + zm.width))
                        ? (center.x - (zm.left + zm.width))
                        : 0;
                const dy = (center.y < zm.top)
                    ? (zm.top - center.y)
                    : (center.y > (zm.top + zm.height))
                        ? (center.y - (zm.top + zm.height))
                        : 0;
                const d2 = (dx * dx) + (dy * dy);
                if (d2 < bestD2) {
                    bestD2 = d2;
                    bestZone = zone;
                }
            }

            // If not intersecting any zone, attach to the nearest one only if it's reasonably close.
            if (!card.parentZoneId && bestZone) {
                // If there's only one zone, legacy projects often lost the IDs entirely.
                // In that case, bind every card-like group to the single zone so the layout can be reconstructed.
                if (zones.length === 1) {
                    card.parentZoneId = bestZone._customId;
                } else {
                    const zm = getZoneMetrics(bestZone) ?? bestZone.getBoundingRect(true);
                    const maxDim = Math.max(zm.width || 0, zm.height || 0);

                    // More aggressive repair if the project has no valid bindings at all (classic "solto" legacy state).
                    const base = hadAnyValidBinding ? 2.5 : 6.0;
                    const maxD = Math.max(200, maxDim * base);
                    if (Number.isFinite(bestD2) && bestD2 <= (maxD * maxD)) {
                        card.parentZoneId = bestZone._customId;
                    }
                }
            }

            // Se o _zoneSlot aponta para uma zona diferente da resolvida acima,
            // invalidamos o slot para forcar recalculateZoneLayout a reatribuir um slot
            // valido. Sem isso o card ficaria posicionado no slot de uma zona que
            // ja nao e sua pai — UI diverge do JSON apos undo/redo ou reload.
            const repairedZid = String((card as any)?.parentZoneId || '').trim();
            const slotZid = String((card as any)?._zoneSlot?.zoneId || '').trim();
            if (repairedZid && slotZid && slotZid !== repairedZid) {
                (card as any)._zoneSlot = null;
            }
            normalizeProductCardIdentity(card, {
                zoneInstanceId: repairedZid || null,
                reason: 'rehydrate-card'
            });
        });

        // Keep card → frame binding aligned with its zone frame.
        cards.forEach((card: any) => {
            const zoneId = String((card as any)?.parentZoneId || '').trim();
            if (!zoneId) return;
            const zone = zonesById.get(zoneId);
            if (!zone) return;
            const zoneFrameId = getResolvedZoneFrameId(zone);
            applyCardFrameBinding(card, zoneFrameId);
        });

        const zoneIdsWithCards = new Set<string>();
        cards.forEach((c: any) => {
            if (typeof c.parentZoneId === 'string') zoneIdsWithCards.add(c.parentZoneId);
        });
        zones.forEach((z: any) => {
            if (zoneIdsWithCards.has(z._customId)) z.isProductZone = true;
        });

        if (relayout) {
            zones.forEach((z: any) => {
                if (z.isProductZone || zoneIdsWithCards.has(z._customId)) {
                    try {
                        const zoneCards = cards.filter((c: any) => String((c as any).parentZoneId || '').trim() === String(z._customId || '').trim());
                        // CRITICAL FIX: Do NOT force relayout if cards already have valid
                        // saved positions from JSON. Relaying out overwrites saved left/top/width/height
                        // with grid-computed values, destroying the exact layout the user saved.
                        // Only relayout if cards are clearly missing positions (all at 0,0 or NaN).
                        const allHavePositions = zoneCards.length > 0 && zoneCards.every((c: any) => {
                            const l = Number(c.left ?? NaN);
                            const t = Number(c.top ?? NaN);
                            return Number.isFinite(l) && Number.isFinite(t);
                        });
                        const allAtOrigin = zoneCards.length > 1 && zoneCards.every((c: any) => {
                            return Math.abs(Number(c.left ?? 0)) < 2 && Math.abs(Number(c.top ?? 0)) < 2;
                        });
                        if (allHavePositions && !allAtOrigin) {
                            // Cards have valid saved positions — preserve them exactly as saved.
                            // Just ensure coords are fresh for hit-testing.
                            zoneCards.forEach((c: any) => c.setCoords?.());
                        } else {
                            // Cards are missing positions or all stacked at origin — relayout needed.
                            recalculateZoneLayout(z, zoneCards, { skipResize: true });
                        }
                    } catch (err) {
                        console.warn('[rehydrateCanvasZones] Failed to relayout zone', err);
                    }
                }
            });
        }

        scheduleZoneSnapshotRecovery(zones, 'rehydrate');

        // Ensure zones never sit above their cards (legacy saved designs sometimes have wrong stacking order).
        // If the zone is above the cards, it intercepts clicks and prevents selecting products individually.
        try {
            const c: any = canvas.value as any;
            if (typeof c.moveTo === 'function') {
                zones.forEach((z: any) => {
                    const list = canvas.value!.getObjects();
                    const zoneIndex = list.indexOf(z);
                    if (zoneIndex < 0) return;

                    const zoneCardIndices: number[] = [];
                    for (let i = 0; i < list.length; i++) {
                        const o = list[i];
                        if (!o || o === z) continue;
                        const isCard = !!(o.isSmartObject || o.isProductCard || isLikelyProductCard(o));
                        if (!isCard) continue;
                        if ((o as any).parentZoneId === z._customId) zoneCardIndices.push(i);
                    }
                    if (!zoneCardIndices.length) return;

                    const minCardIndex = Math.min(...zoneCardIndices);
                    if (!Number.isFinite(minCardIndex)) return;

                    // Keep it above artboard-bg and frames.
                    const bgIndex = list.findIndex((o: any) => o?.id === 'artboard-bg');
                    let floorIndex = bgIndex >= 0 ? bgIndex + 1 : 0;
                    for (let i = 0; i < list.length; i++) {
                        if (list[i]?.isFrame) floorIndex = Math.max(floorIndex, i + 1);
                    }

                    const targetIndex = Math.max(floorIndex, minCardIndex - 1);
                    if (zoneIndex > targetIndex) c.moveTo(z, targetIndex);
                });
            }
        } catch (e) {
            // Ignore stacking errors
        }

        // Frames sempre atrás do conteúdo (evita bloquear drag do mouse em imagens)
        ensureFramesBelowContents();
        stabilizePriceGroupsForPersistence(canvas.value, 'rehydrate');
        scheduleMissingProductImageRecovery();

        refreshCanvasObjects();
        safeRequestRenderAll();
    } finally {
        isHistoryProcessing.value = prevHistory;
    }
}

const handleRecalculateLayout = () => {
    const zone = getCurrentZoneObject();
    if (!zone) return;
    ensureZoneSanity(zone);
    recalculateZoneLayout(zone);
    // Re-select zone and refresh snapshot after layout recalculation
    if (canvas.value) {
        try { canvas.value.setActiveObject(zone); } catch { /* ignore */ }
        safeRequestRenderAll();
    }
    refreshSelectedRef();
}


</script>

<template>
  <div class="flex flex-col h-full min-h-0 min-w-0 w-full bg-background text-foreground antialiased font-sans overflow-hidden">
      
      <ProjectManager
        v-if="showProjectManager"
        :isOpen="showProjectManager" 
        @close="showProjectManager = false"
        @load="(data) => loadCanvasData(data)"
      />

      <AiImageStudioModal
        v-if="aiStudioOpen"
        v-model="aiStudioOpen"
        :uploads="aiStudioUploads"
        :initial="aiStudioOptions.initial"
        @created="handleAiStudioCreated"
      />

      <div
        v-if="showProductImageUploadPicker"
        class="fixed inset-0 z-140 bg-black/60 backdrop-blur-[1px] flex items-center justify-center p-4"
        @click.self="showProductImageUploadPicker = false; clearPendingProductImageOperation()"
      >
        <div class="w-full max-w-5xl max-h-[85vh] bg-[#1a1a1a] border border-white/10 rounded-xl shadow-2xl flex flex-col overflow-hidden">
          <div class="flex items-center justify-between px-4 py-3 border-b border-white/10">
            <div>
              <h3 class="text-sm font-semibold text-white">Selecionar do Upload</h3>
              <p class="text-[11px] text-zinc-400">
                {{ productImagePickerMode === 'replace' ? 'Substituir imagem do produto' : 'Adicionar imagem mantendo a atual' }}
              </p>
            </div>
            <button
              type="button"
              class="text-zinc-400 hover:text-white text-lg leading-none"
              @click="showProductImageUploadPicker = false; clearPendingProductImageOperation()"
            >
              ×
            </button>
          </div>

          <div class="px-4 py-3 border-b border-white/10">
            <input
              v-model="productImagePickerSearch"
              type="text"
              placeholder="Buscar imagem no upload..."
              class="w-full h-10 bg-zinc-900 border border-white/10 rounded px-3 text-sm text-white focus:outline-none focus:border-violet-500/50"
            />
          </div>

          <div class="flex-1 overflow-y-auto p-4">
            <div v-if="!filteredProductImageUploads.length" class="text-xs text-zinc-500">
              Nenhuma imagem encontrada no upload.
            </div>
            <div v-else class="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 gap-3">
              <button
                v-for="asset in filteredProductImageUploads"
                :key="asset.id"
                type="button"
                class="bg-zinc-900 border border-white/10 rounded-lg overflow-hidden text-left hover:border-violet-500/50 transition-colors"
                @click="applyProductImageFromUploadPicker(asset)"
              >
                <div class="aspect-square">
                  <img :src="toWasabiDirectUrl(asset.url) || asset.url" class="w-full h-full object-cover" />
                </div>
                <div class="px-2 py-1.5 border-t border-white/10">
                  <p class="text-[10px] text-zinc-200 truncate">{{ asset.name || 'Sem nome' }}</p>
                </div>
              </button>
            </div>
          </div>
        </div>
      </div>

      <!-- Central Workspace -->
      <div class="flex flex-1 min-h-0 min-w-0 overflow-hidden relative bg-[#1a1a1a]">
          <!-- Left Sidebar (New Component) -->
          <SidebarLeft v-show="!isMobile" @insert-asset="insertAssetToCanvas" @insert-element="insertElementToCanvas" @open-menu="showProjectManager = true" @generate-institutional="handleGenerateInstitutional">
              <template #layers-panel>
                  <LayersPanel 
                      class="flex-1"
                      :objects="canvasObjects" 
                      :selectedId="selectedObjectId"
                      :selectedIds="selectedObjectIds"
                      @select="selectObject"
                      @toggle-visible="toggleVisible"
                      @toggle-lock="toggleLock"
                      @delete="deleteObject"
                      @move-up="id => moveLayer(id, 'up')"
                      @move-down="id => moveLayer(id, 'down')"
                      @rename="renameLayer"
                      @reorder="reorderLayerByDrag"
                      @context-menu="handleLayersContextMenu"
                  />
              </template>
          </SidebarLeft>

          <!-- Canvas Stage -->
          <main class="flex-1 min-w-0 min-h-0 relative bg-[#1a1a1a] flex items-center justify-center overflow-hidden cursor-grab active:cursor-grabbing" :style="isMobile ? ((project.pages?.length || 0) > 1 ? 'padding-bottom: 140px' : 'padding-bottom: 56px') : ''">
              <!-- Infinite Canvas Effect (Wrapper) -->
                  <div ref="wrapperEl" class="w-full h-full min-w-0 min-h-0 relative flex items-center justify-center overflow-hidden bg-[#1a1a1a]">
                  <canvas ref="canvasEl" class="block canvas-touch-surface" @contextmenu.prevent.stop></canvas>

                  <CanvasRulers
                    :visible="viewShowRulers"
                    :canvas="canvas"
                    :wrapper-el="wrapperEl"
                    :guides="rulerGuides"
                    @create-guide="handleCreateUserGuide"
                    @update-guide="handleUpdateUserGuide"
                    @delete-guide="handleDeleteUserGuide"
                  />

                  <!-- Design loader overlay (prevents "blank canvas until click" confusion) -->
                  <div
                    v-show="showDesignLoaderOverlay"
                    class="absolute inset-0 flex items-center justify-center bg-black/40 backdrop-blur-[1px] cursor-wait"
                    style="z-index: 200;"
                    aria-live="polite"
                  >
                    <div class="px-4 py-3 rounded-lg bg-zinc-950/70 border border-white/10 shadow-xl">
                      <div class="flex items-center gap-2">
                        <div class="w-4 h-4 rounded-full border-2 border-white/20 border-t-white animate-spin"></div>
                        <p class="text-sm text-white/90">{{ designLoadMessage }}</p>
                      </div>
                      <p class="text-[11px] text-white/55 mt-1">{{ designLoadProgressLine || 'Aguarde alguns segundos.' }}</p>
                    </div>
                  </div>

                  <!-- Storage degraded banner (missing/blocked images) -->
                  <div
                    v-show="showStorageDegradedBanner"
                    class="absolute top-3 left-1/2 -translate-x-1/2"
                    style="z-index: 210;"
                  >
                    <div class="flex items-center gap-2 px-3 py-2 rounded-full bg-amber-950/60 border border-amber-300/20 text-amber-100 shadow-lg">
                      <span class="text-xs">{{ storageDegradedHint || 'Algumas imagens nao carregaram.' }}</span>
                      <button
                        type="button"
                        class="text-xs px-2 py-1 rounded-full bg-amber-200/10 hover:bg-amber-200/15 border border-amber-200/20"
                        @click="retryStorageReload"
                      >
                        Recarregar
                      </button>
                      <button
                        v-if="canRecoverLatestNonEmpty"
                        type="button"
                        class="text-xs px-2 py-1 rounded-full bg-white/5 hover:bg-white/10 border border-white/10"
                        @click="openHistoryModal"
                      >
                        Historico
                      </button>
                      <button
                        v-if="canRecoverLatestNonEmpty"
                        type="button"
                        class="text-xs px-2 py-1 rounded-full bg-red-200/10 hover:bg-red-200/15 border border-red-200/20"
                        :disabled="isRecoveringLatestNonEmpty"
                        @click="recoverLatestNonEmptyForActivePage"
                      >
                        {{ isRecoveringLatestNonEmpty ? 'Recuperando...' : 'Recuperar' }}
                      </button>
                    </div>
                  </div>

                  <ContextMenu
                    v-model="canvasContextMenu.show"
                    :x="canvasContextMenu.x"
                    :y="canvasContextMenu.y"
                    :items="canvasContextMenuItems"
                    @select="handleCanvasContextMenuSelect"
                  />

                  <ContextMenu
                    v-model="layersContextMenu.show"
                    :x="layersContextMenu.x"
                    :y="layersContextMenu.y"
                    :items="layersContextMenuItems"
                    @select="handleLayersContextMenuSelect"
                  />
                  
                  <!-- Virtual Scrollbars (Figma Style) -->
                  <div 
                    v-show="scrollV.visible" 
                    class="absolute right-1 w-1.5 bg-white/20 hover:bg-white/40 rounded-full z-50 transition-colors cursor-pointer" 
                    :style="{ top: scrollV.top + 'px', height: scrollV.height + 'px' }"
                    @mousedown="handleVerticalScrollbarDrag"
                  ></div>
                  <div 
                    v-show="scrollH.visible" 
                                        class="absolute bottom-1 h-1.5 bg-white/20 hover:bg-white/40 rounded-full z-60 transition-colors cursor-pointer" 
                    :style="{ left: scrollH.left + 'px', width: scrollH.width + 'px' }"
                    @mousedown="handleHorizontalScrollbarDrag"
                  ></div>

                  <!-- Frame Label Overlays (clickable, always visible) -->
                  <FrameLabelsOverlay
                    :labels="frameLabels"
                    @label-click="handleFrameLabelClick"
                    @label-mousedown="handleFrameLabelMouseDown"
                  />

                  <ZoneQuickActions
                    v-if="selectedZoneQuickActions"
                    :visible="showZoneQuickActions"
                    :top="selectedZoneQuickActionsPos.top"
                    :left="selectedZoneQuickActionsPos.left"
                    :width="selectedZoneQuickActionsPos.width"
                    :height="selectedZoneQuickActionsPos.height"
                    :name="selectedZoneQuickActions.name"
                    :role-label="selectedZoneQuickActions.roleLabel"
                    :status-label="selectedZoneQuickActions.statusLabel"
                    :frame-label="selectedZoneQuickActions.frameLabel"
                    :product-count="selectedZoneQuickActions.productCount"
                    :is-empty="selectedZoneQuickActions.isEmpty"
                    @fill="handleZoneQuickActionFill"
                    @append="handleZoneQuickActionAppend"
                    @replace="handleZoneQuickActionReplace"
                    @preset="handleZoneQuickActionPreset"
                    @duplicate="handleZoneQuickActionDuplicate"
                  />

                  <input type="file" ref="fileInput" class="hidden" @change="handleFileUpload" accept="image/*" multiple />
              </div>

              <!-- Contextual Toolbar for Vector Paths (Above Main Toolbar) -->
	              <PenContextualToolbar
	                :visible="showPenContextualToolbar"
	                :is-vector-path="!!selectedObjectRef?.isVectorPath || !!currentEditingPath?.isVectorPath"
	                :is-node-editing="isNodeEditing"
	                :can-delete-point="selectedPathNodeIndex !== null"
                @toggle-visible="selectedObjectRef && updateObjectProperty('visible', !selectedObjectRef.visible)"
                @toggle-handles="handleAction('toggle-handles')"
                @add-point="handleAction('add-path-point')"
                @delete-point="handleAction('delete-path-point')"
                @split-path="splitPath"
                @simplify-path="simplifyPath"
                @close-path="closePath"
              />

              <!-- Floating Toolbar (Figma Style) - Bottom Center -->
              <CanvasFloatingToolbar
                v-show="!isMobile"
                :is-drawing="isDrawing"
                :is-pen-mode="isPenMode"
                @select-tool="setTool('select')"
                @add-frame="addFrame"
                @add-shape="(type, options) => addShape(type as any, options as any)"
                @add-text="(variant) => addText(variant as any)"
                @toggle-pen-mode="togglePenMode"
                @toggle-drawing="toggleDrawing"
                @set-pen-width="setPenWidth"
                @add-grid-zone="addGridZone"
                @open-label-templates="showLabelTemplatesModal = true"
              />

              <!-- Mobile Undo/Redo Bar (always visible on mobile) -->
              <div
                v-if="isMobile"
                class="absolute top-2 left-2 z-200 flex items-center gap-1 px-1.5 py-1 rounded-lg bg-[#18181b]/90 backdrop-blur-md border border-white/10 shadow-lg"
              >
                <button class="touch-target flex items-center justify-center text-white/60 hover:text-white active:text-violet-400 rounded-lg hover:bg-white/10 w-9 h-9" title="Desfazer" @click="undo()">
                  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M3 7v6h6"/><path d="M21 17a9 9 0 0 0-9-9 9 9 0 0 0-6 2.3L3 13"/></svg>
                </button>
                <button class="touch-target flex items-center justify-center text-white/60 hover:text-white active:text-violet-400 rounded-lg hover:bg-white/10 w-9 h-9" title="Refazer" @click="redo()">
                  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M21 7v6h-6"/><path d="M3 17a9 9 0 0 1 9-9 9 9 0 0 1 6 2.3L21 13"/></svg>
                </button>
              </div>

              <!-- Mobile Zoom Display (top right) -->
              <div
                v-if="isMobile"
                class="absolute top-2 right-2 z-200 flex items-center gap-1"
              >
                <!-- Botao Exportar destacado (atalho rapido para ExportDialog) -->
                <button
                  class="touch-target flex items-center gap-1 px-2.5 py-1.5 rounded-lg bg-violet-500 hover:bg-violet-600 active:bg-violet-700 text-white shadow-lg border border-violet-400/40"
                  title="Exportar (PNG / JPG / PDF)"
                  @click="exportDesign()"
                >
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" x2="12" y1="15" y2="3"/></svg>
                  <span class="text-[11px] font-semibold">Exportar</span>
                </button>

                <!-- Grupo de zoom -->
                <div class="flex items-center gap-1 px-1.5 py-1 rounded-lg bg-[#18181b]/90 backdrop-blur-md border border-white/10 shadow-lg">
                  <button class="touch-target flex items-center justify-center text-white/60 hover:text-white active:text-violet-400 rounded-lg hover:bg-white/10 w-9 h-9" title="Zoom -" @click="handleZoomOut()">
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="11" cy="11" r="8"/><line x1="21" x2="16.65" y1="21" y2="16.65"/><line x1="8" x2="14" y1="11" y2="11"/></svg>
                  </button>
                  <span class="text-[11px] text-white/50 min-w-9 text-center tabular-nums">{{ Math.round(currentZoom) }}%</span>
                  <button class="touch-target flex items-center justify-center text-white/60 hover:text-white active:text-violet-400 rounded-lg hover:bg-white/10 w-9 h-9" title="Zoom +" @click="handleZoomIn()">
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="11" cy="11" r="8"/><line x1="21" x2="16.65" y1="21" y2="16.65"/><line x1="11" x2="11" y1="8" y2="14"/><line x1="8" x2="14" y1="11" y2="11"/></svg>
                  </button>
                </div>
              </div>

              <!-- Mobile Quick Actions Bar (appears when object is selected) -->
              <div
                v-if="isMobile && selectedObjectRef"
                class="absolute left-0 right-0 z-200 flex items-center justify-center px-2"
                :style="(project.pages?.length || 0) > 1 ? 'bottom: 148px' : 'bottom: 64px'"
              >
                <div class="flex items-center gap-0.5 px-2 py-1.5 rounded-xl bg-[#18181b]/95 backdrop-blur-md border border-white/10 shadow-xl overflow-x-auto max-w-full scrollbar-hide">
                  <!-- Copy -->
                  <button class="touch-target flex items-center justify-center text-white/60 hover:text-white active:text-violet-400 rounded-lg hover:bg-white/10 px-2 shrink-0" title="Copiar" @click="triggerCopyShortcut">
                    <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><rect width="14" height="14" x="8" y="8" rx="2"/><path d="M4 16c-1.1 0-2-.9-2-2V4c0-1.1.9-2 2-2h10c1.1 0 2 .9 2 2"/></svg>
                  </button>
                  <!-- Paste -->
                  <button class="touch-target flex items-center justify-center text-white/60 hover:text-white active:text-violet-400 rounded-lg hover:bg-white/10 px-2 shrink-0" title="Colar" @click="triggerPasteShortcut">
                    <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M15 2H9a1 1 0 0 0-1 1v2c0 .6.4 1 1 1h6c.6 0 1-.4 1-1V3c0-.6-.4-1-1-1Z"/><path d="M8 4H6a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2M16 4h2a2 2 0 0 1 2 2v2"/><path d="M12 12h4"/><path d="M12 16h4"/></svg>
                  </button>
                  <div class="w-px h-5 bg-white/10 mx-0.5 shrink-0"></div>
                  <!-- Duplicate -->
                  <button class="touch-target flex items-center justify-center text-white/60 hover:text-white active:text-violet-400 rounded-lg hover:bg-white/10 px-2 shrink-0" title="Duplicar" @click="handleAction('duplicate')">
                    <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><rect width="13" height="13" x="9" y="9" rx="2"/><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"/></svg>
                  </button>
                  <!-- Delete -->
                  <button class="touch-target flex items-center justify-center text-white/60 hover:text-white active:text-red-400 rounded-lg hover:bg-white/10 px-2 shrink-0" title="Deletar" @click="deleteActiveSelectionFromCanvas()">
                    <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M3 6h18"/><path d="M19 6v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6"/><path d="M8 6V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2"/></svg>
                  </button>
                  <div class="w-px h-5 bg-white/10 mx-0.5 shrink-0"></div>
                  <!-- Flip H -->
                  <button class="touch-target flex items-center justify-center text-white/60 hover:text-white active:text-violet-400 rounded-lg hover:bg-white/10 px-2 shrink-0" title="Flip Horizontal" @click="handleAction('flip-h')">
                    <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M8 3H5a2 2 0 0 0-2 2v14c0 1.1.9 2 2 2h3"/><path d="M16 3h3a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2h-3"/><line x1="12" x2="12" y1="20" y2="4"/></svg>
                  </button>
                  <!-- Flip V -->
                  <button class="touch-target flex items-center justify-center text-white/60 hover:text-white active:text-violet-400 rounded-lg hover:bg-white/10 px-2 shrink-0" title="Flip Vertical" @click="handleAction('flip-v')">
                    <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M3 8V5a2 2 0 0 1 2-2h14c1.1 0 2 .9 2 2v3"/><path d="M3 16v3a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-3"/><line x1="4" x2="20" y1="12" y2="12"/></svg>
                  </button>
                  <div class="w-px h-5 bg-white/10 mx-0.5 shrink-0"></div>
                  <!-- Bring to Front -->
                  <button class="touch-target flex items-center justify-center text-white/60 hover:text-white active:text-violet-400 rounded-lg hover:bg-white/10 px-2 shrink-0" title="Trazer para frente" @click="arrangeActiveObjects('bring-to-front')">
                    <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="m17 11-5-5-5 5"/><path d="m17 18-5-5-5 5"/></svg>
                  </button>
                  <!-- Send to Back -->
                  <button class="touch-target flex items-center justify-center text-white/60 hover:text-white active:text-violet-400 rounded-lg hover:bg-white/10 px-2 shrink-0" title="Enviar para trás" @click="arrangeActiveObjects('send-to-back')">
                    <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="m7 6 5 5 5-5"/><path d="m7 13 5 5 5-5"/></svg>
                  </button>
                  <div class="w-px h-5 bg-white/10 mx-0.5 shrink-0"></div>
                  <!-- Group -->
                  <button class="touch-target flex items-center justify-center text-white/60 hover:text-white active:text-violet-400 rounded-lg hover:bg-white/10 px-2 shrink-0" title="Agrupar" @click="groupSelection()">
                    <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><rect x="2" y="2" width="8" height="8" rx="1"/><rect x="14" y="2" width="8" height="8" rx="1"/><rect x="2" y="14" width="8" height="8" rx="1"/><rect x="14" y="14" width="8" height="8" rx="1"/></svg>
                  </button>
                  <!-- Ungroup -->
                  <button class="touch-target flex items-center justify-center text-white/60 hover:text-white active:text-violet-400 rounded-lg hover:bg-white/10 px-2 shrink-0" title="Desagrupar" @click="handleAction('ungroup')">
                    <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><rect x="5" y="5" width="14" height="14" rx="2" stroke-dasharray="3 3"/><path d="M2 2h5v5H2z" fill="currentColor" opacity="0.3"/><path d="M17 2h5v5h-5z" fill="currentColor" opacity="0.3"/><path d="M2 17h5v5H2z" fill="currentColor" opacity="0.3"/><path d="M17 17h5v5h-5z" fill="currentColor" opacity="0.3"/></svg>
                  </button>
                  <div class="w-px h-5 bg-white/10 mx-0.5 shrink-0"></div>
                  <!-- Align Left -->
                  <button class="touch-target flex items-center justify-center text-white/60 hover:text-white active:text-violet-400 rounded-lg hover:bg-white/10 px-2 shrink-0" title="Alinhar Esquerda" @click="alignSelectionHorizontally('left')">
                    <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8"><line x1="4" x2="4" y1="2" y2="22"/><rect x="8" y="4" width="12" height="5" rx="1"/><rect x="8" y="15" width="8" height="5" rx="1"/></svg>
                  </button>
                  <!-- Align Center H -->
                  <button class="touch-target flex items-center justify-center text-white/60 hover:text-white active:text-violet-400 rounded-lg hover:bg-white/10 px-2 shrink-0" title="Centralizar H" @click="alignSelectionHorizontally('center')">
                    <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8"><line x1="12" x2="12" y1="2" y2="22"/><rect x="5" y="4" width="14" height="5" rx="1"/><rect x="7" y="15" width="10" height="5" rx="1"/></svg>
                  </button>
                  <!-- Align Right -->
                  <button class="touch-target flex items-center justify-center text-white/60 hover:text-white active:text-violet-400 rounded-lg hover:bg-white/10 px-2 shrink-0" title="Alinhar Direita" @click="alignSelectionHorizontally('right')">
                    <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8"><line x1="20" x2="20" y1="2" y2="22"/><rect x="4" y="4" width="12" height="5" rx="1"/><rect x="8" y="15" width="8" height="5" rx="1"/></svg>
                  </button>
                  <div class="w-px h-5 bg-white/10 mx-0.5 shrink-0"></div>
                  <!-- Properties -->
                  <button class="touch-target flex items-center justify-center text-white/60 hover:text-white active:text-violet-400 rounded-lg hover:bg-white/10 px-2 shrink-0" title="Propriedades" @click="mobilePanel = 'properties'">
                    <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><line x1="4" x2="4" y1="21" y2="14"/><line x1="4" x2="4" y1="10" y2="3"/><line x1="12" x2="12" y1="21" y2="12"/><line x1="12" x2="12" y1="8" y2="3"/><line x1="20" x2="20" y1="21" y2="16"/><line x1="20" x2="20" y1="12" y2="3"/><line x1="2" x2="6" y1="14" y2="14"/><line x1="10" x2="14" y1="8" y2="8"/><line x1="18" x2="22" y1="16" y2="16"/></svg>
                  </button>
                </div>
              </div>
          </main>

          <EditorRightSidebar
            v-show="!isMobile"
            :collaborators="collaborators || []"
            :current-user="currentUser"
            :show-zoom-menu="showZoomMenu"
            :current-zoom="currentZoom"
            :get-color-from-string="getColorFromString"
            :get-initial="getInitial"
            :selected-object="selectedObjectRef"
            :active-mode="activeMode"
            :page-settings="pageSettings"
            :color-styles="project.colorStyles || []"
            :product-zone="productZoneState.productZone.value"
            :product-zone-inspector="selectedZoneInspectorData"
            :product-global-styles="productZoneState.globalStyles.value"
            :label-templates="labelTemplates"
            :view-show-grid="viewShowGrid"
            :view-show-rulers="viewShowRulers"
            :view-show-guides="viewShowGuides"
            :snap-to-objects="snapToObjects"
            :snap-to-guides="snapToGuides"
            :snap-to-grid="snapToGrid"
            :grid-size="gridSize"
            @update:show-zoom-menu="showZoomMenu = $event"
            @present="startPresentation()"
            @open-ai-generate="openAiGenerationModal"
            @open-share="shareDesign"
            @zoom-50="handleZoom50"
            @zoom-100="handleZoom100"
            @zoom-200="handleZoom200"
            @zoom-400="handleZoom400"
            @zoom-fit="zoomToFit"
            @zoom-selection="handleZoomToSelection"
            @toggle-grid="toggleGrid"
            @toggle-rulers="toggleRulers"
            @toggle-guides="toggleGuides"
            @toggle-snap-objects="toggleSnapObjects"
            @toggle-snap-guides="toggleSnapGuides"
            @toggle-snap-grid="toggleSnapGrid"
            @set-grid-size="setGridSize"
            @update-property="updateObjectProperty"
            @update-smart-group="updateSmartGroup"
            @update-page-settings="updatePageSettings"
            @action="handleAction"
            @add-color-style="addColorStyle"
            @apply-color-style="applyColorStyle"
            @update-zone="handleUpdateZone"
            @update-global-styles="handleUpdateGlobalStyles"
            @apply-template-to-zone="handleApplyTemplateToZone"
            @apply-preset="handleApplyZonePreset"
            @sync-gaps="handleSyncZoneGaps"
            @recalculate-layout="handleRecalculateLayout"
            @manage-label-templates="showLabelTemplatesModal = true"
            @open-zone-review="handleZoneQuickActionFill"
            @change-mode="(mode: 'design' | 'prototype') => activeMode = mode"
          />
      </div>

      <!-- Mobile Pages Carousel (estilo Canva: swipe horizontal entre páginas) -->
      <EditorMobilePagesCarousel
        v-if="isMobile && (project.pages?.length || 0) > 1"
        :pages="project.pages"
        :active-page-id="currentPageId"
        @select-page="switchToPage"
        @add-page="addNewPage"
        @duplicate-page="duplicatePage"
        @delete-page="(id) => { const idx = project.pages?.findIndex((p: any) => p.id === id); if (idx != null && idx >= 0) deletePage(idx) }"
      />

      <!-- Mobile Bottom Nav -->
      <EditorMobileNav
        v-if="isMobile"
        ref="mobileNavRef"
        @open-panel="mobilePanel = $event"
      />

      <!-- Mobile Bottom Sheet -->
      <EditorMobileBottomSheet
        v-if="isMobile && mobilePanel"
        :title="mobilePanel === 'tools' ? 'Ferramentas' : mobilePanel === 'layers' ? 'Camadas' : mobilePanel === 'properties' ? 'Propriedades' : mobilePanel === 'pages' ? 'Páginas' : mobilePanel === 'uploads' ? 'Imagens' : 'Mais'"
        @close="mobilePanel = null; mobileNavRef?.clearActive()"
      >
        <!-- Tools panel -->
        <div v-if="mobilePanel === 'tools'" class="space-y-4">
          <!-- Shapes -->
          <div>
            <div class="text-[11px] text-white/40 uppercase tracking-wider mb-2 px-1">Formas</div>
            <div class="grid grid-cols-4 gap-2">
              <button class="flex flex-col items-center gap-1.5 p-3 rounded-xl bg-white/5 hover:bg-white/10 text-white/70 active:text-white" @click="addFrame(); mobilePanel = null; mobileNavRef?.clearActive()">
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><rect x="3" y="3" width="18" height="18" rx="2"/></svg>
                <span class="text-[11px]">Frame</span>
              </button>
              <button class="flex flex-col items-center gap-1.5 p-3 rounded-xl bg-white/5 hover:bg-white/10 text-white/70 active:text-white" @click="addShape('rect'); mobilePanel = null; mobileNavRef?.clearActive()">
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><rect x="4" y="4" width="16" height="16" rx="1"/></svg>
                <span class="text-[11px]">Retângulo</span>
              </button>
              <button class="flex flex-col items-center gap-1.5 p-3 rounded-xl bg-white/5 hover:bg-white/10 text-white/70 active:text-white" @click="addShape('rect', { rx: 16, ry: 16 }); mobilePanel = null; mobileNavRef?.clearActive()">
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><rect x="4" y="4" width="16" height="16" rx="6"/></svg>
                <span class="text-[11px]">Arredondado</span>
              </button>
              <button class="flex flex-col items-center gap-1.5 p-3 rounded-xl bg-white/5 hover:bg-white/10 text-white/70 active:text-white" @click="addShape('circle'); mobilePanel = null; mobileNavRef?.clearActive()">
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><circle cx="12" cy="12" r="9"/></svg>
                <span class="text-[11px]">Círculo</span>
              </button>
              <button class="flex flex-col items-center gap-1.5 p-3 rounded-xl bg-white/5 hover:bg-white/10 text-white/70 active:text-white" @click="addShape('ellipse'); mobilePanel = null; mobileNavRef?.clearActive()">
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><ellipse cx="12" cy="12" rx="10" ry="6"/></svg>
                <span class="text-[11px]">Elipse</span>
              </button>
              <button class="flex flex-col items-center gap-1.5 p-3 rounded-xl bg-white/5 hover:bg-white/10 text-white/70 active:text-white" @click="addShape('triangle'); mobilePanel = null; mobileNavRef?.clearActive()">
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M12 4L3 20h18L12 4z"/></svg>
                <span class="text-[11px]">Triângulo</span>
              </button>
              <button class="flex flex-col items-center gap-1.5 p-3 rounded-xl bg-white/5 hover:bg-white/10 text-white/70 active:text-white" @click="addShape('line'); mobilePanel = null; mobileNavRef?.clearActive()">
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><line x1="5" y1="19" x2="19" y2="5"/></svg>
                <span class="text-[11px]">Linha</span>
              </button>
              <button class="flex flex-col items-center gap-1.5 p-3 rounded-xl bg-white/5 hover:bg-white/10 text-white/70 active:text-white" @click="addShape('star'); mobilePanel = null; mobileNavRef?.clearActive()">
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"/></svg>
                <span class="text-[11px]">Estrela</span>
              </button>
            </div>
          </div>
          <!-- Text & Drawing -->
          <div>
            <div class="text-[11px] text-white/40 uppercase tracking-wider mb-2 px-1">Texto & Desenho</div>
            <div class="grid grid-cols-4 gap-2">
              <button class="flex flex-col items-center gap-1.5 p-3 rounded-xl bg-white/5 hover:bg-white/10 text-white/70 active:text-white" @click="addText(); mobilePanel = null; mobileNavRef?.clearActive()">
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M4 7V4h16v3"/><path d="M12 4v16"/><path d="M8 20h8"/></svg>
                <span class="text-[11px]">Texto</span>
              </button>
              <button class="flex flex-col items-center gap-1.5 p-3 rounded-xl bg-white/5 hover:bg-white/10 text-white/70 active:text-white" @click="addText('heading'); mobilePanel = null; mobileNavRef?.clearActive()">
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M6 12h12"/><path d="M6 4v16"/><path d="M18 4v16"/></svg>
                <span class="text-[11px]">Título</span>
              </button>
              <button class="flex flex-col items-center gap-1.5 p-3 rounded-xl bg-white/5 hover:bg-white/10 text-white/70 active:text-white" @click="togglePenMode(); mobilePanel = null; mobileNavRef?.clearActive()">
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="m12 19 7-7 3 3-7 7-3-3z"/><path d="m18 13-1.5-7.5L2 2l3.5 14.5L13 18l5-5z"/><path d="m2 2 7.586 7.586"/><circle cx="11" cy="11" r="2"/></svg>
                <span class="text-[11px]">Caneta</span>
              </button>
              <button class="flex flex-col items-center gap-1.5 p-3 rounded-xl bg-white/5 hover:bg-white/10 text-white/70 active:text-white" @click="toggleDrawing(); mobilePanel = null; mobileNavRef?.clearActive()">
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M21.174 6.812a1 1 0 0 0-3.986-3.987L3.842 16.174a2 2 0 0 0-.5.83l-1.321 4.352a.5.5 0 0 0 .623.622l4.353-1.32a2 2 0 0 0 .83-.497z"/></svg>
                <span class="text-[11px]">Desenho</span>
              </button>
            </div>
          </div>
          <!-- Product & Templates -->
          <div>
            <div class="text-[11px] text-white/40 uppercase tracking-wider mb-2 px-1">Produtos & Templates</div>
            <div class="grid grid-cols-4 gap-2">
              <button class="flex flex-col items-center gap-1.5 p-3 rounded-xl bg-white/5 hover:bg-white/10 text-white/70 active:text-white" @click="addGridZone(); mobilePanel = null; mobileNavRef?.clearActive()">
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/><rect x="3" y="14" width="7" height="7"/><rect x="14" y="14" width="7" height="7"/></svg>
                <span class="text-[11px]">Grid Zone</span>
              </button>
              <button class="flex flex-col items-center gap-1.5 p-3 rounded-xl bg-white/5 hover:bg-white/10 text-white/70 active:text-white" @click="showLabelTemplatesModal = true; mobilePanel = null; mobileNavRef?.clearActive()">
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M12 2H2v10l9.29 9.29c.94.94 2.48.94 3.42 0l6.58-6.58c.94-.94.94-2.48 0-3.42L12 2Z"/><path d="M7 7h.01"/></svg>
                <span class="text-[11px]">Etiquetas</span>
              </button>
              <button class="flex flex-col items-center gap-1.5 p-3 rounded-xl bg-white/5 hover:bg-white/10 text-white/70 active:text-white" @click="mobilePanel = 'uploads'">
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><rect x="3" y="3" width="18" height="18" rx="2"/><circle cx="9" cy="9" r="2"/><path d="m21 15-3.086-3.086a2 2 0 0 0-2.828 0L6 21"/></svg>
                <span class="text-[11px]">Imagens</span>
              </button>
              <button class="flex flex-col items-center gap-1.5 p-3 rounded-xl bg-white/5 hover:bg-white/10 text-white/70 active:text-white" @click="openAiGenerationModal(); mobilePanel = null; mobileNavRef?.clearActive()">
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="m12 3-1.912 5.813a2 2 0 0 1-1.275 1.275L3 12l5.813 1.912a2 2 0 0 1 1.275 1.275L12 21l1.912-5.813a2 2 0 0 1 1.275-1.275L21 12l-5.813-1.912a2 2 0 0 1-1.275-1.275L12 3Z"/></svg>
                <span class="text-[11px]">IA Gerar</span>
              </button>
            </div>
          </div>
        </div>

        <!-- Uploads / Imagens panel -->
        <template v-if="mobilePanel === 'uploads'">
          <AssetsPanel
            class="-mx-4 -mb-4 flex-1 min-h-0"
            @insert-asset="(asset) => { insertAssetToCanvas(asset); mobilePanel = null; mobileNavRef?.clearActive(); }"
          />
        </template>

        <!-- Layers panel -->
        <template v-if="mobilePanel === 'layers'">
          <LayersPanel
            class="flex-1 min-h-0"
            :objects="canvasObjects"
            :selectedId="selectedObjectId"
            :selectedIds="selectedObjectIds"
            @select="selectObject"
            @toggle-visible="toggleVisible"
            @toggle-lock="toggleLock"
            @delete="deleteObject"
            @move-up="id => moveLayer(id, 'up')"
            @move-down="id => moveLayer(id, 'down')"
            @rename="renameLayer"
            @reorder="reorderLayerByDrag"
          />
        </template>

        <!-- Properties panel (right sidebar content) -->
        <template v-if="mobilePanel === 'properties'">
          <EditorRightSidebar
            :collaborators="[]"
            :current-user="currentUser"
            :show-zoom-menu="false"
            :current-zoom="currentZoom"
            :get-color-from-string="getColorFromString"
            :get-initial="getInitial"
            :selected-object="selectedObjectRef"
            :active-mode="activeMode"
            :page-settings="pageSettings"
            :color-styles="project.colorStyles || []"
            :product-zone="productZoneState.productZone.value"
            :product-zone-inspector="selectedZoneInspectorData"
            :product-global-styles="productZoneState.globalStyles.value"
            :label-templates="labelTemplates"
            :view-show-grid="viewShowGrid"
            :view-show-rulers="viewShowRulers"
            :view-show-guides="viewShowGuides"
            :snap-to-objects="snapToObjects"
            :snap-to-guides="snapToGuides"
            :snap-to-grid="snapToGrid"
            :grid-size="gridSize"
            class="relative! w-full! shadow-none! border-0!"
            @update-property="updateObjectProperty"
            @update-smart-group="updateSmartGroup"
            @update-page-settings="updatePageSettings"
            @action="handleAction"
            @add-color-style="addColorStyle"
            @apply-color-style="applyColorStyle"
            @update-zone="handleUpdateZone"
            @update-global-styles="handleUpdateGlobalStyles"
            @apply-template-to-zone="handleApplyTemplateToZone"
            @apply-preset="handleApplyZonePreset"
            @sync-gaps="handleSyncZoneGaps"
            @recalculate-layout="handleRecalculateLayout"
            @manage-label-templates="showLabelTemplatesModal = true"
            @open-zone-review="handleZoneQuickActionFill"
            @change-mode="(mode: 'design' | 'prototype') => activeMode = mode"
          />
        </template>

        <!-- Pages panel -->
        <template v-if="mobilePanel === 'pages'">
          <PageNavigator
            :pages="project.pages || []"
            :active-page-id="currentPageId"
            @select-page="switchToPage"
            @add-page="addNewPage"
            @duplicate-page="duplicatePage"
            @delete-page="deletePage"
            @reorder-pages="reorderPages"
          />
        </template>

        <!-- More panel -->
        <div v-if="mobilePanel === 'more'" class="space-y-4">
          <!-- Zoom -->
          <div>
            <div class="text-[11px] text-white/40 uppercase tracking-wider mb-2 px-1">Zoom ({{ Math.round(currentZoom) }}%)</div>
            <div class="grid grid-cols-4 gap-2">
              <button class="flex flex-col items-center gap-1.5 p-2.5 rounded-xl bg-white/5 hover:bg-white/10 text-white/70 active:text-white" @click="handleZoom50()">
                <span class="text-sm font-semibold">50%</span>
              </button>
              <button class="flex flex-col items-center gap-1.5 p-2.5 rounded-xl bg-white/5 hover:bg-white/10 text-white/70 active:text-white" @click="handleZoom100()">
                <span class="text-sm font-semibold">100%</span>
              </button>
              <button class="flex flex-col items-center gap-1.5 p-2.5 rounded-xl bg-white/5 hover:bg-white/10 text-white/70 active:text-white" @click="handleZoom200()">
                <span class="text-sm font-semibold">200%</span>
              </button>
              <button class="flex flex-col items-center gap-1.5 p-2.5 rounded-xl bg-white/5 hover:bg-white/10 text-white/70 active:text-white" @click="zoomToFit(); mobilePanel = null; mobileNavRef?.clearActive()">
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M15 3h6v6"/><path d="M9 21H3v-6"/><path d="m21 3-7 7"/><path d="m3 21 7-7"/></svg>
                <span class="text-[10px]">Ajustar</span>
              </button>
            </div>
          </div>
          <!-- Actions -->
          <div>
            <div class="text-[11px] text-white/40 uppercase tracking-wider mb-2 px-1">Ações</div>
            <div class="grid grid-cols-4 gap-2">
              <!-- Exportar: abre o ExportDialog completo (PNG/JPEG/PDF, pagina/frame/todos) -->
              <button class="flex flex-col items-center gap-1.5 p-3 rounded-xl bg-violet-500/15 hover:bg-violet-500/25 text-violet-200 active:text-white col-span-2" @click="exportDesign(); mobilePanel = null; mobileNavRef?.clearActive()">
                <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" x2="12" y1="15" y2="3"/></svg>
                <span class="text-[11px] font-semibold">Exportar (PNG / JPG / PDF)</span>
              </button>
              <button class="flex flex-col items-center gap-1.5 p-3 rounded-xl bg-white/5 hover:bg-white/10 text-white/70 active:text-white" @click="startPresentation(); mobilePanel = null; mobileNavRef?.clearActive()">
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><polygon points="5 3 19 12 5 21 5 3"/></svg>
                <span class="text-[11px]">Apresentar</span>
              </button>
              <button class="flex flex-col items-center gap-1.5 p-3 rounded-xl bg-white/5 hover:bg-white/10 text-white/70 active:text-white" @click="shareDesign(); mobilePanel = null; mobileNavRef?.clearActive()">
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><circle cx="18" cy="5" r="3"/><circle cx="6" cy="12" r="3"/><circle cx="18" cy="19" r="3"/><line x1="8.59" x2="15.42" y1="13.51" y2="17.49"/><line x1="15.41" x2="8.59" y1="6.51" y2="10.49"/></svg>
                <span class="text-[11px]">Compartilhar</span>
              </button>
            </div>
          </div>
          <!-- View Settings -->
          <div>
            <div class="text-[11px] text-white/40 uppercase tracking-wider mb-2 px-1">Visualização</div>
            <div class="grid grid-cols-3 gap-2">
              <button class="flex flex-col items-center gap-1.5 p-3 rounded-xl hover:bg-white/10 active:text-white" :class="viewShowGrid ? 'bg-violet-500/20 text-violet-400' : 'bg-white/5 text-white/70'" @click="toggleGrid()">
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><rect width="18" height="18" x="3" y="3" rx="2"/><path d="M3 9h18"/><path d="M3 15h18"/><path d="M9 3v18"/><path d="M15 3v18"/></svg>
                <span class="text-[11px]">Grid</span>
              </button>
              <button class="flex flex-col items-center gap-1.5 p-3 rounded-xl hover:bg-white/10 active:text-white" :class="viewShowRulers ? 'bg-violet-500/20 text-violet-400' : 'bg-white/5 text-white/70'" @click="toggleRulers()">
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M3 5v14"/><path d="M3 5h4"/><path d="M3 9h2"/><path d="M3 13h4"/><path d="M3 17h2"/><path d="M3 19h18V5"/><path d="M21 5h-4"/><path d="M17 5v2"/><path d="M13 5v4"/><path d="M9 5v2"/></svg>
                <span class="text-[11px]">Réguas</span>
              </button>
              <button class="flex flex-col items-center gap-1.5 p-3 rounded-xl hover:bg-white/10 active:text-white" :class="viewShowGuides ? 'bg-violet-500/20 text-violet-400' : 'bg-white/5 text-white/70'" @click="toggleGuides()">
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><line x1="12" x2="12" y1="2" y2="22" stroke-dasharray="4 2"/><line x1="2" x2="22" y1="12" y2="12" stroke-dasharray="4 2"/></svg>
                <span class="text-[11px]">Guias</span>
              </button>
              <button class="flex flex-col items-center gap-1.5 p-3 rounded-xl hover:bg-white/10 active:text-white" :class="snapToObjects ? 'bg-violet-500/20 text-violet-400' : 'bg-white/5 text-white/70'" @click="toggleSnapObjects()">
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M4.5 4.5l3 3"/><path d="M19.5 4.5l-3 3"/><path d="M4.5 19.5l3-3"/><path d="M19.5 19.5l-3-3"/><rect x="8" y="8" width="8" height="8" rx="1"/></svg>
                <span class="text-[10px]">Snap Obj</span>
              </button>
              <button class="flex flex-col items-center gap-1.5 p-3 rounded-xl hover:bg-white/10 active:text-white" :class="snapToGuides ? 'bg-violet-500/20 text-violet-400' : 'bg-white/5 text-white/70'" @click="toggleSnapGuides()">
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><line x1="12" x2="12" y1="2" y2="22"/><path d="M8 8l4-4 4 4"/><path d="M8 16l4 4 4-4"/></svg>
                <span class="text-[10px]">Snap Guia</span>
              </button>
              <button class="flex flex-col items-center gap-1.5 p-3 rounded-xl hover:bg-white/10 active:text-white" :class="snapToGrid ? 'bg-violet-500/20 text-violet-400' : 'bg-white/5 text-white/70'" @click="toggleSnapGrid()">
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/><rect x="3" y="14" width="7" height="7"/><rect x="14" y="14" width="7" height="7"/><circle cx="7" cy="7" r="1.5" fill="currentColor"/></svg>
                <span class="text-[10px]">Snap Grid</span>
              </button>
            </div>
          </div>
        </div>
      </EditorMobileBottomSheet>

      <!-- MODALS SYSTEM (Internal Dialogs) -->
      <EditorModalsHost
        :show-save-modal="showSaveModal"
        :save-project-name="saveProjectName"
        :show-label-templates-modal="showLabelTemplatesModal"
        :label-templates="labelTemplates"
        :selected-template-id="activeZoneTemplateId()"
        :can-save-label-template-from-selection="canSaveLabelTemplateFromSelectionComputed"
        :show-a-i-modal="showAIModal"
        :ai-prompt="aiPrompt"
        :ai-reference-image-data-url="aiReferenceImageDataUrl"
        :ai-apply-mode="aiApplyMode"
        :ai-page-type="aiPageType"
        :ai-page-width="aiPageWidth"
        :ai-page-height="aiPageHeight"
        :is-processing="isProcessing"
        :show-paste-list-modal="showPasteListModal"
        :active-paste-tab="activePasteTab"
        :paste-list-text="pasteListText"
        :pasted-image="pastedImage"
        :is-analyzing-image="isAnalyzingImage"
        :show-delete-page-modal="showDeletePageModal"
        :show-product-review-modal="showProductReviewModal"
        :review-products="reviewProducts"
        :show-import-mode="!!(targetGridZone && isLikelyProductZone(targetGridZone))"
        :product-import-existing-count="productImportExistingCount"
        :product-review-initial-import-mode="productReviewInitialImportMode"
        :import-zone-label-template-id="importZoneLabelTemplateId"
        :show-export-modal="showExportModal"
        :export-settings="exportSettings"
        :available-frames-for-export="availableFramesForExport"
        :has-exportable-selected-object="hasExportableSelectedObject"
        :available-frames-for-import="availableFramesForImport"
        :available-zones-for-import="availableZonesForImport"
        :show-share-modal="showShareModal"
        :share-settings="shareSettings"
        :show-presentation-modal="showPresentationModal"
        :presentation-image="presentationImage"
        :presentation-hotspots="presentationHotspots"
        :figma-crop-active="figmaCrop.isCropActive.value"
        :crop-frame-rect="figmaCrop.cropFrameRect.value"
        :crop-frame-name="figmaCrop.cropFrameName.value"
        :crop-canvas-offset="cropCanvasOffset"
        @update:show-save-modal="showSaveModal = $event"
        @update:save-project-name="saveProjectName = $event"
        @save="saveProject"
        @update:show-label-templates-modal="showLabelTemplatesModal = $event"
        @edit-selection="beginEditSelectedLabel"
        @create-from-selection="createLabelTemplateFromSelection"
        @create-default="createDefaultLabelTemplate"
        @update-from-selection="updateLabelTemplateFromSelection"
        @insert-to-canvas="insertLabelTemplateToCanvas"
        @update-template="handleUpdateTemplateFromMiniEditor"
        @duplicate-template="duplicateLabelTemplateById"
        @delete-template="deleteLabelTemplateById"
        @apply-template-to-zone="applyTemplateToActiveZone"
        @set-template-splash-image="setTemplateSplashImage"
        @update:show-a-i-modal="showAIModal = $event"
        @update:ai-prompt="aiPrompt = $event"
        @update:ai-reference-image-data-url="aiReferenceImageDataUrl = $event"
        @update:ai-apply-mode="aiApplyMode = $event"
        @update:ai-page-type="aiPageType = $event"
        @update:ai-page-width="aiPageWidth = $event"
        @update:ai-page-height="aiPageHeight = $event"
        @generate-ai="generateFlyerWithAI"
        @update:show-paste-list-modal="showPasteListModal = $event"
        @update:active-paste-tab="activePasteTab = $event"
        @update:paste-list-text="pasteListText = $event"
        @update:pasted-image="pastedImage = $event"
        @update:is-analyzing-image="isAnalyzingImage = $event"
        @submit-paste-list="handlePasteList"
        @submit-paste-file="handlePasteFile"
        @update:show-delete-page-modal="showDeletePageModal = $event"
        @confirm-delete-page="confirmDeletePage"
        @update:show-product-review-modal="handleProductReviewModalVisibility"
        @import-products="confirmProductImport"
        @update:show-export-modal="showExportModal = $event"
        @export="performExport"
        @update:show-share-modal="showShareModal = $event"
        @toggle-share-frame="toggleFrameSelection"
        @select-all-share-frames="selectAllFrames"
        @share="performShare"
        @update:show-presentation-modal="showPresentationModal = $event"
        @hotspot-click="handleHotspotClick"
        @update:figma-crop-active="figmaCrop.isCropActive.value = $event"
        @update:crop-frame-rect="handleCropRectUpdate"
        @crop-complete="handleCropComplete"
      />

      <div
        v-if="aiToast"
        class="fixed top-4 right-4 z-(--z-toast) px-3 py-2 rounded-lg border text-sm shadow-xl"
        :class="aiToast.type === 'error'
          ? 'bg-red-950/90 border-red-300/35 text-red-100'
          : (aiToast.type === 'success'
              ? 'bg-emerald-950/90 border-emerald-300/35 text-emerald-100'
              : 'bg-sky-950/90 border-sky-300/35 text-sky-100')"
      >
        {{ aiToast.message }}
      </div>

      <div
        v-if="isExportDownloadInProgress"
        class="fixed inset-0 z-(--z-toast) pointer-events-none flex items-center justify-center"
      >
        <div class="flex items-center gap-3 rounded-xl border border-violet-400/35 bg-zinc-950/90 px-4 py-3 shadow-2xl">
          <span class="inline-block h-4 w-4 rounded-full border-2 border-violet-300/30 border-t-violet-300 animate-spin" />
          <div class="text-left">
            <p class="text-sm font-semibold text-violet-100">{{ exportDownloadStatus }}</p>
            <p class="text-[11px] text-violet-200/75">Preparando download...</p>
          </div>
        </div>
      </div>

      <!-- Page History / Restore Modal -->
      <Teleport to="body">
        <Transition
          enter-active-class="transition duration-200 ease-out"
          enter-from-class="opacity-0"
          enter-to-class="opacity-100"
          leave-active-class="transition duration-150 ease-in"
          leave-from-class="opacity-100"
          leave-to-class="opacity-0"
        >
          <div v-if="showHistoryModal" class="fixed inset-0 z-(--z-modal) flex items-center justify-center">
            <!-- Backdrop -->
            <div class="absolute inset-0 bg-black/70 backdrop-blur-sm" @click="showHistoryModal = false" />

            <!-- Panel -->
            <div class="relative w-[min(520px,92vw)] max-h-[85vh] flex flex-col rounded-2xl border border-white/8 bg-zinc-900/95 shadow-[0_25px_60px_-12px_rgba(0,0,0,0.7)] overflow-hidden">

              <!-- Header -->
              <div class="flex items-center gap-3 px-5 pt-5 pb-4">
                <div class="flex items-center justify-center w-9 h-9 rounded-xl bg-violet-500/15 shrink-0">
                  <svg class="w-4.5 h-4.5 text-violet-400" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="1.8">
                    <path stroke-linecap="round" stroke-linejoin="round" d="M12 6v6l4 2m6-2a9 9 0 11-18 0 9 9 0 0118 0z" />
                  </svg>
                </div>
                <div class="flex-1 min-w-0">
                  <h3 class="text-[15px] font-semibold text-white/95 leading-tight tracking-[-0.01em]">Historico da pagina</h3>
                  <p class="text-[12px] text-white/45 mt-0.5">Restaure uma versao anterior</p>
                </div>
                <button
                  type="button"
                  class="flex items-center justify-center w-8 h-8 rounded-lg text-white/40 hover:text-white/80 hover:bg-white/6 transition-all duration-150"
                  @click="showHistoryModal = false"
                >
                  <svg class="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
                    <path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" />
                  </svg>
                </button>
              </div>

              <!-- Content -->
              <div class="flex-1 overflow-y-auto px-5 pb-5 min-h-0">

                <!-- Loading state -->
                <div v-if="historyLoading" class="flex flex-col items-center justify-center py-12 gap-3">
                  <div class="w-8 h-8 rounded-full border-2 border-white/10 border-t-violet-400 animate-spin" />
                  <p class="text-[13px] text-white/50">Carregando versoes...</p>
                </div>

                <!-- Error state -->
                <div v-else-if="historyError" class="flex flex-col items-center justify-center py-10 gap-2">
                  <div class="flex items-center justify-center w-10 h-10 rounded-xl bg-red-500/10">
                    <svg class="w-5 h-5 text-red-400" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="1.8">
                      <path stroke-linecap="round" stroke-linejoin="round" d="M12 9v3.75m9-.75a9 9 0 11-18 0 9 9 0 0118 0zm-9 3.75h.008v.008H12v-.008z" />
                    </svg>
                  </div>
                  <p class="text-[13px] text-red-300/90 text-center max-w-70">{{ historyError }}</p>
                </div>

                <!-- Empty state -->
                <div v-else-if="!historyItems.length" class="flex flex-col items-center justify-center py-10 gap-2">
                  <div class="flex items-center justify-center w-10 h-10 rounded-xl bg-white/4">
                    <svg class="w-5 h-5 text-white/25" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="1.8">
                      <path stroke-linecap="round" stroke-linejoin="round" d="M20 13V6a2 2 0 00-2-2H6a2 2 0 00-2 2v7m16 0v5a2 2 0 01-2 2H6a2 2 0 01-2-2v-5m16 0h-2.586a1 1 0 00-.707.293l-2.414 2.414a1 1 0 01-.707.293h-2.172a1 1 0 01-.707-.293l-2.414-2.414A1 1 0 006.586 13H4" />
                    </svg>
                  </div>
                  <p class="text-[13px] text-white/40">Nenhuma versao salva ainda</p>
                  <p class="text-[11px] text-white/25 max-w-60 text-center">Versoes sao salvas automaticamente quando voce edita o projeto.</p>
                </div>

                <!-- History items -->
                <div v-else class="flex flex-col gap-2">
                  <div
                    v-for="(it, idx) in historyItems"
                    :key="`${it.source}:${it.key}:${it.versionId || ''}:${it.lastModified}`"
                    class="group relative flex items-center gap-3.5 px-4 py-3.5 rounded-xl border transition-all duration-150"
                    :class="((it as any).source === 'current' || historyItemIsLatest(idx)) ? 'bg-violet-500/[0.07] border-violet-500/20 hover:border-violet-500/35' : 'bg-white/2 border-white/6 hover:bg-white/4 hover:border-white/12'"
                  >
                    <!-- Timeline dot -->
                    <div class="flex flex-col items-center self-stretch shrink-0">
                      <div
                        class="w-2.5 h-2.5 rounded-full mt-0.5 ring-[3px] shrink-0"
                        :class="((it as any).source === 'current' || historyItemIsLatest(idx)) ? 'bg-violet-400 ring-violet-400/20' : 'bg-white/20 ring-white/6'"
                      />
                      <div v-if="idx < historyItems.length - 1" class="w-px flex-1 mt-1 bg-white/6" />
                    </div>

                    <!-- Info -->
                    <div class="flex-1 min-w-0">
                      <div class="flex items-center gap-2">
                        <p class="text-[13px] font-medium text-white/90 leading-tight">
                          {{ formatHistoryDateTime(it.lastModified) }}
                        </p>
                        <span
                          v-if="(it as any).source === 'current'"
                          class="inline-flex items-center px-1.5 py-px rounded text-[10px] font-medium bg-emerald-500/20 text-emerald-300 leading-relaxed"
                        >Versao atual</span>
                        <span
                          v-else-if="historyItemIsLatest(idx)"
                          class="inline-flex items-center px-1.5 py-px rounded text-[10px] font-medium bg-violet-500/20 text-violet-300 leading-relaxed"
                        >Mais recente</span>
                      </div>
                      <div class="flex items-center gap-1.5 mt-1">
                        <span class="text-[11px] text-white/35">{{ formatHistoryRelative(it.lastModified) }}</span>
                        <span v-if="it.objectCount != null" class="text-[11px] text-white/20">&#183;</span>
                        <span v-if="it.objectCount != null" class="text-[11px] text-white/35">{{ it.objectCount }} objetos</span>
                        <span v-if="it.size != null" class="text-[11px] text-white/20">&#183;</span>
                        <span v-if="it.size != null" class="text-[11px] text-white/35">{{ Math.max(1, Math.round((it.size || 0) / 1024)) }} KB</span>
                      </div>
                    </div>

                    <!-- Restore button -->
                    <button
                      type="button"
                      class="shrink-0 flex items-center gap-1.5 text-[12px] font-medium px-3.5 py-2 rounded-lg transition-all duration-150 disabled:opacity-40 disabled:cursor-not-allowed"
                      :class="restoringHistoryKey === getHistoryRestoreKey(it as any)
                        ? 'bg-violet-500/20 text-violet-300 cursor-wait'
                        : 'bg-white/6 text-white/70 hover:bg-violet-500/15 hover:text-violet-200 active:scale-[0.97]'"
                      :disabled="!!restoringHistoryKey"
                      @click="restoreFromHistoryItem(it as any)"
                    >
                      <svg v-if="restoringHistoryKey === getHistoryRestoreKey(it as any)" class="w-3.5 h-3.5 animate-spin" fill="none" viewBox="0 0 24 24">
                        <circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4" />
                        <path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
                      </svg>
                      <svg v-else class="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
                        <path stroke-linecap="round" stroke-linejoin="round" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                      </svg>
                      {{ restoringHistoryKey === getHistoryRestoreKey(it as any) ? 'Restaurando...' : 'Restaurar' }}
                    </button>
                  </div>
                </div>
              </div>

              <!-- Footer hint -->
              <div v-if="!historyLoading && !historyError && historyItems.length" class="px-5 py-3 border-t border-white/6 bg-white/2">
                <p class="text-[11px] text-white/30 text-center">
                  Ate {{ 3 }} versoes salvas automaticamente por pagina
                </p>
              </div>

            </div>
          </div>
        </Transition>
      </Teleport>

  </div>
</template>

